-- Poems batch 405
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('song-ci-372','临江仙','无名氏','宋','宋词','song-ci','临江仙','[]','促坐重燃绛蜡，香泉细泻银瓶。',68,'宋词/ci.song.19000.json','["促坐重燃绛蜡，香泉细泻银瓶。", "一瓯月露照人明。", "清真无俗韵，久淡似交清。", "正味能销酒力，馀甘解助茶清。", "琼浆一饮觉身轻。", "蓝桥知不远，归卧对云英。"]'),
('song-ci-373','行香子','无名氏','宋','宋词','song-ci','行香子','[]','天与秋光。',84,'宋词/ci.song.19000.json','["天与秋光。", "转转情伤，探金英、知近重阳。", "薄衣初减，绿蚁初尝。", "渐一番风，一番雨，一番凉。", "黄昏院落，恓恓惶惶。", "酒醒时、往事愁肠。", "那堪永夜，明月空床。", "问砧声捣，蛩声细，漏声长。"]'),
('song-ci-374','诉衷情','无名氏','宋','宋词','song-ci','诉衷情','[]','碧天明月晃金波。',54,'宋词/ci.song.19000.json','["碧天明月晃金波。", "清浅滞星河。", "深深院宇人静，独自问姮娥。", "圆夜少，缺时多。", "事因何。", "嫦娥莫是，也有别离，一似人麽。"]'),
('song-ci-375','绕池游','无名氏','宋','宋词','song-ci','绕池游','[]','渐春工巧，玉漏花深寒浅。',88,'宋词/ci.song.19000.json','["渐春工巧，玉漏花深寒浅。", "韶景变、融晴蕙风暖。", "都门十二，三五银蟾光满。", "瑞烟葱茜，禁城阆苑。", "棚山雉扇。", "绛蜡交辉星汉。", "神仙籍、梨园奏弦管。", "都人游玩。", "万井山呼欢抃。", "岁岁天仗，愿瞻凤辇。"]'),
('song-ci-376','好事近','无名氏','宋','宋词','song-ci','好事近','[]','小院看酴醿，正是盛开时节。',53,'宋词/ci.song.19000.json','["小院看酴醿，正是盛开时节。", "莫惜大家沈醉，有春醅初泼。", "花前月下细看来，无物比清绝。", "若问此花何似，似一堆香雪。"]'),
('song-ci-377','阮郎归','无名氏','宋','宋词','song-ci','阮郎归','[]','春风吹雨绕残枝。',56,'宋词/ci.song.19000.json','["春风吹雨绕残枝。", "落花无可飞。", "小池寒渌欲生漪。", "雨晴还日西。", "帘半卷，燕双归。", "讳愁无奈眉。", "翻身整顿著残棋。", "沈吟应劫迟。"]'),
('song-ci-378','点绛唇','无名氏','宋','宋词','song-ci','点绛唇','[]','公子归来，画堂深院丛罗绮。',50,'宋词/ci.song.19000.json','["公子归来，画堂深院丛罗绮。", "绿杯浮蚁。", "风皱红鳞起。", "信马斜阳，误入桃源里。", "珠帘底。", "淡妆斜倚。", "一寸秋江水。"]'),
('song-ci-379','海棠春','无名氏','宋','宋词','song-ci','海棠春','[]','晓莺窗外春啼晓。',58,'宋词/ci.song.19000.json','["晓莺窗外春啼晓。", "睡未足、把人惊觉。", "翠被晓寒轻，宝篆沈烟袅。", "宿酲未解，双娥报道。", "别院笙歌宴早。", "试问海棠花，昨夜开多少。"]'),
('song-ci-380','宴桃源・如梦令','无名氏','宋','宋词','song-ci','宴桃源・如梦令','[]','落日霞消一缕。',40,'宋词/ci.song.19000.json','["落日霞消一缕。", "素月棱棱微吐。", "何处夜归人，呕嗄几声柔橹。", "归去。", "归去。", "家在烟波深处。"]'),
('song-ci-381','祝英台・祝英台近','无名氏','宋','宋词','song-ci','祝英台・祝英台近','[]','海棠开，花影下，忆得共游戏。',95,'宋词/ci.song.19000.json','["海棠开，花影下，忆得共游戏。", "恰似双鸾，同步彩云里。", "梦回雨收云散，匆匆归去，一枕乍、惊回浓睡。", "甚情味。", "人去花亦凋零，秾芳伴憔悴。", "点点飞红，知是去时泪。", "可堪冷落黄昏，潇潇微雨，断魂处。", "朱阑独倚。"]'),
('song-ci-382','夜游宫','无名氏','宋','宋词','song-ci','夜游宫','[]','是处追寻侣。',70,'宋词/ci.song.19000.json','["是处追寻侣。", "灯光散、九衢红雾。", "人在星河繁闹处。", "暗相逢，惹天香，飘满路。", "游困先归去。", "奈怨别、相思情绪。", "闲傍小桃□独步。", "月明寒，拈宜男，无一语。"]'),
('song-ci-383','杨柳枝','无名氏','宋','宋词','song-ci','杨柳枝','[]','簌簌花飞一雨残。',48,'宋词/ci.song.19000.json','["簌簌花飞一雨残。", "乍衣单。", "屏风数幅画江山。", "水云闲。", "别易会难无计那，泪潸潸。", "夕阳楼上凭栏干。", "望长安。"]'),
('song-ci-384','摊破浣溪沙・山花子','无名氏','宋','宋词','song-ci','摊破浣溪沙・山花子','[]','相恨相思一个人。',54,'宋词/ci.song.19000.json','["相恨相思一个人。", "柳眉桃脸自然春。", "别离情思，寂寞向谁论。", "映地残霞红照水，断魂芳草碧连云。", "水边楼上，回首倚黄昏。"]'),
('song-ci-385','一翦梅','无名氏','宋','宋词','song-ci','一翦梅','[]','恨入椒觞暖未拈。',70,'宋词/ci.song.19000.json','["恨入椒觞暖未拈。", "春葱微蘸，谁是纤纤。", "别来愁夜不胜长，明日从教一线添。", "夜久寒深睡未忺。", "旧愁新恨，占断眉尖。", "一钩斜月却知人。", "直到天明，不下疏帘。"]'),
('song-ci-386','卜算子','无名氏','宋','宋词','song-ci','卜算子','[]','垂螺近额时，只怕莺声老。',55,'宋词/ci.song.19000.json','["垂螺近额时，只怕莺声老。", "尽日贪花斗草忙，不信有闲烦恼。", "凤鬓已胜钗，恨别王孙早。", "若把芳心说与伊，道绿遍、池塘草。"]'),
('song-ci-387','忆王孙','无名氏','宋','宋词','song-ci','忆王孙','[]','杨柳风前旗鼓闹。',66,'宋词/ci.song.19000.json','["杨柳风前旗鼓闹。", "正陌上、闲花芳草。", "忍将愁眼覰芳菲，人未老。", "春先老。", "长安比日知多少。", "日易见、长安难到。", "无情苕水不西流，渐迤逦、仙舟小。"]'),
('song-ci-388','南歌子','无名氏','宋','宋词','song-ci','南歌子','[]','夕露沾芳草，斜阳带远村。',62,'宋词/ci.song.19000.json','["夕露沾芳草，斜阳带远村。", "几声残角起谯门。", "撩乱栖鸦飞舞、闹黄昏。", "天共高城远，香馀绣被温。", "客程常是可销魂。", "乍向心头横著、个人人。"]'),
('song-ci-389','南歌子','无名氏','宋','宋词','song-ci','南歌子','[]','楼迥迷云日，溪深涨晓沙。',62,'宋词/ci.song.19000.json','["楼迥迷云日，溪深涨晓沙。", "年来悴憔费铅华。", "楼上一天春思、浩无涯。", "罗带宽腰素，真珠溜脸霞。", "海棠开尽柳飞花。", "薄幸只知游荡、不思家。"]'),
('song-ci-390','南歌子','无名氏','宋','宋词','song-ci','南歌子','[]','玉殿分时果，金盘弄赐冰。',62,'宋词/ci.song.19000.json','["玉殿分时果，金盘弄赐冰。", "晚来阶下按歌声。", "恰好一方明月、可中庭。", "露下天如水，风来夜又清。", "偏他不肯大家行。", "漾下扇儿拍手、引流萤。"]'),
('song-ci-391','失调名','无名氏','宋','宋词','song-ci','失调名','[]','千里伤行客。',6,'宋词/ci.song.19000.json','["千里伤行客。"]'),
('song-ci-392','失调名','无名氏','宋','宋词','song-ci','失调名','[]','黄叶无风自落，彩云不雨空归。',14,'宋词/ci.song.19000.json','["黄叶无风自落，彩云不雨空归。"]'),
('song-ci-393','玉珑璁','无名氏','宋','宋词','song-ci','玉珑璁','[]','城南路。',76,'宋词/ci.song.19000.json','["城南路。", "桥南路。", "玉钩帘卷香横雾。", "新相识。", "旧相识。", "浅颦低拍，嫩红轻碧。", "惜惜惜。", "刘郎去。", "阮郎住。", "为云为雨朝还暮。", "心相忆。", "空相忆。", "露荷心性，柳花踪迹。", "得得得。"]'),
('song-ci-394','浣溪沙','无名氏','宋','宋词','song-ci','浣溪沙','[]','碎剪香罗浥泪痕。',48,'宋词/ci.song.19000.json','["碎剪香罗浥泪痕。", "鹧鸪声断不堪闻。", "马嘶人去近黄昏。", "整整斜斜扬柳陌，疏疏密密杏花村。", "一番风月更销魂。"]'),
('song-ci-395','点绛唇','无名氏','宋','宋词','song-ci','点绛唇','[]','燕子依依，晓来总为谁归去。',50,'宋词/ci.song.19000.json','["燕子依依，晓来总为谁归去。", "淡云生处。", "已觉宾鸿度。", "浅笑深颦，便面机中素。", "乘鸾女。", "琐窗琼宇。", "会有明年暑。"]'),
('song-ci-396','踏青游','无名氏','宋','宋词','song-ci','踏青游','[]','识个人人，恰正二年欢会。',102,'宋词/ci.song.19000.json','["识个人人，恰正二年欢会。", "似赌赛、六只浑四。", "向巫山、重重去，如鱼水。", "两情美。", "同倚画楼十二。", "倚了又还重倚。", "两日不来，时时在人心里。", "拟问卜、常占归计。", "拚三八清齐，望永同鸳被。", "到梦里。", "蓦然被人惊觉，梦也有头无尾。"]'),
('song-ci-397','玉楼春','无名氏','宋','宋词','song-ci','玉楼春','[]','东风杨柳门前路。',64,'宋词/ci.song.19000.json','["东风杨柳门前路。", "毕竟雕鞍留不住。", "柔情胜似岭头云，别泪多如花上雨。", "青楼画幕无重数。", "听得楼边车马去。", "若将眉黛染情深，且到丹青难画处。"]'),
('song-ci-398','浣溪沙','无名氏','宋','宋词','song-ci','浣溪沙','[]','云锁柴门半掩关。',48,'宋词/ci.song.19000.json','["云锁柴门半掩关。", "垂纶犹自在前湾。", "独乘孤棹夜方还。", "任使有荣居紫禁，争如无事隐青山。", "浮名浮利总输闲。"]'),
('song-ci-399','浣溪沙','无名氏','宋','宋词','song-ci','浣溪沙','[]','一副纶竿一只船。',48,'宋词/ci.song.19000.json','["一副纶竿一只船。", "蓑衣竹笠是生缘。", "五湖来往不知年。", "青嶂更无荣辱到，白头终没利名牵。", "芦花深处伴鸥眠。"]'),
('song-ci-400','浣溪沙','无名氏','宋','宋词','song-ci','浣溪沙','[]','钓罢高歌酒一杯。',48,'宋词/ci.song.19000.json','["钓罢高歌酒一杯。", "醉醒曾笑楚臣来。", "夕阳维缆碧江隈。", "蓑笠每因山雨戴，船窗多为水花开。", "安居流景任相催。"]'),
('song-ci-401','浣溪沙','无名氏','宋','宋词','song-ci','浣溪沙','[]','雨气兼香泛芰荷。',48,'宋词/ci.song.19000.json','["雨气兼香泛芰荷。", "回舟冒雨懒披蓑。", "夜阑风静水无波。", "白酒追欢常恨少，青山入望岂嫌多。", "人间荣辱尽从他。"]'),
('song-ci-402','定风波','无名氏','宋','宋词','song-ci','定风波','[]','雨雾云收望远山。',70,'宋词/ci.song.19000.json','["雨雾云收望远山。", "钓竿林下恣清闲。", "蝉噪日斜林影转。", "溪岸。", "绿深红浅画屏间。", "对酒狂歌时鼓枻。", "更邀同志醉前湾。", "待月却寻维缆处，归来，烟萝一迳接柴关。"]'),
('song-ci-403','雨中花・夜行船','无名氏','宋','宋词','song-ci','雨中花・夜行船','[]','我有五重深深愿。',66,'宋词/ci.song.19000.json','["我有五重深深愿。", "第一愿、且图久远。", "二愿恰如雕梁双燕。", "岁岁后、长相见。", "三愿薄情相顾恋。", "第四愿、永不分散。", "五愿奴留收园结果，做个人宅院。"]'),
('song-ci-404','望海潮','无名氏','宋','宋词','song-ci','望海潮','[]','彩筒角黍，兰桡画舫，佳时竟吊沅湘。',129,'宋词/ci.song.19000.json','["彩筒角黍，兰桡画舫，佳时竟吊沅湘。", "古意未收，新愁又起，断魂流水茫茫。", "堪笑又堪伤。", "有临皋仙子，连璧檀郎。", "暗约同归，远烟深处弄沧浪。", "倚楼魂已飞扬。", "共偷挥玉箸，痛饮霞觞。", "烟水无情，揉花碎玉，空馀怨抑凄凉。", "杨谢旧遗芳。", "算世间纵有，不恁非常。", "但看芙蓉并蒂，他日一双双。"]'),
('song-ci-405','失调名','无名氏','宋','宋词','song-ci','失调名','[]','喜则喜、得入手。',35,'宋词/ci.song.19000.json','["喜则喜、得入手。", "愁则愁、不长久。", "忻则忻、我两个斯守。", "怕则怕、人来破斗。"]'),
('song-ci-406','扑蝴蝶','无名氏','宋','宋词','song-ci','扑蝴蝶','[]','烟条雨叶，绿遍江南岸。',92,'宋词/ci.song.19000.json','["烟条雨叶，绿遍江南岸。", "思归倦客，寻芳来较晚。", "岫边红日初斜，陌上飞花正满。", "凄凉数声羌管。", "怨春短。", "玉人应在，明月楼中画眉懒。", "蛮笺锦字，多时鱼雁断。", "恨随去水东流，事与行云共远。", "罗衾旧香犹暖。"]'),
('song-ci-407','侍香金童','无名氏','宋','宋词','song-ci','侍香金童','[]','喜叶之地，手把怀儿摸。',78,'宋词/ci.song.19000.json','["喜叶之地，手把怀儿摸。", "甚恰恨、出题斯撞著。", "内臣过得不住脚。", "忙里只是，看得斑驳。", "骇这一身冷汗，都如云雾薄。", "比似年时头势恶。", "待检又还猛想度。", "只恐根底，有人寻着。"]'),
('song-ci-408','啄木儿','无名氏','宋','宋词','song-ci','啄木儿','[]','洗出养花天气。',7,'宋词/ci.song.19000.json','["洗出养花天气。"]'),
('song-ci-409','柳梢青','无名氏','宋','宋词','song-ci','柳梢青','[]','晓星明灭。',60,'宋词/ci.song.19000.json','["晓星明灭。", "白露点、秋风落叶。", "故址颓垣，荒烟衰草，溪前宫阙。", "长安道上行客，念依旧、名深利切。", "改变容颜，销磨古今，垅头残月。"]'),
('song-ci-410','眉峰碧・卜算子','无名氏','宋','宋词','song-ci','眉峰碧・卜算子','[]','蹙破眉峰碧。',56,'宋词/ci.song.19000.json','["蹙破眉峰碧。", "纤手还重执。", "镇日相看未足时，忍便使、鸳鸯只。", "薄暮投村驿。", "风雨愁通夕。", "窗外芭蕉窗里人，分明叶上心头滴。"]'),
('song-ci-411','失调名','无名氏','宋','宋词','song-ci','失调名','[]','送千里蟾宫客。',7,'宋词/ci.song.19000.json','["送千里蟾宫客。"]'),
('song-ci-412','失调名','无名氏','宋','宋词','song-ci','失调名','[]','来春高步过南宫，更答取龙头策。',15,'宋词/ci.song.19000.json','["来春高步过南宫，更答取龙头策。"]'),
('song-ci-413','失调名','无名氏','宋','宋词','song-ci','失调名','[]','恐伊不信是龙头，和书寄与三题草。',16,'宋词/ci.song.19000.json','["恐伊不信是龙头，和书寄与三题草。"]'),
('song-ci-414','失调名','无名氏','宋','宋词','song-ci','失调名','[]','问醉吟今夜，何处凤楼偏好。',13,'宋词/ci.song.19000.json','["问醉吟今夜，何处凤楼偏好。"]'),
('song-ci-415','失调名','无名氏','宋','宋词','song-ci','失调名','[]','光生里閈，荣破天荒。',10,'宋词/ci.song.19000.json','["光生里閈，荣破天荒。"]'),
('song-ci-416','行香子','无名氏','宋','宋词','song-ci','行香子','[]','清要无因，举选艰辛。',84,'宋词/ci.song.19000.json','["清要无因，举选艰辛。", "系书钱、须要十分。", "浮名浮利，虚苦劳神。", "叹旅中愁，心中闷，部中身。", "虽抱文章，苦苦推寻。", "更休说、谁假谁真。", "不如归去，作个齐民。", "免一回来，一回讨，一回论。"]'),
('song-ci-417','失调名','无名氏','宋','宋词','song-ci','失调名','[]','君是园中杨柳，能得几时青。',44,'宋词/ci.song.19000.json','["君是园中杨柳，能得几时青。", "趁金明、春光尚好，尊酒赏闲情。", "他年归去，强山阴处，一枕晓霞清。"]'),
('song-ci-418','失调名','无名氏','宋','宋词','song-ci','失调名','[]','华宫瑶馆游毕。',63,'宋词/ci.song.19000.json','["华宫瑶馆游毕。", "却返绛节、回鸾翼。", "荷殷勤、三斝香醪，供养我、上真仙客。", "赤霭浮空，祥云远布，是我来时节。", "且频修，同泛舸、上云秋碧。"]'),
('song-ci-419','湘灵瑟','无名氏','宋','宋词','song-ci','湘灵瑟','[]','霜风摧兰。',41,'宋词/ci.song.19000.json','["霜风摧兰。", "银屏生晓寒。", "淡扫眉山。", "脸红殷。", "潇湘浦，芙蓉湾。", "相思数声哀叹。", "画楼尊酒闲。"]'),
('song-ci-420','失调名','无名氏','宋','宋词','song-ci','失调名','[]','平地一声雷。',6,'宋词/ci.song.19000.json','["平地一声雷。"]'),
('song-ci-421','失调名','无名氏','宋','宋词','song-ci','失调名','[]','休休得也□，云深处、高卧斜阳。',15,'宋词/ci.song.19000.json','["休休得也□，云深处、高卧斜阳。"]'),
('song-ci-422','失调名','无名氏','宋','宋词','song-ci','失调名','[]','单于若问君家世，说与教知。',21,'宋词/ci.song.19000.json','["单于若问君家世，说与教知。", "便是红窗迥底儿。"]'),
('song-ci-423','失调名','无名氏','宋','宋词','song-ci','失调名','[]','说与教知。',13,'宋词/ci.song.19000.json','["说与教知。", "便是中朝一汉儿。"]'),
('song-ci-424','失调名','无名氏','宋','宋词','song-ci','失调名','[]','便是监商孟客儿。',8,'宋词/ci.song.19000.json','["便是监商孟客儿。"]'),
('song-ci-425','减字木兰花','无名氏','宋','宋词','song-ci','减字木兰花','[]','家门希差。',52,'宋词/ci.song.19000.json','["家门希差。", "养得一枚依样画。", "百事无能。", "只去篱边缠倒藤。", "几回水上。", "轧捺不翻真个强。", "无处容他。", "只好炎天晒作巴。"]'),
('song-ci-426','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','光芒。',34,'宋词/ci.song.19000.json','["光芒。", "长万丈，司空见惯，应谓寻常。", "……仍传□、儋崖父老，只候蔡元长。"]'),
('song-ci-427','失调名','无名氏','宋','宋词','song-ci','失调名','[]','妙手庖人，搓得细如麻线。',93,'宋词/ci.song.19000.json','["妙手庖人，搓得细如麻线。", "面儿白、心下黑，身长行短。", "蓦地下来后，吓出一身冷汗。", "这一场欢会，早危如累卵。", "便做羊肉燥子，勃推饤碗。", "终不似、引盘美满。", "舞万遍。", "无心看。", "愁听弦管。", "收盘盏。", "寸肠暗断。"]'),
('song-ci-428','浪淘沙','无名氏','宋','宋词','song-ci','浪淘沙','[]','水饭恶冤家。',64,'宋词/ci.song.19000.json','["水饭恶冤家。", "些小姜瓜。", "尊前正欲饮流霞。", "却被伊来刚打住，好闷人那。", "不免着匙爬。", "一似吞沙。", "主人若也要人夸。", "莫惜更搀三五盏，锦上添花。"]'),
('song-ci-429','夜游宫','无名氏','宋','宋词','song-ci','夜游宫','[]','因被吾皇手诏。',69,'宋词/ci.song.19000.json','["因被吾皇手诏。", "把天下、寺来改了。", "大觉金仙也不小。", "德士道。", "却我甚头脑。", "道袍须索要。", "冠儿戴、恁且休笑。", "最是一种祥瑞好。", "古来少。", "葫芦上面生芝草。"]'),
('song-ci-430','西江月','无名氏','宋','宋词','song-ci','西江月','[]','早岁轻衫短帽。',58,'宋词/ci.song.19000.json','["早岁轻衫短帽。", "中间圆顶方袍。", "忽然天赐降宸毫。", "接引私心入道。", "可谓一身三教。", "如今且得逍遥。", "擎拳稽首拜云霄。", "有分长生不老。"]'),
('song-ci-431','青玉案','无名氏','宋','宋词','song-ci','青玉案','[]','钉鞋踏破祥符路。',80,'宋词/ci.song.19000.json','["钉鞋踏破祥符路。", "似白鹭、纷纷去。", "试盝幞头谁与度。", "八厢儿事，两员直殿，怀挟无藏处。", "时辰报尽天将暮。", "把笔胡填备员句。", "试问闲愁知几许。", "两条脂烛，半盂馊饭，一阵黄昏雨。"]'),
('song-ci-432','失调名','无名氏','宋','宋词','song-ci','失调名','[]','瘦得脸儿两指大。',8,'宋词/ci.song.19000.json','["瘦得脸儿两指大。"]'),
('song-ci-433','失调名','无名氏','宋','宋词','song-ci','失调名','[]','柳丝只解风前舞。',17,'宋词/ci.song.19000.json','["柳丝只解风前舞。", "诮系惹、那人不住。"]'),
('song-ci-434','滴滴金','无名氏','宋','宋词','song-ci','滴滴金','[]','当初亲下求言诏。',57,'宋词/ci.song.19000.json','["当初亲下求言诏。", "引得都来胡道。", "人人招是骆宝王，并洛阳年少。", "自讼监宫并岳庙。", "都一时闲了。", "误人多是误人多，误了人多少。"]'),
('song-ci-435','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','["\u592a\u6e56"]','平生太湖上，短棹几经过。',114,'宋词/ci.song.19000.json','["平生太湖上，短棹几经过。", "如今重到，何事愁与水云多。", "拟把匣中长剑，换取扁舟一叶，归去老渔蓑。", "银艾非吾事，丘壑已蹉跎。", "脍新鲈，斟美酒，起悲歌。", "太平生长，岂谓今日识兵戈。", "欲泻三江雪浪，净洗胡尘千里，不用挽天河。", "回首望霄汉，双泪堕清波。"]'),
('song-ci-436','失调名','无名氏','宋','宋词','song-ci','失调名','[]','做园子，得数载。',72,'宋词/ci.song.19000.json','["做园子，得数载。", "栽培得、那花木，就中堪爱。", "特将一个、保义酬劳，反做了、今日殃害。", "诏书下来索金带。", "这官告、看看毁坏。", "放牙笏、便担屎担，却依旧种菜。"]'),
('song-ci-437','失调名','无名氏','宋','宋词','song-ci','失调名','[]','叠假山、得保义。',62,'宋词/ci.song.19000.json','["叠假山、得保义。", "幞头上、带著百般村气。", "做模样、偏得人憎，又识甚条例。", "今日伏惟安置。", "官诰又来索气。", "不如更叠个盆山，卖八文十二。"]'),
('song-ci-438','结带巾','无名氏','宋','宋词','song-ci','结带巾','[]','头巾带。',64,'宋词/ci.song.19000.json','["头巾带。", "谁理会。", "三千贯赏钱，新行条例。", "不得向后长垂，与胡服相类。", "法甚严，人尽畏。", "便缝阔大带，向前面系。", "和我太学先辈，被人呼保义。"]'),
('song-ci-439','失调名','无名氏','宋','宋词','song-ci','失调名','[]','欲折花枝斜插鬓。',8,'宋词/ci.song.19000.json','["欲折花枝斜插鬓。"]'),
('song-ci-440','失调名','无名氏','宋','宋词','song-ci','失调名','[]','薰风时送芰荷香。',8,'宋词/ci.song.19000.json','["薰风时送芰荷香。"]'),
('song-ci-441','失调名','无名氏','宋','宋词','song-ci','失调名','[]','花有重开月再圆。',8,'宋词/ci.song.19000.json','["花有重开月再圆。"]'),
('song-ci-442','鹊桥仙','无名氏','宋','宋词','song-ci','鹊桥仙','[]','柳家一句最著题，道暮雨、芳尘轻洒。',17,'宋词/ci.song.19000.json','["柳家一句最著题，道暮雨、芳尘轻洒。"]'),
('song-ci-443','失调名','无名氏','宋','宋词','song-ci','失调名','[]','你自平生行短，不公正、欺物瞒心。',88,'宋词/ci.song.19000.json','["你自平生行短，不公正、欺物瞒心。", "交年夜、将烧毁，犹自昧神明。", "若还替得，你可知好里，争奈无凭。", "我虽然无口，肚里清醒。", "除非阎家大伯，一时间、批判昏沈。", "休痴呵，临时恐怕，各自要安身。"]'),
('song-ci-444','失调名','无名氏','宋','宋词','song-ci','失调名','[]','别有暗愁深意。',7,'宋词/ci.song.19000.json','["别有暗愁深意。"]'),
('song-ci-445','失调名','无名氏','宋','宋词','song-ci','失调名','[]','晓风吹人，酒醒时候。',10,'宋词/ci.song.19000.json','["晓风吹人，酒醒时候。"]'),
('song-ci-446','失调名','无名氏','宋','宋词','song-ci','失调名','[]','海棠花谢清明后。',8,'宋词/ci.song.19000.json','["海棠花谢清明后。"]'),
('song-ci-447','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','春晓千门放钥匙。',64,'宋词/ci.song.19000.json','["春晓千门放钥匙。", "万官班从出祥曦。", "九重彩浪浮龙盖，一点红云护赭衣。", "车马过，打球归。", "芳尘洒定不教飞。", "钧天品动回銮曲，十里珠帘待日西。"]'),
('song-ci-448','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','日暮迎祥对御回。',64,'宋词/ci.song.19000.json','["日暮迎祥对御回。", "宫花载路锦成堆。", "天津桥畔鞭声过，宣德楼前扇影开。", "奏舜乐，进尧杯。", "传宣车马上天街。", "君王喜与民同乐，八面三呼震地来。"]'),
('song-ci-449','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','紫禁烟光一万重。',64,'宋词/ci.song.19000.json','["紫禁烟光一万重。", "五门金碧射晴空。", "梨园羯鼓三千面，陆海鳌山十二峰。", "香雾重，月华浓。", "露台仙仗彩云中。", "朱栏画栋金泥幕，卷尽红莲十里风。"]'),
('song-ci-450','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','香雾氤氲结彩山。',64,'宋词/ci.song.19000.json','["香雾氤氲结彩山。", "蓬莱顶上驾头还。", "绣鞯狨坐三千骑，玉带金鱼四十班。", "风细细，佩珊珊。", "一天和气转春寒。", "千门万户笙萧里，十二楼台月上栏。"]'),
('song-ci-451','青玉案','无名氏','宋','宋词','song-ci','青玉案','[]','人生南北如歧路。',80,'宋词/ci.song.19000.json','["人生南北如歧路。", "世事悠悠等风絮。", "造化小儿无定据。", "翻来覆去，倒横直竖，眼见都如许。", "伊周功业何须慕。", "不学渊明便归去。", "坎止流行随所寓。", "玉堂金马，竹篱茅舍，总是无心处。"]'),
('song-ci-452','绛都春','无名氏','宋','宋词','song-ci','绛都春','[]','寒阴渐晓。',121,'宋词/ci.song.19000.json','["寒阴渐晓。", "报驿使探春，南枝开早。", "粉蕊弄香，芳脸凝酥琼枝小。", "雪天分外精神好。", "向白玉堂前应到。", "化工不管，朱门闭也，暗传音耗。", "轻渺。", "盈盈笑靥，称娇面、爱学宫妆新巧。", "几度醉吟，独倚栏干黄昏后。", "月笼疏影横斜照。", "更莫待、单于吹老。", "便须折取归来，胆瓶顿了。"]'),
('song-ci-453','孤鸾','无名氏','宋','宋词','song-ci','孤鸾','[]','天然标格。',119,'宋词/ci.song.19000.json','["天然标格。", "是小萼堆红，芳姿凝白。", "淡伫新妆，浅点寿阳宫额。", "东君相留厚意，倩年年、与传消息。", "昨夜前村雪里，有一枝先折。", "念故人、何处水云隔。", "纵驿使相逢，难寄春色。", "试问丹青手，是怎生描得。", "晓来一番雨过，更那堪、数声羌笛。", "归去和羹未晚，劝行人休摘。"]'),
('song-ci-454','金菊对芙蓉','无名氏','宋','宋词','song-ci','金菊对芙蓉','[]','花则一名，种分三色，嫩红妖白娇黄。',121,'宋词/ci.song.19000.json','["花则一名，种分三色，嫩红妖白娇黄。", "正清秋佳景，雨霁风凉。", "郊墟十里飘兰麝，潇洒处、旖旎非常。", "自然风韵，开时不惹，蝶乱蜂狂。", "携酒独揖蟾光。", "问花神何属，离兑中央。", "引骚人乘兴，广赋诗章。", "几多才子争攀折，嫦娥道，三种深香，状元红是，黄为榜眼，白探花郎。"]'),
('song-ci-455','失调名','无名氏','宋','宋词','song-ci','失调名','[]','郎马频嘶竟不来。',8,'宋词/ci.song.19000.json','["郎马频嘶竟不来。"]'),
('song-ci-456','失调名','无名氏','宋','宋词','song-ci','失调名','[]','轻暖轻寒，正是赏花天气。',12,'宋词/ci.song.19000.json','["轻暖轻寒，正是赏花天气。"]'),
('song-ci-457','失调名','无名氏','宋','宋词','song-ci','失调名','[]','盻盻秋波。',5,'宋词/ci.song.19000.json','["盻盻秋波。"]'),
('song-ci-458','失调名','无名氏','宋','宋词','song-ci','失调名','[]','春色恼人眠不得。',8,'宋词/ci.song.19000.json','["春色恼人眠不得。"]'),
('song-ci-459','失调名','无名氏','宋','宋词','song-ci','失调名','[]','千丝万绪惹春风。',8,'宋词/ci.song.19000.json','["千丝万绪惹春风。"]'),
('song-ci-460','失调名','无名氏','宋','宋词','song-ci','失调名','[]','燕子引雏飞。',6,'宋词/ci.song.19000.json','["燕子引雏飞。"]'),
('song-ci-461','失调名','无名氏','宋','宋词','song-ci','失调名','[]','莫怪沈腰易瘦。',7,'宋词/ci.song.19000.json','["莫怪沈腰易瘦。"]'),
('song-ci-462','失调名','无名氏','宋','宋词','song-ci','失调名','[]','双双飞燕柳边轻。',8,'宋词/ci.song.19000.json','["双双飞燕柳边轻。"]'),
('song-ci-463','失调名','无名氏','宋','宋词','song-ci','失调名','[]','帘卷画堂人寂静。',8,'宋词/ci.song.19000.json','["帘卷画堂人寂静。"]'),
('song-ci-464','失调名','无名氏','宋','宋词','song-ci','失调名','[]','一番雨过，池塘十里芰荷香。',13,'宋词/ci.song.19000.json','["一番雨过，池塘十里芰荷香。"]'),
('song-ci-465','失调名','无名氏','宋','宋词','song-ci','失调名','[]','湘簟展清波。',6,'宋词/ci.song.19000.json','["湘簟展清波。"]'),
('song-ci-466','失调名','无名氏','宋','宋词','song-ci','失调名','[]','醉乡天广大。',6,'宋词/ci.song.19000.json','["醉乡天广大。"]'),
('song-ci-467','失调名','无名氏','宋','宋词','song-ci','失调名','[]','云情雨意商量雪。',8,'宋词/ci.song.19000.json','["云情雨意商量雪。"]'),
('song-ci-468','失调名','无名氏','宋','宋词','song-ci','失调名','[]','凤楼帘卷鳌山对。',8,'宋词/ci.song.19000.json','["凤楼帘卷鳌山对。"]'),
('song-ci-469','失调名','无名氏','宋','宋词','song-ci','失调名','[]','箫鼓向晚。',5,'宋词/ci.song.19000.json','["箫鼓向晚。"]'),
('song-ci-470','失调名','无名氏','宋','宋词','song-ci','失调名','[]','倚风三喷横竹。',7,'宋词/ci.song.19000.json','["倚风三喷横竹。"]'),
('song-ci-471','失调名','无名氏','宋','宋词','song-ci','失调名','[]','卷上珠帘光。',6,'宋词/ci.song.19000.json','["卷上珠帘光。"]'),
('song-ci-472','失调名','无名氏','宋','宋词','song-ci','失调名','[]','轻暖轻寒，正是困人天气。',12,'宋词/ci.song.19000.json','["轻暖轻寒，正是困人天气。"]'),
('song-ci-473','失调名','无名氏','宋','宋词','song-ci','失调名','[]','一种相思两地愁。',8,'宋词/ci.song.19000.json','["一种相思两地愁。"]'),
('song-ci-474','失调名','无名氏','宋','宋词','song-ci','失调名','[]','饮尽莫留残。',6,'宋词/ci.song.19000.json','["饮尽莫留残。"]'),
('song-ci-475','秋霁','无名氏','宋','宋词','song-ci','秋霁','[]','壬戌之秋，是苏子与客，泛舟赤壁。',127,'宋词/ci.song.19000.json','["壬戌之秋，是苏子与客，泛舟赤壁。", "举酒属客，月明风细，水光与天相接。", "扣舷唱月。", "桂棹兰桨堪游逸。", "又有客。", "能吹洞箫，和声鸣烟。", "追想孟德、困於周郎，到今空有，当时踪迹。", "算惟有、清风朗月，取之无禁用不竭。", "客喜洗盏还再酌。", "既已同醉，相与枕藉舟中，始知东方，晃然既白。"]'),
('song-ci-476','贺新郎','无名氏','宋','宋词','song-ci','贺新郎','[]','步自雪堂去。',141,'宋词/ci.song.19000.json','["步自雪堂去。", "望临皋、将归二客，从余遵路。", "木叶萧萧霜露降，仰见天高月吐。", "共对影、行歌频顾。", "月白风清如此夜，叹无肴、有酒成虚度。", "闻薄暮，网罾举。", "归而斗酒谋诸妇。", "便携鳞载酒，相从旧追游处。", "断岸横江寻赤壁，不复江山如故，但放舟、中流容与。", "客去冥然方就睡，梦蹁跹、羽衣揖余语。", "相顾笑，遂惊寤。"]'),
('song-ci-477','如梦令','无名氏','宋','宋词','song-ci','如梦令','[]','韵似江梅标致。',40,'宋词/ci.song.19000.json','["韵似江梅标致。", "美似江梅多丽。", "清似腊梅香，白似雪梅香腻，非是。", "非是。", "我道梅花似你。"]'),
('song-ci-478','忆秦娥','无名氏','宋','宋词','song-ci','忆秦娥','[]','暮云碧。',56,'宋词/ci.song.19000.json','["暮云碧。", "佳人不见愁如织。", "愁如织。", "两行征雁，数声羌笛。", "锦书难寄西飞翼。", "无言只是空相忆。", "空相忆。", "纱窗人梦，梦双人只。"]'),
('song-ci-479','忆秦娥','无名氏','宋','宋词','song-ci','忆秦娥','[]','娇滴滴。',56,'宋词/ci.song.19000.json','["娇滴滴。", "双眉敛破春山色。", "春山色。", "为君含笑，为君愁蹙。", "多情别后无消息。", "此时更有谁知得。", "谁知得。", "夜深无寐，度江横笛。"]'),
('song-ci-480','忆秦娥','无名氏','宋','宋词','song-ci','忆秦娥','[]','秋寂寂。',56,'宋词/ci.song.19000.json','["秋寂寂。", "碧纱窗外人横笛。", "人横笛。", "天津桥上，旧曾听得。", "宫妆玉指无人识。", "龙吟水底声初息。", "声初息。", "月明江上，数峰凝碧。"]'),
('song-ci-481','浪淘沙','无名氏','宋','宋词','song-ci','浪淘沙','[]','帘外五更风。',64,'宋词/ci.song.19000.json','["帘外五更风。", "吹梦无踪。", "画楼重上与谁同。", "记得玉钗斜拨火，宝篆成空。", "回首紫金峰。", "雨润烟浓。", "一江春浪醉醒中。", "留得罗襟前日泪，弹与征鸿。"]'),
('song-ci-482','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','碧落横秋，浮云崩浪，夜凉先到梧桐。',118,'宋词/ci.song.19000.json','["碧落横秋，浮云崩浪，夜凉先到梧桐。", "荷花十丈，人在赤城中。", "凤髻尚梳雾湿，眉峰翠、的烁双瞳。", "多应是，金丹一粒，点就蕊仙宫。", "相逢。", "蓬岛客，酒翻银海，一饮如虹。", "弄横玉招月，吹上层空。", "青鸾传书满座，蟠桃树、已结轻红。", "拚沉醉，人间拍手，一笑有东风。"]'),
('song-ci-483','失调名','无名氏','宋','宋词','song-ci','失调名','[]','和尚性好耍。',52,'宋词/ci.song.19000.json','["和尚性好耍。", "贪恋一枝花。", "见说醉归明月夜。", "滋味难禁价。", "金帛宁论价。", "毒手遭他下。", "料想从今难更也。", "空惹傍人话。"]'),
('song-ci-484','望江南・忆江南','无名氏','宋','宋词','song-ci','望江南・忆江南','[]','江南竹，巧匠织成笼。',32,'宋词/ci.song.19000.json','["江南竹，巧匠织成笼。", "赠与吾师藏法体，碧潭深处伴蛟龙。", "色即是成空。"]'),
('song-ci-485','西江月','无名氏','宋','宋词','song-ci','西江月','[]','早晚以成行色，主人莫与留延。',58,'宋词/ci.song.19000.json','["早晚以成行色，主人莫与留延。", "正当春月艳阳天。", "去赛从前心愿。", "执状去呈仙尉，殷勤早与周旋。", "不辞客路往来难，暂辍舞裙歌扇。"]'),
('song-ci-486','燕山亭','无名氏','宋','宋词','song-ci','燕山亭','[]','风雨无情，红药吐时，下得恹恹摧挫。',122,'宋词/ci.song.19000.json','["风雨无情，红药吐时，下得恹恹摧挫。", "云艳卷凉，旋汲银屏，收拾二三千朵。", "长日留伊，要把酒、不教放过。", "无那。", "越放纵香心，越盘来大。", "特地点检笙歌，先要吹个、六么曲破。", "总是少年，负却才名，佳客共伊围坐。", "粉薄香浓，为笑多、不肯梳裹。", "知麽。", "须醉倒、今宵伴我。"]'),
('song-ci-487','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','山色晴岚景物佳。',64,'宋词/ci.song.19000.json','["山色晴岚景物佳。", "暖烘回雁起平沙。", "东郊渐觉花供眼，南陌依稀草吐芽。", "堤上柳，未藏鸦。", "寻芳趁步到山家。", "陇头几树红梅落，红杏枝头未著花。"]'),
('song-ci-488','眼儿媚','无名氏','宋','宋词','song-ci','眼儿媚','[]','深闺小院日初长。',57,'宋词/ci.song.19000.json','["深闺小院日初长。", "娇女绮罗裳。", "不做东君造化，金针刺绣群芳样。", "斜枝嫩叶包开蕊。", "唯只欠馨香。", "曾向园林深处，引教蝶乱蜂狂。"]'),
('song-ci-489','南乡子','无名氏','宋','宋词','song-ci','南乡子','[]','帘卷水西楼。',66,'宋词/ci.song.19000.json','["帘卷水西楼。", "一曲新腔唱打油。", "宿雨眠云年少梦，休讴。", "且尽生前酒一瓯。", "明日又登舟。", "却指今宵是旧游。", "同是他乡沦落客，休愁。", "月子弯弯照几州。"]'),
('song-ci-490','失调名','无名氏','宋','宋词','song-ci','失调名','[]','帝里元宵风光好，胜仙岛蓬莱。',61,'宋词/ci.song.19000.json','["帝里元宵风光好，胜仙岛蓬莱。", "玉动飞尘，车喝绣毂，月照楼台。", "三官此夕欢谐。", "金莲万盏，撒向天街。", "讶鼓通宵，花灯竟起，五夜齐开。"]'),
('song-ci-491','酹江月・念奴娇','无名氏','宋','宋词','song-ci','酹江月・念奴娇','[]','阳春歌阙，正玉梅翻雪，江涛如海。',120,'宋词/ci.song.19000.json','["阳春歌阙，正玉梅翻雪，江涛如海。", "秀孕东阳山水，果诞黑头元宰。", "早蹋天扉，洪钧独运，嘉会符千戴。", "衔杯乐圣，不妨机务聊解。", "且恁笑弄云泉，太平勋业，说与苍生须在。", "闻道槐庭虚位久，天意端如有待。", "衮绣来时，渔蓑脱取，留我他年晒。", "良辰一笑，醉乡天地宽大。"]'),
('song-ci-492','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','明月双溪上，胜景号金华。',114,'宋词/ci.song.19000.json','["明月双溪上，胜景号金华。", "当年此夕，多少鸾凤杂云霞。", "共拥飘飘仙伯，来作人间英杰，王谢旧名家。", "纶绋妙文采，帷幄富忠嘉。", "圣天子，形梦寐，眷尤加。", "麒麟阁上，早晚丹陛听宣麻。", "鼎轴无穷勋业，岁岁熏风日永，萱秀北堂花。", "潋滟绮筵酒，寿算等河沙。"]'),
('song-ci-493','水龙吟','无名氏','宋','宋词','song-ci','水龙吟','[]','昔人风调谁高，二疏盛日还乡里。',126,'宋词/ci.song.19000.json','["昔人风调谁高，二疏盛日还乡里。", "公卿祖道，百城图画，争传佳事。", "闻自垂车日，都门外、送车凡几。", "今世无工画，署之勿道，焜煌处、烛青史。", "佳甚东阳山水。", "是昔时、钓游某地。", "风流脱似，洛中耆老，一人而已。", "好为霞觞釂，正庭阶、彩衣荣侍。", "便明朝有诏，启门解说，值先生醉。"]'),
('song-ci-494','谒金门','无名氏','宋','宋词','song-ci','谒金门','[]','春不老。',53,'宋词/ci.song.19000.json','["春不老。", "细数花风犹到。", "挥翰玉堂应早早。", "花知中令考。", "词进芳笺才调。", "文饮清樽怀抱。", "一片潇湘供一笑。", "楚山青未了。"]'),
('song-ci-495','千春词','无名氏','宋','宋词','song-ci','千春词','[]','瞿岭云齐，建溪源远，庆衍英奇。',138,'宋词/ci.song.19000.json','["瞿岭云齐，建溪源远，庆衍英奇。", "且机乘天巧，臣贤主圣，后光同日月以为期。", "千戴相逢，一朝盛事，自昔人夸今见之。", "催归诏，要领班宸殿，捧万年卮。", "嘻嘻。", "莫道春迟。", "已著梅梢第一枝。", "映紫荷持橐，星辰步武，黄金横带，朝夕论思。", "不但斯时，重恢事业，整顿乾坤弘所施。", "洪钧转，虽寒根雪谷，物物生辉。"]'),
('song-ci-496','酹江月・念奴娇','无名氏','宋','宋词','song-ci','酹江月・念奴娇','[]','欢声雷动，问邦民，知道君候生日。',120,'宋词/ci.song.19000.json','["欢声雷动，问邦民，知道君候生日。", "欲把天文占好事，夜半遥瞻南极。", "耿耿三台，寒光相射，瑞采连珠壁。", "自今以始，我公眉寿千亿。", "见说燕寝香凝，旌旗微动，猎猎薰风入。", "收拾乾坤生长意，留向人间敷锡。", "预约明年，难兄难弟，同侍虞琴侧。", "坐令仁寿，八荒开此寿域。"]'),
('song-ci-497','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','五狱三光，孕秀精神，时生俊髦。',138,'宋词/ci.song.19000.json','["五狱三光，孕秀精神，时生俊髦。", "看出匣锋芒，备施盘错，济川力量，历试风涛。", "直卷经纶，十徵不就，争羡先生出处高。", "徜徉处，有晋公绿野，陶令东皋。", "精神翰墨游遨。", "无一点风霜上鬓毛。", "不访蓬莱，遍搜仙药，不登阆苑，三摘蟠桃。", "洒洒丰姿，棱棱标致，长对梅花雪里梢。", "青如许，与老松苍竹，定岁寒交。"]'),
('song-ci-498','念奴娇','无名氏','宋','宋词','song-ci','念奴娇','[]','今年秋早，似常年、人世光阴如电。',120,'宋词/ci.song.19000.json','["今年秋早，似常年、人世光阴如电。", "君看老仙风度别，绿发芳瞳长健。", "细数平生，三千功行，一一修持遍。", "通明殿上，钧天张乐高燕。", "应似六一先生，神清之洞，万仞苍苔藓。", "少待中原开霁了，一片闲云舒卷。", "姹女炼成，婴儿养就，坐阅蓬莱浅。", "青霄笙鹤，也应回顾鸡犬。"]'),
('song-ci-499','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','早是玉堂客，犹著侍臣冠。',114,'宋词/ci.song.19000.json','["早是玉堂客，犹著侍臣冠。", "便为霖去亦晚，何况此身闲。", "胸次光风霁月，意味满庭芳草，体用两相关。", "坐对粤山好，名更重於山。", "寿生申，霜肃晓，露宾寒。", "从教重九过了，政有菊堪餐。", "日绕东篱笑傲，香共秋容淡薄，晚节要人看。", "久不见贾谊，天已问平安。"]'),
('song-ci-500','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','一线添宫绣，画景刻初还。',114,'宋词/ci.song.19000.json','["一线添宫绣，画景刻初还。", "五云旬浃不散，瑞色满乾坤。", "凝作山堂佳气，来庆冰壶寿旦，戏彩喜重斑。", "相对窦桂椿，环列谢芝兰。", "经纶事，戡定策，两才全。", "苍生翘首三载，霖雨报东山。", "已感宵衣梦寐，应录御屏姓字，光动紫微垣。", "一骑日边至，趣诏凤池班。"]'),
('song-ci-501','满江红','无名氏','宋','宋词','song-ci','满江红','[]','蓓蕾江梅，正好是、小春时候。',115,'宋词/ci.song.19000.json','["蓓蕾江梅，正好是、小春时候。", "螺浦下、乾坤间气，山川锺秀。", "作起风流今几代，诚斋心印亲传授。", "更修名、大节与谁同，韩山斗。", "修月斧，擎天手。", "鸿敛翼，云归岫。", "有庄园陶径，菊滋松茂。", "只恐东山真事业，更应西洛登耆旧。", "有年年、宣勤到鳌扉，黄封酒。"]'),
('song-ci-502','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','北斗璇魁，南闽元帅，西清真地行仙。',113,'宋词/ci.song.19000.json','["北斗璇魁，南闽元帅，西清真地行仙。", "东林白社，依约认前缘。", "霞洞天台万叠，记当时、秀减山川。", "三生梦，岩公宝刻，云锁石桥边。", "时度御炉吹雾，宫烛传烟。", "望图中家庆，朱紫蝉联。", "入见辕门佳节，到新春、长是开筵。", "明年看，五云深处，黄发映貂蝉。"]'),
('song-ci-503','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','三楚诗书帅，人物压中州。',114,'宋词/ci.song.19000.json','["三楚诗书帅，人物压中州。", "飘飘青琐，典刑蜀国旧风流。", "小袖玉堂挥手，来拥元戎十乘，红旆照青油。", "尺一唤归去，名久在金瓯。", "倚春声，赓水调，倩歌喉。", "登龙旧客，只回误上武陵舟。", "正是蟠桃开也，特向尊前为寿，一醉一千秋。", "携取此花去，还侍玉宸游。"]'),
('song-ci-504','朝中措','无名氏','宋','宋词','song-ci','朝中措','[]','郎星初度一旬前。',57,'宋词/ci.song.19000.json','["郎星初度一旬前。", "瑞雪早蹁跹。", "金节耆祥称寿，一妃宣劝迎年。", "锦天绣地，薰香手祷，福禄如川。", "只恐催呈魏笏，便还紫橐青毡。"]'),
('song-ci-505','宝鼎现','无名氏','宋','宋词','song-ci','宝鼎现','[]','天高良月。',187,'宋词/ci.song.19000.json','["天高良月。", "瑞霭葱倩，绮霞粲浩。", "望宝阁、奎躔交绚，秀毓文星正佳节。", "九万里俱在下，礼乐三千剀切。", "扶兴运、魁星标瑞，曾补赭黄衮阙。", "盎盎一道棠阴芾，宜福星、临照南国。", "岁屡稔，月沉夜柝，父老欢谣齐喜溢。", "庆衮衮、罗庭前兰玉，好是香连夜月。", "十万户深深祝，愿此寿星南极。", "自是天上神仙，宽宸顾、实劳耆德。", "辄使星入觐，又报日边消息。", "天为遣、梅花催雪。", "惟有春知得。", "要待列、金鼎和羹，两两台星齐色。"]'),
('song-ci-506','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','阊阖初开，羽葆来从，斗畔天南。',140,'宋词/ci.song.19000.json','["阊阖初开，羽葆来从，斗畔天南。", "看长身玉立，精神耿耿，风姿冰冷，琼佩珊珊。", "政数龚黄，才称屈宋，君合居其伯仲间。", "犹堪庆，早恩沾令子，新著朝冠。", "东园。", "未即开藩。", "且乡曲吾曹共往还。", "向棋边几见，烂柯樵客，琴中时写，流水高山。", "野鹤立阶，灵龟支坐，修竹梅花伴岁寒。", "荣华事，有传家从橐，立上清班。"]'),
('song-ci-507','虞美人','无名氏','宋','宋词','song-ci','虞美人','[]','翠屏罗幕遮前后。',66,'宋词/ci.song.19000.json','["翠屏罗幕遮前后。", "舞袖翻长寿。", "紫髯冠佩御炉香。", "看取明年归奉、万年觞。", "今宵池上蟠桃席。", "咫尺长安日。", "宝烟飞焰万花浓。", "试看中间白鹤、驾仙风。"]'),
('song-ci-508','瑞鹤仙','无名氏','宋','宋词','song-ci','瑞鹤仙','[]','薰风送炎暑。',127,'宋词/ci.song.19000.json','["薰风送炎暑。", "正万品亨嘉，恢台当序。", "祥烟淡天宇。", "渐银蟾满魄，金茎凝露。", "奎躔壁度。", "见寒光、凌乱辉吐。", "记当年此际，真仙命世，恍惊飙驭。", "荣遇。", "妙龄英发，腾实蜚声，早班郎署。", "歌喧五裤。", "更万里，期轩翥。", "暂乘轺揽辔，肃将王命，已洽百城休誉。", "愿从今、夕揭金瓯，永隆依注。"]'),
('song-ci-509','万年欢','无名氏','宋','宋词','song-ci','万年欢','[]','南极星明，问笙歌弦管，今是何夕。',122,'宋词/ci.song.19000.json','["南极星明，问笙歌弦管，今是何夕。", "竹马儿童，尽道使君生日。", "又见蟠桃结实。", "是谁向、珠宫偷得。", "炉烟袅，惟愿年年，使君常驻熊轼。", "那知宦游似客。", "任双旌五马，飘转南北。", "细柳甘棠，都是使君亲植。", "见说吾皇仄席。", "恐非晚、归朝宣直。", "功成了，却隐东山，算惟龟鹤相识。"]'),
('song-ci-510','酹江月・念奴娇','无名氏','宋','宋词','song-ci','酹江月・念奴娇','[]','东南锺秀。',122,'宋词/ci.song.19000.json','["东南锺秀。", "记当年、玉麟坠地，风云奔走。", "别驾风流才展骥，未快经纶大手。", "风月平分，吏民胥庆，松李阴浓昼。", "满城灯火，崧高神降时候。", "好是今夕华筵，水沉烟里，竹径松姿瘦。", "闻道君王仄席，尺一凤凰飞诏。", "堤筑新沙，印垂大斗，毡复貂蝉旧。", "麒麟勋业，庄椿难计眉寿。"]'),
('song-ci-511','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','天遣东皇，来庆诞辰，和气先回。',139,'宋词/ci.song.19000.json','["天遣东皇，来庆诞辰，和气先回。", "趁未将风月，平分八桂，且垂弧矢，相映三槐。", "歌遏行云，舞萦回雪，不比常年寿宴开。", "有贤守，送三千乐指，环侍金罍。", "文章政事奇哉。", "曾飞舄双凫天外来。", "便合除之六察，少旌最绩，何为别驾，暂屈长才。", "尚亿传家，行将跨灶，岂但侯藩与外台。", "称觞看，灵龟支坐，老鹤眠阶。"]'),
('song-ci-512','东坡引','无名氏','宋','宋词','song-ci','东坡引','[]','人物伊周样。',70,'宋词/ci.song.19000.json','["人物伊周样。", "清政龚黄状。", "平分风月双溪上。", "红颜方少壮。", "红颜方少壮。", "生贤令节，满觞摇漾。", "红袖舞，青蛾唱。", "我来祝寿无他望。", "相门重拜相。", "相门重拜相。"]'),
('song-ci-513','木兰花・玉楼春','无名氏','宋','宋词','song-ci','木兰花・玉楼春','[]','北湖云锦。',52,'宋词/ci.song.19000.json','["北湖云锦。", "铺遍琉璃三万顷。", "风月诗仙。", "趁得花时出洞天。", "红菱碧藕。", "满劝一杯千岁寿。", "来岁看花。", "新筑苏堤路上沙。"]'),
('song-ci-514','八宝妆','无名氏','宋','宋词','song-ci','八宝妆','[]','是舍人才调，犹采茅、紫芝峰。',123,'宋词/ci.song.19000.json','["是舍人才调，犹采茅、紫芝峰。", "有列宿心胸，清辞太白，雅趣元龙。", "从他暂、无毡官冷，怡然怀抱自从容。", "枫陛荐章吻合，金闺仙籍名通。", "暑馀凉送薰风。", "圆桂魄、丽遥空。", "庆初度垂弧，莲开十丈，酒满千锺。", "明年称寿何处，看玉犀、人在玉堂中。", "藻鉴正当莲省，诸生来到蟾宫。"]'),
('song-ci-515','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','学富总龟，英蜚漕鹗，正当少年。',139,'宋词/ci.song.19000.json','["学富总龟，英蜚漕鹗，正当少年。", "向山阴发轫，从容莲幕，结知当路，翠剡争先。", "万斛龙骧，湖襄飞饷，赏秩新纶来日边。", "重重庆，又金鱼新渥，玉树芝兰。", "今朝好语欢传。", "正南极真人生世天。", "是紫囊阴隲，朱幡美德，平山锺秀，崧岳生贤。", "事业惊人，行魁胪唱，展庆公庭云母间。", "称觞祝，对今宵明月，千古团圆。"]'),
('song-ci-516','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','梅雨初晴，时当夏五，一轮桂魄方圆。',118,'宋词/ci.song.19000.json','["梅雨初晴，时当夏五，一轮桂魄方圆。", "平山毓秀，间世产英贤。", "那更椿庭戏彩，祗觞处、簇拥神仙。", "荷囊紫，朱幡辉映，新渥又兰孙。", "山阴，方借迳，结知当路，荐剡争先。", "况湖襄输转，赏秩新颁。", "更喜两飞漕鹗，魁兰省、首听胪传。", "丹墀上，屏分云母，鲁后与周前。"]'),
('song-ci-517','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','禁卫传呼约下廊。',64,'宋词/ci.song.19000.json','["禁卫传呼约下廊。", "层层掌扇簇亲王。", "明珠照地三千乘，一片春雷入未央。", "宫漏永，柳街长。", "华灯偏共月争光。", "乐声都在人声里，五夜车尘马足香。"]'),
('song-ci-518','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','宝炬金莲一万条。',64,'宋词/ci.song.19000.json','["宝炬金莲一万条。", "火龙围辇转州桥。", "月迎仙仗回三殿，风递韵音下九霄。", "登复道，听鸣鞘。", "再颁酥酒赐臣僚。", "太平无事多欢乐，夜半传宣放早朝。"]'),
('song-ci-519','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','玉座临轩宴近臣。',64,'宋词/ci.song.19000.json','["玉座临轩宴近臣。", "御楼灯火发春温。", "九重天上闻仙乐，万宝床边侍至尊。", "花似海，月如盆。", "不任宣劝醉醺醺。", "岂知头上宫花重，贪爱传柑遗细君。"]'),
('song-ci-520','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','九陌游人起暗尘。',64,'宋词/ci.song.19000.json','["九陌游人起暗尘。", "一天灯雾锁彤云。", "瑶台雪映无穷玉，阆苑花开不夜春。", "攒宝骑，簇雕轮。", "汉家宫阙五侯门。", "景阳钟动才归去，犹挂西窗望月痕。"]'),
('song-ci-521','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','宣德楼前雪未融。',64,'宋词/ci.song.19000.json','["宣德楼前雪未融。", "贺正人见彩山红。", "九衢照影纷纷月，万井吹香细细风。", "复道远，暗相通。", "平阳主第五王宫。", "凤萧声里春寒浅，不到珠帘第二重。"]'),
('song-ci-522','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','风约微云不放阴。',64,'宋词/ci.song.19000.json','["风约微云不放阴。", "满天星点缀明金。", "烛龙衔耀烘残雪，羯鼓催花发上林。", "河影转，漏声沈。", "缕衣罗薄暮云深。", "更期明夜相逢处，还尽今宵未足心。"]'),
('song-ci-523','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','五日都无一日阴。',64,'宋词/ci.song.19000.json','["五日都无一日阴。", "住来车马闹如林。", "葆真行到烛初上，丰乐游归夜已深。", "人未散，月将沈。", "更期明夜到而今。", "归来尚向灯前说，犹恨追游不称心。"]'),
('song-ci-524','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','彻晓华灯照凤城。',64,'宋词/ci.song.19000.json','["彻晓华灯照凤城。", "犹嗔宫漏促天明。", "九重天上闻花气，五色云中应笑声。", "频报道，奏河清。", "万民和乐见人情。", "年丰米贱无边事，万国称觞贺太平。"]'),
('song-ci-525','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','忆得当年全盛时。',64,'宋词/ci.song.19000.json','["忆得当年全盛时。", "人情物态自熙熙。", "家家帘幕人归晚，处处楼台月上迟。", "花市里，使人迷。", "州东无暇看州西。", "都人只到收灯夜，已向樽前约上池。"]'),
('song-ci-526','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','步障移春锦绣丛。',64,'宋词/ci.song.19000.json','["步障移春锦绣丛。", "珠帘翠幕护春风。", "沈香甲煎薰炉暖，玉树明金蜜炬融。", "车流水，马游龙。", "欢声浮动建章宫。", "谁怜此夜春江上，魂断黄梁一梦中。"]'),
('song-ci-527','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','真个亲曾见太平。',64,'宋词/ci.song.19000.json','["真个亲曾见太平。", "元宵且说景龙灯。", "四方同奏升平曲，天下都无叹息声。", "长月好，定天晴。", "人人五夜到天明。", "如今一把伤心泪，犹恨江南过此生。"]'),
('song-ci-528','失调名','无名氏','宋','宋词','song-ci','失调名','[]','有个秀才姓汪。',27,'宋词/ci.song.19000.json','["有个秀才姓汪。", "骑个驴儿过江。", "江又过不得，做尽万千趋锵。"]'),
('song-ci-529','失调名','无名氏','宋','宋词','song-ci','失调名','[]','有个秀才姓汪。',28,'宋词/ci.song.19000.json','["有个秀才姓汪。", "住在祁门下乡。", "行第排来四八，做尽万千趋锵。"]'),
('song-ci-530','失调名','无名氏','宋','宋词','song-ci','失调名','[]','何时一尊酒，重与细论文。',12,'宋词/ci.song.19000.json','["何时一尊酒，重与细论文。"]'),
('song-ci-531','失调名','无名氏','宋','宋词','song-ci','失调名','[]','六论不知出处。',28,'宋词/ci.song.19000.json','["六论不知出处。", "写得乌梅几字。", "圣恩广大如天，也赐束帛归去。"]'),
('song-ci-532','失调名','无名氏','宋','宋词','song-ci','失调名','[]','高文虎，称伶俐。',67,'宋词/ci.song.19000.json','["高文虎，称伶俐。", "万苦千辛，作个放生亭记。", "后头没一句说著朝廷，尽把师　归美。", "这老子忒无廉耻。", "不知润笔能几。", "夏王说不是商王，只怕伏生是你。"]'),
('song-ci-533','失调名','无名氏','宋','宋词','song-ci','失调名','[]','十年前事，浑似梦初惊。',11,'宋词/ci.song.19000.json','["十年前事，浑似梦初惊。"]'),
('song-ci-534','失调名','无名氏','宋','宋词','song-ci','失调名','[]','千里有个好相识，望青山一色。',14,'宋词/ci.song.19000.json','["千里有个好相识，望青山一色。"]'),
('song-ci-535','失调名','无名氏','宋','宋词','song-ci','失调名','[]','五马游春，彩佩照人，光生南陌。',15,'宋词/ci.song.19000.json','["五马游春，彩佩照人，光生南陌。"]'),
('song-ci-536','失调名','无名氏','宋','宋词','song-ci','失调名','[]','炉香如雾斗帐深。',8,'宋词/ci.song.19000.json','["炉香如雾斗帐深。"]'),
('song-ci-537','失调名','无名氏','宋','宋词','song-ci','失调名','[]','香野锦林谁是主。',8,'宋词/ci.song.19000.json','["香野锦林谁是主。"]'),
('song-ci-538','失调名','无名氏','宋','宋词','song-ci','失调名','[]','一庭影浸梧竹。',7,'宋词/ci.song.19000.json','["一庭影浸梧竹。"]'),
('song-ci-539','金钱子','无名氏','宋','宋词','song-ci','金钱子','[]','昨夜金风，黄叶乱飘阶下。',93,'宋词/ci.song.19000.json','["昨夜金风，黄叶乱飘阶下。", "听窗前、芭蕉雨打。", "触处池塘，睹风荷凋谢。", "景色凄凉，总闲却、舞台歌榭。", "独倚阑干，惟有木犀幽雅。", "吐清香、胜如兰麝。", "似金垒妆成，想丹青难画。", "纤手折来，胆瓶中、一枝潇洒。"]'),
('song-ci-540','念奴娇','无名氏','宋','宋词','song-ci','念奴娇','[]','沁园秋早。',121,'宋词/ci.song.19000.json','["沁园秋早。", "对亭台冷落，荒凉池沼。", "西帝晨游无异胜，都把仙花开了。", "金粟玲珑，鹅黄娇嫩，不管霜风悄。", "清香入梦，梦魂惟怕天晓。", "乘兴折取一枝，满身兰麝，不减蟾宫好。", "赠与佳人，因笑道、休学姮娥空老。", "待约明朝，金英满地，莫遣儿童扫。", "相将花上，醉眠尤胜芳草。"]'),
('song-ci-541','失调名','无名氏','宋','宋词','song-ci','失调名','[]','芳草绿如茵，与蓝袍、草争翠色。',15,'宋词/ci.song.19000.json','["芳草绿如茵，与蓝袍、草争翠色。"]'),
('song-ci-542','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','五百人中第一仙。',64,'宋词/ci.song.19000.json','["五百人中第一仙。", "等闲平步上青天。", "绿袍乍著君恩重，黄榜初开御墨鲜。", "龙作马，玉为鞭。", "花如罗绮柳如绵。", "时人莫讶登科早，自是嫦娥爱少年。"]'),
('song-ci-543','鹊桥仙','无名氏','宋','宋词','song-ci','鹊桥仙','[]','我嗏今夜为情忙，又那得、工夫送巧。',17,'宋词/ci.song.19000.json','["我嗏今夜为情忙，又那得、工夫送巧。"]'),
('song-ci-544','失调名','无名氏','宋','宋词','song-ci','失调名','[]','瑞霞成绮。',17,'宋词/ci.song.19000.json','["瑞霞成绮。", "映舴艋棹轻，鲤鱼狂风起。"]'),
('song-ci-545','失调名','无名氏','宋','宋词','song-ci','失调名','[]','□□□□□金缕。',14,'宋词/ci.song.19000.json','["□□□□□金缕。", "探听春来处。"]'),
('song-ci-546','失调名','无名氏','宋','宋词','song-ci','失调名','[]','晓日楼头残雪尽。',32,'宋词/ci.song.19000.json','["晓日楼头残雪尽。", "乍破腊、风传春信。", "彩燕丝鸡，珠幡玉胜，并归钗鬓。"]'),
('song-ci-547','失调名','无名氏','宋','宋词','song-ci','失调名','[]','南楼人未起。',17,'宋词/ci.song.19000.json','["南楼人未起。", "爆竹声闻，应在笙歌里。"]'),
('song-ci-548','失调名','无名氏','宋','宋词','song-ci','失调名','[]','竹爆当门庭，震门陛也。',11,'宋词/ci.song.19000.json','["竹爆当门庭，震门陛也。"]'),
('song-ci-549','失调名','无名氏','宋','宋词','song-ci','失调名','[]','待醉里小王，书写副、神荼郁垒。',15,'宋词/ci.song.19000.json','["待醉里小王，书写副、神荼郁垒。"]'),
('song-ci-550','木兰花・玉楼春','无名氏','宋','宋词','song-ci','木兰花・玉楼春','[]','东风昨夜吹春昼。',64,'宋词/ci.song.19000.json','["东风昨夜吹春昼。", "陡觉去年梅蕊旧。", "谁人能解把长绳，系得乌飞并兔走。", "清香潋滟杯中酒。", "新眼苗条江上柳。", "尊前莫惜玉颜酡。", "且喜一年年入手。"]'),
('song-ci-551','木兰花・玉楼春','无名氏','宋','宋词','song-ci','木兰花・玉楼春','[]','东风昨夜归来后。',64,'宋词/ci.song.19000.json','["东风昨夜归来后。", "景物便为春意候。", "金丝齐奏喜新春，愿介香醪千岁寿。", "寻花插破桃枝臭。", "造化工夫先到柳。", "熔酥剪彩恨无香，且放真香先入酒。"]'),
('song-ci-552','失调名','无名氏','宋','宋词','song-ci','失调名','[]','捏个牛儿体态。',35,'宋词/ci.song.19000.json','["捏个牛儿体态。", "按年令，旋拖五彩。", "鼓乐相迎，红裙捧拥，表一个、胜春节届。"]'),
('song-ci-553','失调名','无名氏','宋','宋词','song-ci','失调名','[]','彩缕旛儿花枝小。',17,'宋词/ci.song.19000.json','["彩缕旛儿花枝小。", "凤钗上、轻轻斜袅。"]'),
('song-ci-554','失调名','无名氏','宋','宋词','song-ci','失调名','[]','金吾不禁元宵，漏声更莫催晓。',14,'宋词/ci.song.19000.json','["金吾不禁元宵，漏声更莫催晓。"]'),
('song-ci-555','失调名','无名氏','宋','宋词','song-ci','失调名','[]','况今宵好景，金吾不禁，玉漏休催。',16,'宋词/ci.song.19000.json','["况今宵好景，金吾不禁，玉漏休催。"]'),
('song-ci-556','失调名','无名氏','宋','宋词','song-ci','失调名','[]','金铺翠、蛾毛巧。',31,'宋词/ci.song.19000.json','["金铺翠、蛾毛巧。", "是工夫不少。", "闹蛾儿拣了蜂儿卖，卖雪柳、宫梅好。"]'),
('song-ci-557','失调名','无名氏','宋','宋词','song-ci','失调名','[]','灯球儿小，闹蛾儿颤。',16,'宋词/ci.song.19000.json','["灯球儿小，闹蛾儿颤。", "又何须头面。"]'),
('song-ci-558','新水令','无名氏','宋','宋词','song-ci','新水令','[]','冒风连骑出金城，闻孤猿韵切，怀念亲眷。',147,'宋词/ci.song.19000.json','["冒风连骑出金城，闻孤猿韵切，怀念亲眷。", "为笑徐都尉，徒夸彩绘，写出盈盈娇面。", "振旅阗阗。", "讶睹阆苑神仙。", "越公深骤万马，侵凌转盼。", "感先锋，容放镜，收鸾鉴一半。", "归前阵，惨怛切，同陪元帅恣欢恋。", "二岁偶尔，将军沈醉连绵，私令婢捧菱花，都市寻遍。", "新官听说邀郎宴。", "因令赋悲欢。", "孰敢。", "做人甚难。", "梅妆复照，傅粉重见。"]'),
('song-ci-559','驻马听','无名氏','宋','宋词','song-ci','驻马听','[]','雕鞍成谩驻。',115,'宋词/ci.song.19000.json','["雕鞍成谩驻。", "望断也不归，院深天暮。", "倚遍旧日，曾共凭肩门户。", "踏青何处所，想醉拍、春衫歌舞。", "征旆举。", "一步红尘，一步回顾。", "行行愁独语。", "想媚容、今宵怨郎不住。", "来为相思苦。", "又空将愁去。", "人生无定据。", "叹后会、不知何处。", "愁万缕。", "仗东风、和泪吹与。"]'),
('song-ci-560','南歌子','无名氏','宋','宋词','song-ci','南歌子','[]','禁苑沈沈静，春波漾漾行。',62,'宋词/ci.song.19000.json','["禁苑沈沈静，春波漾漾行。", "仙姿才韵两相并。", "叶上题诗、千古得佳名。", "墙外分明见，花间隐约声。", "银钩掷处眼双明。", "应讶昔时、不得见情人。"]'),
('song-ci-561','失调名','无名氏','宋','宋词','song-ci','失调名','[]','角黍厅前，祭天神、妆成异果。',14,'宋词/ci.song.19000.json','["角黍厅前，祭天神、妆成异果。"]'),
('song-ci-562','失调名','无名氏','宋','宋词','song-ci','失调名','[]','旋酌菖蒲酒，灵气满芳尊。',12,'宋词/ci.song.19000.json','["旋酌菖蒲酒，灵气满芳尊。"]'),
('song-ci-563','失调名','无名氏','宋','宋词','song-ci','失调名','[]','自结成同心百索。',18,'宋词/ci.song.19000.json','["自结成同心百索。", "祝愿子、更亲自系著。"]'),
('song-ci-564','阮郎归','无名氏','宋','宋词','song-ci','阮郎归','[]','及妆时结薄衫儿。',56,'宋词/ci.song.19000.json','["及妆时结薄衫儿。", "蒙金艾虎儿。", "画罗领抹缬裙儿。", "盆莲小景儿。", "香袋子，搐钱儿。", "胸前一对儿。", "绣帘妆罢出来时。", "问人宜不宜。"]'),
('song-ci-565','阮郎归','无名氏','宋','宋词','song-ci','阮郎归','[]','门儿高挂艾人儿。',56,'宋词/ci.song.19000.json','["门儿高挂艾人儿。", "鹅儿粉扑儿。", "结儿缀着小符儿。", "蛇儿百索儿。", "纱帕子，玉环儿。", "孩儿画扇儿。", "奴儿自是豆娘儿。", "今朝正及时。"]'),
('song-ci-566','失调名','无名氏','宋','宋词','song-ci','失调名','[]','双凤钗头，争带御书符。',11,'宋词/ci.song.19000.json','["双凤钗头，争带御书符。"]'),
('song-ci-567','失调名','无名氏','宋','宋词','song-ci','失调名','[]','才向兰汤浴罢，娇羞簪云髻，正雅称鸳鸯会。',20,'宋词/ci.song.19000.json','["才向兰汤浴罢，娇羞簪云髻，正雅称鸳鸯会。"]'),
('song-ci-568','失调名','无名氏','宋','宋词','song-ci','失调名','[]','才向兰汤浴罢，娇羞困、殢人未忺梳掠。',30,'宋词/ci.song.19000.json','["才向兰汤浴罢，娇羞困、殢人未忺梳掠。", "艾虎衫儿，轻衬素肌香薄。"]'),
('song-ci-569','失调名','无名氏','宋','宋词','song-ci','失调名','[]','御符争带。',11,'宋词/ci.song.19000.json','["御符争带。", "斜插交枝艾。"]'),
('song-ci-570','失调名','无名氏','宋','宋词','song-ci','失调名','[]','从前浪荡休整理。',31,'宋词/ci.song.19000.json','["从前浪荡休整理。", "钉赤口、防猜忌。", "而今魔难管全无，一似粽儿黏腻。"]'),
('song-ci-571','失调名','无名氏','宋','宋词','song-ci','失调名','[]','天上佳期。',93,'宋词/ci.song.19000.json','["天上佳期。", "九衢灯月交辉。", "摩□孩儿，斗巧争奇。", "戴短檐珠子帽，披小缕金衣。", "嗔眉笑眼，百般地、敛手相宜。", "转晴底、工夫不少，引得人爱后如痴。", "快输钱，须要扑，不问归迟。", "归来猛醒，争如我、活底孩儿。"]'),
('song-ci-572','伊州曲','无名氏','宋','宋词','song-ci','伊州曲','[]','金鸡障下胡雏戏。',146,'宋词/ci.song.19000.json','["金鸡障下胡雏戏。", "乐极祸来，渔阳兵起。", "鸾舆幸蜀，玉环缢死。", "马嵬坡下尘滓。", "夜对行宫皓月，恨最恨、春风桃李。", "洪都方士。", "念君萦系。", "妃子。", "蓬莱殿里。", "觅寻太真，宫中睡起。", "遥谢君意。", "泪流琼脸，梨花带雨，仿佛霓裳初试。", "寄钿合、共金钗，私言徒尔。", "在天愿为、比翼同飞。", "居地应为、连理双枝。", "天长与地久，唯此恨无已。"]'),
('song-ci-573','失调名','无名氏','宋','宋词','song-ci','失调名','[]','月到中秋偏莹。',89,'宋词/ci.song.19000.json','["月到中秋偏莹。", "乍团圆、早欺我孤影。", "穿帘共透幕，来寻趁。", "钩起窗儿，里面故把、灯儿扑烬。", "看尽古今歌咏。", "状玉盘、又拟金饼。", "谁花言巧语、胡厮胫。", "我只道、尔是照人孤眠，恼杀人，旧都名业镜。"]'),
('song-ci-574','失调名','无名氏','宋','宋词','song-ci','失调名','[]','手拈茱萸簪髻，一枝聊记重阳。',14,'宋词/ci.song.19000.json','["手拈茱萸簪髻，一枝聊记重阳。"]'),
('song-ci-575','失调名','无名氏','宋','宋词','song-ci','失调名','[]','插黄花、对尊前，且看茱萸好。',14,'宋词/ci.song.19000.json','["插黄花、对尊前，且看茱萸好。"]'),
('song-ci-576','失调名','无名氏','宋','宋词','song-ci','失调名','[]','明年此□，□知谁健，且尽黄花酒。',16,'宋词/ci.song.19000.json','["明年此□，□知谁健，且尽黄花酒。"]'),
('song-ci-577','倾杯序・倾杯乐','无名氏','宋','宋词','song-ci','倾杯序・倾杯乐','["\u957f\u6c5f"]','昔有王生，冠世文章，尝随旧游江渚。',254,'宋词/ci.song.19000.json','["昔有王生，冠世文章，尝随旧游江渚。", "偶尔停舟寓目，遥望江祠，依依陌上闲步。", "恭诣殿砌，稽首瞻仰，返回归路。", "遇老叟，坐于矶石，貌纯古。", "因语□，子非王勃是致，生惊询之，片饷方悟。", "子有清才，幸对滕王高阁，可作当年词赋。", "汝但上舟，休虑。", "迢迢仗清风去。", "到筵中、下笔华丽，如神助。", "会俊侣。", "面如玉。", "大夫久坐觉生怒。", "报云落霞并飞孤鹜。", "秋水长天，一色澄素。", "阎公竦然，复坐华筵，次诗引序。", "道鸣鸾佩玉，锵锵罢歌舞。", "栋云飞过南浦。", "暮帘卷向西山雨。", "闲云潭影，淡淡悠悠，物换星移，几度寒暑。", "阁中帝子，悄悄垂名，在於何处。", "算长江、俨然自东去。"]'),
('song-ci-578','失调名','无名氏','宋','宋词','song-ci','失调名','[]','奈愁又、愁无避处，愁随一线□长。',16,'宋词/ci.song.19000.json','["奈愁又、愁无避处，愁随一线□长。"]'),
('song-ci-579','失调名','无名氏','宋','宋词','song-ci','失调名','[]','万户与千门，驱傩鼎沸。',11,'宋词/ci.song.19000.json','["万户与千门，驱傩鼎沸。"]'),
('song-ci-580','失调名','无名氏','宋','宋词','song-ci','失调名','[]','兽炭共围，通宵不寐，守尽残更待春至。',18,'宋词/ci.song.19000.json','["兽炭共围，通宵不寐，守尽残更待春至。"]'),
('song-ci-581','蝶恋花','无名氏','宋','宋词','song-ci','蝶恋花','[]','花为年年春易改。',70,'宋词/ci.song.19000.json','["花为年年春易改。", "待放柔条，系取春常在。", "宫样妆成还可爱。", "鬓边斜作拖枝戴。", "每到无情风雨大。", "点检群芳，却是深丛耐。", "摇曳绿罗金缕带。", "丹青传得妖娆态。"]'),
('song-ci-582','如梦令','无名氏','宋','宋词','song-ci','如梦令','[]','今夜荼䕷风起。',40,'宋词/ci.song.19000.json','["今夜荼䕷风起。", "应是玉消琼碎。", "淡荡满城春，恼破愁人春睡。", "须醉。", "须醉。", "莫待梅黄雨细。"]'),
('song-ci-583','最高楼','无名氏','宋','宋词','song-ci','最高楼','[]','司春有序，排次到荼䕷。',103,'宋词/ci.song.19000.json','["司春有序，排次到荼䕷。", "远预报，在庭知。", "蕊珠宫里晨妆罢，披香殿下晓班齐。", "探花正、驱使问，菊花期。", "元不逊、梅花浮月影，也知妒、梨花带雨枝。", "偏恨柳、绿条垂。", "与其向晚包团絮，不如对酒折芳蕤。", "谢东君，收拾在，牡丹时。"]'),
('song-ci-584','南柯子・南歌子','无名氏','宋','宋词','song-ci','南柯子・南歌子','[]','翠袖熏龙脑，乌云映玉台。',62,'宋词/ci.song.19000.json','["翠袖熏龙脑，乌云映玉台。", "春葱一簇荐金杯。", "曾记西楼同醉、角声催。", "袅袅凌波浅，深深步月来。", "隔纱微笑恐郎猜。", "素艳浓香依旧、去年开。"]'),
('song-ci-585','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','青幄高张，琼枝巧缀，万颗香染红殷。',118,'宋词/ci.song.19000.json','["青幄高张，琼枝巧缀，万颗香染红殷。", "绛罗衣润，疑是火然山。", "白玉钗头试篸，黄金带、奇巧工钻。", "题评处，仙家异种，分付在人间。", "年年。", "输帝里，欢呼内监，妆点金盘。", "况曾得真妃，笑脸频看。", "炎岭当时奏曲，风流命、乐府名传。", "凭谁道、移归禁苑，长使近天颜。"]'),
('song-ci-586','浣溪沙','无名氏','宋','宋词','song-ci','浣溪沙','[]','酒拍胭脂颗颗新。',48,'宋词/ci.song.19000.json','["酒拍胭脂颗颗新。", "丹砂然火弃精神。", "暑天秋杪锦生春。", "香味已惊樱实淡，绛皮还笑荔枝皴。", "美人偏喜破朱唇。"]'),
('song-ci-587','南柯子・南歌子','无名氏','宋','宋词','song-ci','南柯子・南歌子','[]','积雪迷松迳，围炉掩竹扉。',62,'宋词/ci.song.19000.json','["积雪迷松迳，围炉掩竹扉。", "床头一味有蹲鸱。", "软火深开香熟、已多时。", "自得陶朱法，休教懒瓒知。", "浪传黄独正甘肥。", "紫玉婴儿盈尺、更新奇。"]'),
('song-ci-588','贺新郎','无名氏','宋','宋词','song-ci','贺新郎','[]','天意扶炎宋。',141,'宋词/ci.song.19000.json','["天意扶炎宋。", "为吾皇、维衡狱孕，长沙星梦。", "社稷勋庸天地窄，不数智名功勇。", "要自有、胸中妙用。", "擎着东南一柱，看边民、买犊归耕种。", "官职易，此身重。", "黄封已见传宣送。", "却春来、洪钧初转，紫枢归拱。", "岁岁玉楼春噀处，慧质明妆环拥。", "正弟劝、兄酬欢纵。", "一寸丹心坚似铁，待磨崖、勒就浯溪颂。", "龙尾道，接天踵。"]'),
('song-ci-589','贺圣朝','无名氏','宋','宋词','song-ci','贺圣朝','[]','太平无事，四边宁静狼烟眇。',106,'宋词/ci.song.19000.json','["太平无事，四边宁静狼烟眇。", "国泰民安，谩说尧舜禹汤好。", "万民翘望彩都门，龙灯凤烛相照。", "只听得教坊杂剧欢笑。", "美人巧。", "宝箓宫前，咒水书符断妖。", "更梦近、竹林深处胜蓬岛。", "笙歌闹。", "奈吾皇，不待元宵景色来到。", "只恐后月，阴晴未保。"]'),
('song-ci-590','踏莎行','无名氏','宋','宋词','song-ci','踏莎行','[]','宴罢琼林，醉游花市，此时方显男儿志。',18,'宋词/ci.song.19000.json','["宴罢琼林，醉游花市，此时方显男儿志。"]'),
('song-ci-591','祝英台近','无名氏','宋','宋词','song-ci','祝英台近','[]','客毡寒，兰房悄，金炉爇红兽。',95,'宋词/ci.song.19000.json','["客毡寒，兰房悄，金炉爇红兽。", "好个霜天，消遣正宜酒。", "嫩橙初截鹅肪，肌肤香透。", "又还记、吴姬纤手。", "事难偶。", "墨冻空染梨笺，新词谩题就。", "酒薄愁浓，敧枕听寒漏。", "可堪霜月亭亭，照人无寐，映窗外、一枝梅瘦。"]'),
('song-ci-592','花心动','无名氏','宋','宋词','song-ci','花心动','[]','碧瓦朱甍，销千门沈沈，丽日初旭。',127,'宋词/ci.song.19000.json','["碧瓦朱甍，销千门沈沈，丽日初旭。", "画栋暗尘，锦瑟空弦，窈窕故窗红绿。", "御柳宫花依然好，春不管、为谁妆束。", "翠华远，风光尽属，野樵夷牧。", "指似行人恸哭。", "尚能道、先朝圣游不足。", "凤辇路荒，龙沼波乾，犹有弃珠遗玉。", "禁廊人静风琴响，只疑是、霓裳遗曲。", "断魂晚，寒鸦又啼古木。"]'),
('song-ci-593','西江月','无名氏','宋','宋词','song-ci','西江月','[]','梁上喃喃燕语，纸间戢戢蚕生。',58,'宋词/ci.song.19000.json','["梁上喃喃燕语，纸间戢戢蚕生。", "满城风雨近清明。", "不道有人新病。", "春事一溪流水，杨花千点浮萍。", "好风一霎为吹晴。", "独步小园清影。"]'),
('song-ci-594','梅花引','无名氏','宋','宋词','song-ci','梅花引','[]','清阴陌。',70,'宋词/ci.song.19000.json','["清阴陌。", "狂踪迹。", "朱门团扇香迎客。", "牡丹风。", "数苞红。", "水香扑蕊，新妆谁为容。", "蜡灯春酒风光夕。", "锦浪龙须花六尺。", "月波寒。", "玉琅玕。", "无情又是，华星送宝鞍。"]'),
('song-ci-595','恋绣衾','无名氏','宋','宋词','song-ci','恋绣衾','[]','元宵三五酒半醺。',68,'宋词/ci.song.19000.json','["元宵三五酒半醺。", "马蹄前、步步是春。", "闹市里、看灯去，喜金吾、不禁夜深。", "如今老大都休也，未黄昏、先闭上门。", "待月到、窗儿上，对梅花、如对故人。"]'),
('song-ci-596','青玉案','无名氏','宋','宋词','song-ci','青玉案','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','年年社日停针线。',80,'宋词/ci.song.19000.json','["年年社日停针线。", "怎忍见、双飞燕。", "今日江城春已半。", "一身犹在，乱山深处，寂寞溪桥畔。", "春衫著破谁针线。", "点点行行泪痕满。", "落日解鞍芳草岸。", "花无人戴，酒无人劝，醉也无人管。"]'),
('song-ci-597','捣练子','无名氏','宋','宋词','song-ci','捣练子','[]','偏□戏，最风流。',32,'宋词/ci.song.19000.json','["偏□戏，最风流。", "斗帐金猊暖不收。", "一阵蜜蜂狂絮里，酒酣眠折玉搔头。"]'),
('song-ci-598','捣练子','无名氏','宋','宋词','song-ci','捣练子','[]','初酒醒，乍衣单。',32,'宋词/ci.song.19000.json','["初酒醒，乍衣单。", "褪著裙儿侧著冠。", "门外小桥寒食夜，月明人去杏花残。"]'),
('song-ci-599','楼心月','无名氏','宋','宋词','song-ci','楼心月','[]','柳下争拿画浆摇。',32,'宋词/ci.song.19000.json','["柳下争拿画浆摇。", "水痕不觉透红绡。", "月明相顾羞归去，都坐池头合凤箫。"]'),
('song-ci-600','楼心月','无名氏','宋','宋词','song-ci','楼心月','[]','手把新荷叶一枝。',32,'宋词/ci.song.19000.json','["手把新荷叶一枝。", "唤来池上只愁归。", "流萤裹在红纱袖，忽到持杯个个飞。"]'),
('song-ci-601','楼心月','无名氏','宋','宋词','song-ci','楼心月','[]','新著生红小舞衣。',32,'宋词/ci.song.19000.json','["新著生红小舞衣。", "案前磨墨误淋漓。", "含嗔逗晚不梳洗，背面牙床吃荔支。"]'),
('song-ci-602','花心动','无名氏','宋','宋词','song-ci','花心动','[]','粉堞云齐，度清笳、愁入暮烟林杪。',127,'宋词/ci.song.19000.json','["粉堞云齐，度清笳、愁入暮烟林杪。", "素艳透春，玉骨凄凉，勾带月痕生早。", "江天苍莽黄昏后，依然是、粉寒香瘦。", "动追感、西园嫩约，夜深人悄。", "记得东风窈窕。", "曾夜踏横斜，醉携娇小。", "惆怅旧欢，回首俱非，忍看绿笺红豆。", "香销纸帐人孤寝，相思恨、花还知否。", "梦回处，霜飞翠楼已晓。"]'),
('song-ci-603','踏莎行','无名氏','宋','宋词','song-ci','踏莎行','[]','殢酒情怀，恨春时节。',68,'宋词/ci.song.19000.json','["殢酒情怀，恨春时节。", "柳丝巷陌黄昏月。", "把君团扇卜君来，近墙扑得双蝴蝶。", "笑不成言，喜还生怯。", "颠狂绝似前春雪。", "夜寒无处著相思，梨花一树人如削。"]'),
('song-ci-604','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','题得相思字数行。',64,'宋词/ci.song.19000.json','["题得相思字数行。", "起来桐叶满纱窗。", "秋光欲雨棋声泻，粉帐不容花露香。", "新寂寞，旧疏狂。", "玉炉消息记钱塘。", "小阑立遍红蕉树，一带残云趁月黄。"]'),
('song-ci-605','阮郎归','无名氏','宋','宋词','song-ci','阮郎归','[]','薄罗生色画酴醿。',56,'宋词/ci.song.19000.json','["薄罗生色画酴醿。", "酴醿满架时。", "隔池贪看燕争泥。", "坠双红荔支。", "销金字，晚唐诗。", "夹纱团扇儿。", "自遮微雨傍花归。", "个情天得知。"]'),
('song-ci-606','青门怨','无名氏','宋','宋词','song-ci','青门怨','[]','月痮烟景。',65,'宋词/ci.song.19000.json','["月痮烟景。", "远思孤影。", "旧梦云飞，离魂冰冷。", "脉脉恨满东风。", "对孤鸿。", "翠珠尘冷香如雾。", "人何许。", "心逐章台絮。", "夜深酒醒烛暗，独倚危楼。", "为谁愁。"]'),
('song-ci-607','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','不能烦恼得，掉臂便归休。',114,'宋词/ci.song.19000.json','["不能烦恼得，掉臂便归休。", "前度风樯，这回潦辙几悠悠。", "幸得有云一谷，更自有书万卷，著甚麽来由。", "月采混鱼目，霜口涴蝇头。", "相山中，侯醉境，将诗流。", "情知薄命，天样勋业也须收。", "辟逻世间万事，推放那边一壁，百尺卧高楼。", "日月草头露，天地水中沤。"]'),
('song-ci-608','失调名','无名氏','宋','宋词','song-ci','失调名','[]','东南妩媚，雌了男儿。',10,'宋词/ci.song.19000.json','["东南妩媚，雌了男儿。"]'),
('song-ci-609','霜天晓角','无名氏','宋','宋词','song-ci','霜天晓角','[]','一声阿鹊。',54,'宋词/ci.song.19000.json','["一声阿鹊。", "人在云西角。", "信有黄昏风雨，孤灯酒、不禁酌。", "错错。", "谁误著。", "明知明做却。", "颇寄香笺归去，教看了、细揉嚼。"]'),
('song-ci-610','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','凤阁祥烟，龙城佳气，明禋恭谢时丰。',118,'宋词/ci.song.19000.json','["凤阁祥烟，龙城佳气，明禋恭谢时丰。", "绮罗争看，帘幕卷南风。", "十里仙仪宝仗，暖红翠、玉碾玲珑。", "銮回也，箫韶缓奏，声在五云中。", "千官，迎万乘，丝纶叠叠，锦绣重重。", "听鸣矟辇路，宴罢鳌宫。", "瞻仰天颜有喜，君恩霈、寰宇雍容。", "生平愿，洪基巩固，圣寿永无穷。"]'),
('song-ci-611','庆清朝','无名氏','宋','宋词','song-ci','庆清朝','[]','银漏花残，红消烛泪。',105,'宋词/ci.song.19000.json','["银漏花残，红消烛泪。", "九重鱼钥欢声沸。", "奏万乘、祥曦门外。", "盖圣君、恭谢灵休，谨访景明嘉礼。", "天意好，祥风瑞月，时正当、小春天气。", "禁街十里香中，御辇万红影里。", "千官花底，控绣勒、宝鞭摇曳。", "看万年，永庆吾皇，拈指又瞻三载。"]'),
('song-ci-612','御街行','无名氏','宋','宋词','song-ci','御街行','[]','时康三载升平世。',85,'宋词/ci.song.19000.json','["时康三载升平世。", "恭谢三朝礼。", "群臣禁卫带花回，龊巷儿郎精锐。", "战袍新样团雕拥，重隘围子队。", "绣衣花帽挨排砌。", "锦仗天街里。", "有如仙队玉京来，妙乐钧天盈耳。", "都民观望时，果是消灾灭罪。"]'),
('song-ci-613','瑞鹤仙','无名氏','宋','宋词','song-ci','瑞鹤仙','[]','是欢声盈万户。',124,'宋词/ci.song.19000.json','["是欢声盈万户。", "庆景陵礼毕，銮舆游步。", "西郊暖风布。", "喜湖山深锁，非烟非雾。", "传收绣羽。", "骅骝驰骤绒缕。", "望彤芳、稳稳金銮，衮鸾翔舞。", "云驭。", "近回天厩，锡宴琼津，洪恩均顾。", "霞天向暮。", "翠华动，舞韶举。", "绛纱笼千点，星飞清禁，银烛交辉辇路。", "瑞光中、渺祝无疆，太平圣主。"]'),
('song-ci-614','真珠帘','无名氏','宋','宋词','song-ci','真珠帘','[]','病酒情怀犹困懒。',8,'宋词/ci.song.19000.json','["病酒情怀犹困懒。"]'),
('song-ci-615','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','国步多艰，民心靡定，诚吾隐忧。',138,'宋词/ci.song.19000.json','["国步多艰，民心靡定，诚吾隐忧。", "叹浙民转徙，怨寒嗟暑，荆襄死守，阅岁经秋。", "虏未易支，人将相食，识者深为社稷羞。", "当今亟，出陈大谏，箸借留候。", "□□迂阔为谋。", "天下士如何可籍收。", "况君能尧舜，臣皆稷契，世逢汤武，业比伊周。", "政不必新，贯仍宜旧，莫与秀才做尽休。", "吾元老，广四门贤路，一柱中流。"]'),
('song-ci-616','小重山','无名氏','宋','宋词','song-ci','小重山','[]','鼓报黄昏禽影歇。',70,'宋词/ci.song.19000.json','["鼓报黄昏禽影歇。", "单衣犹未试，觉寒怯。", "尘生锦瑟可曾阅。", "人去也，闲过好时节。", "对景复愁绝。", "东风吹不散，鬓边雪。", "些儿心事对谁说。", "眠不得，一枕杏花月。"]'),
('song-ci-617','谒金门','无名氏','宋','宋词','song-ci','谒金门','[]','休只坐。',53,'宋词/ci.song.19000.json','["休只坐。", "也去看花则个。", "明日满庭红欲堕。", "花还愁似我。", "索性痴眠一和。", "凭个梦儿好做。", "杜宇不知春已过。", "枝头声越大。"]'),
('song-ci-618','失调名','无名氏','宋','宋词','song-ci','失调名','[]','惜花心性。',5,'宋词/ci.song.19000.json','["惜花心性。"]'),
('song-ci-619','行香子','无名氏','宋','宋词','song-ci','行香子','[]','浙右华亭。',85,'宋词/ci.song.19000.json','["浙右华亭。", "物价廉平。", "一道会、卖个三升。", "打开瓶后，滑辣光馨。", "教君霎时饮，霎时醉，霎时醒。", "听得渊明。", "说与刘伶。", "这一瓶、约迭三斤。", "君还不信，把秤来秤。", "有一斤酒，一斤水，一斤瓶。"]'),
('song-ci-620','长相思','无名氏','宋','宋词','song-ci','长相思','[]','晴也行。',44,'宋词/ci.song.19000.json','["晴也行。", "雨也行。", "雨也行时不似晴。", "天晴终快人。", "名也成。", "利也成。", "利也成时不似名。", "名成天下惊。"]'),
('song-ci-621','摸鱼儿','无名氏','宋','宋词','song-ci','摸鱼儿','[]','过湘皋、碧龙惊起，冰涎犹护髯影。',140,'宋词/ci.song.19000.json','["过湘皋、碧龙惊起，冰涎犹护髯影。", "春洲未有菱歌伴，独占暮烟千顷。", "呼短艇。", "试翦取纤条，玉溜青丝莹。", "尊前细认。", "试水面新荷，波心半掩，点点翠钿净。", "凄凉味，酪乳那堪比并。", "吴盐一箸秋冷。", "当时不为鲈鱼去，聊尔动渠归兴。", "还记省。", "是几度西风，几度吹愁醒。", "鸥昏鹭瞑。", "谩换得霜痕，萧萧两鬓，羞与共秋镜。"]'),
('song-ci-622','失调名','无名氏','宋','宋词','song-ci','失调名','[]','东君去后花无主。',8,'宋词/ci.song.19000.json','["东君去后花无主。"]'),
('song-ci-623','多丽','无名氏','宋','宋词','song-ci','多丽','[]','日初长，宝炉一缕沈烟。',175,'宋词/ci.song.19000.json','["日初长，宝炉一缕沈烟。", "绿阴新，垂杨亭榭，知谁巧擘香绵。", "有时共、落红零乱，有时共、芳草留连。", "只道无情，那知有意，几回飞过绮窗前。", "人争讶，艳阳三月，乾雪舞晴天。", "游丝外，不堪燕掠，无奈蜂黏。", "那小鬟、忒�山苛樱�镇日地、倚阑干。", "轻吹处、樱桃的的，闲拈处、笋指纤纤。", "爱点猩罗，装成粉缬，嗔人不许放朱帘。", "端相好、蓦然风起，特送上秋千。", "明朝看，池塘雨过，萍翠应添。"]'),
('song-ci-624','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','我善观梅，识梅妙处，舍我其谁。',139,'宋词/ci.song.19000.json','["我善观梅，识梅妙处，舍我其谁。", "待裁冰翦雪，已无足道，凝酥弄粉，愈不为奇。", "枉费心神，巡檐索笑，点检南枝并北枝。", "梅应道，似这般题品，未是相知。", "分明有个端倪。", "遮莫把人间凡眼窥。", "那精神全在，半含蕊处，风流全在，未有香时。", "万木丛边，两三点白，此是生生化化机。", "花开也，又怎生消得，个样词儿。"]'),
('song-ci-625','壶中天・念奴娇','无名氏','宋','宋词','song-ci','壶中天・念奴娇','[]','日长晴昼。',120,'宋词/ci.song.19000.json','["日长晴昼。", "厌厌地、懒向窗前絣绣。", "因倚屏风无意绪，□把眉儿双皱。", "似醉还醒，才眠又起，频拈梨花嗅。", "看他儿女，闲寻百草来斗。", "相思能几何时，料归期不到，清和时候。", "生怕鸳鸯香被冷，旋爇沈檀薰透。", "欲把单衣，鼎新裁翦，又怕供春瘦。", "试看今夜，孤灯还有花否。"]'),
('song-ci-626','满江红','无名氏','宋','宋词','song-ci','满江红','[]','一点阳和，天不许、凡花先得。',114,'宋词/ci.song.19000.json','["一点阳和，天不许、凡花先得。", "这些儿深意，蜂蝶怎生窥测。", "北陆正当风凛冽，南枝却漏春消息。", "教琼仙、翦水缀成葩，天然白。", "影横处，寒窗月。", "香浮处，寒梢雪。", "被东皇做就，这般标格。", "虽是腊前年后景，终非竹外篱边物。", "不安排、顿放玉堂中，真堪惜。"]'),
('song-ci-627','买坡塘・摸鱼儿','无名氏','宋','宋词','song-ci','买坡塘・摸鱼儿','[]','喜西风、朝来如约，新凉一雨初霁。',140,'宋词/ci.song.19000.json','["喜西风、朝来如约，新凉一雨初霁。", "家山望断知何处，渺渺长天秋水。", "空眼底。", "叹雁杳鱼沈，尺纸无人寄。", "芸窗草砌。", "渐影颤疏桐，声敲落叶，孤枕怎成睡。", "逢场戏。", "遮莫悲秋憔悴。", "今朝有酒须醉。", "尊前待唤佳人道，为雪藕丝轻脆。", "闲省记。", "便笑口频开，一岁知能几。", "归期尚未。", "且蜡屐兰桡，湖山深处，同赏月中桂。"]'),
('song-ci-628','瑞鹤仙','无名氏','宋','宋词','song-ci','瑞鹤仙','[]','赏残陶径菊。',127,'宋词/ci.song.19000.json','["赏残陶径菊。", "正袅袅愁予，风凄露肃。", "何人抱幽独。", "更檐马锵金，廊鱼响木。", "此情谁属。", "向底处、骋怀游目。", "小窗前，频览菱花，一笑鬓丝犹绿。", "萧索。", "故国云迷，佳人日暮，轻颦倚竹。", "短钗敲玉。", "算几夜，恁孤宿。", "问旅情如许，怎生排遣，应费酒尊诗轴。", "最无端、谁隔西楼，正调弦促。"]'),
('song-ci-629','更漏子','无名氏','宋','宋词','song-ci','更漏子','[]','画楼深，春昼永。',58,'宋词/ci.song.19000.json','["画楼深，春昼永。", "帘幕东风微冷。", "莺啭罢，燕归来。", "佳人午梦回。", "鬓钗横，眉黛浅。", "一捻楚腰纤软。", "推绣户，倚雕阑。", "无言看牡丹。"]'),
('song-ci-630','更漏子','无名氏','宋','宋词','song-ci','更漏子','[]','鬓慵梳，眉懒画。',58,'宋词/ci.song.19000.json','["鬓慵梳，眉懒画。", "独自行来花下。", "情脉脉，泪垂垂。", "此情知为谁。", "雨初晴，帘半卷。", "两两衔泥新燕。", "人比燕，不成双。", "枉教人断肠。"]'),
('song-ci-631','更漏子','无名氏','宋','宋词','song-ci','更漏子','[]','粉墙低，蓬户小。',58,'宋词/ci.song.19000.json','["粉墙低，蓬户小。", "一点尘运不到。", "眠纱帐，坐蒲团。", "道人随分安。", "笋芽新，蔬甲嫩。", "日日家常羹饭。", "羹饭罢，怎消闲。", "携筇出看山。"]'),
('song-ci-632','愁倚阑令・春光好','无名氏','宋','宋词','song-ci','愁倚阑令・春光好','[]','东风恶，宿云凝。',52,'宋词/ci.song.19000.json','["东风恶，宿云凝。", "忒无情。", "合造梨花深院雨，断肠声。", "枕上春梦初醒。", "红窗外、何处啼莺。", "已办春游双画舫，几时晴。"]'),
('song-ci-633','红窗迥','无名氏','宋','宋词','song-ci','红窗迥','[]','河可挽。',64,'宋词/ci.song.19000.json','["河可挽。", "石可转。", "那一个愁字，却难驱遣。", "眉向酒边暂展。", "酒后依旧见。", "枫叶满阶红万片。", "待拾来、一一题写教遍。", "却倩霜风吹卷。", "直到沙岛远。"]'),
('song-ci-634','一翦梅','无名氏','宋','宋词','song-ci','一翦梅','[]','漠漠春阴酒半酣。',72,'宋词/ci.song.19000.json','["漠漠春阴酒半酣。", "风透春衫。", "雨透春衫。", "人家蚕事欲眠三。", "桑满筐篮。", "柘满筐篮。", "先自离怀百不堪。", "樯燕呢喃。", "梁燕呢喃。", "篝灯强把锦书看。", "人在江南。", "心在江南。"]'),
('song-ci-635','长相思','无名氏','宋','宋词','song-ci','长相思','[]','不思量。',44,'宋词/ci.song.19000.json','["不思量。", "又思量。", "一点寒灯耿夜光。", "鸳衾闲半床。", "雨声长。", "漏声长。", "几阵斜风摇纸窗。", "如何不断肠。"]'),
('song-ci-636','长相思','无名氏','宋','宋词','song-ci','长相思','[]','云垂垂。',44,'宋词/ci.song.19000.json','["云垂垂。", "雨霏霏。", "只恐今年花事迟。", "不然孤负伊。", "燕飞飞。", "柳依依。", "有个人人倚翠扉。", "深攒双黛眉。"]'),
('song-ci-637','长相思','无名氏','宋','宋词','song-ci','长相思','[]','雨如丝。',44,'宋词/ci.song.19000.json','["雨如丝。", "柳如丝。", "织出春来一段奇。", "莺梭来往飞。", "酒如池。", "醉如泥。", "遮莫教人有醒时。", "雨晴都不知。"]'),
('song-ci-638','长相思','无名氏','宋','宋词','song-ci','长相思','[]','燕成双。',44,'宋词/ci.song.19000.json','["燕成双。", "蝶成双。", "飞去飞来杨柳旁。", "问伊因底忙。", "绿纱窗。", "篆炉香。", "午梦惊回书满床。", "棋声春昼长。"]'),
('song-ci-639','采桑子','无名氏','宋','宋词','song-ci','采桑子','[]','年年才到花时候，风雨成旬。',52,'宋词/ci.song.19000.json','["年年才到花时候，风雨成旬。", "不肯开晴。", "误却寻花陌上人。", "今朝报道天晴也，花已成尘。", "寄语花神。", "何似当初莫做春。"]'),
('song-ci-640','风光好','无名氏','宋','宋词','song-ci','风光好','[]','柳阴阴。',44,'宋词/ci.song.19000.json','["柳阴阴。", "水深深。", "风约双凫不自禁。", "碧波心。", "孤村桥断人迷路。", "舟横渡。", "旋买村醪浅浅斟。", "更微吟。"]'),
('song-ci-641','虞美人','无名氏','宋','宋词','song-ci','虞美人','[]','□□□□□□□。',66,'宋词/ci.song.19000.json','["□□□□□□□。", "□□□□□。", "□□□□□□□。", "□□□□□□、□□□。", "□□□□□□处。", "归向桃源住。", "桃源有路透渔溪。", "自恨仙凡从此、隔云泥。"]'),
('song-ci-642','虞美人','无名氏','宋','宋词','song-ci','虞美人','[]','绮疏人把罗衣叠。',66,'宋词/ci.song.19000.json','["绮疏人把罗衣叠。", "岫幌铺残月。", "宝烟细袅博山中。", "梦惹暖红鸳锦、醉香风。", "觉来犹记乘鸾处。", "不是蓝桥住。", "落花流水认前溪。", "想见五云为路、静无泥。"]'),
('song-ci-643','虞美人','无名氏','宋','宋词','song-ci','虞美人','[]','悲商吹尽枝间绿。',66,'宋词/ci.song.19000.json','["悲商吹尽枝间绿。", "绛萼含冰玉。", "为谁搀早冒寒开。", "应念天涯憔悴、挽春回。", "玉壶自酌清漪满。", "又识东风面。", "夜深斜月印窗纱。", "好在数枝疏瘦、两三花。"]'),
('song-ci-644','虞美人','无名氏','宋','宋词','song-ci','虞美人','[]','萧萧风竹千蛟舞。',66,'宋词/ci.song.19000.json','["萧萧风竹千蛟舞。", "云阁催诗雨。", "中秋时节变新凉。", "又是一番红叶、下三湘。", "君如膝上王文度。", "早晚乡关去。", "绣香佳处且留连。", "正好橙黄橘绿、未寒天。"]'),
('song-ci-645','虞美人','无名氏','宋','宋词','song-ci','虞美人','[]','当年合德并飞燕。',66,'宋词/ci.song.19000.json','["当年合德并飞燕。", "涎涎无人见。", "清魂沦入海棠枝。", "料想天寒同著、翠罗衣。", "同心佩带连环玉。", "并髻云鬟绿。", "谁教红萼自成双。", "恰似新荷叶里、睡鸳鸯。"]'),
('song-ci-646','木兰花・玉楼春','无名氏','宋','宋词','song-ci','木兰花・玉楼春','[]','小桃枝上东风转。',64,'宋词/ci.song.19000.json','["小桃枝上东风转。", "□□草绿江南岸。", "绿杨学舞小蛮腰，红药惜开菩萨面。", "故乡何处天涯远。", "黄梁梦断行云断。", "登楼准拟故人书，殷勤试问西归雁。"]'),
('song-ci-647','朝中措','无名氏','宋','宋词','song-ci','朝中措','[]','严霜封草树凋红。',57,'宋词/ci.song.19000.json','["严霜封草树凋红。", "叶落小园空。", "何事洛阳花面，却来冠冕秋风。", "尊前羞损，篱边野菊，池上芙蓉。", "莫放花归崑阆，且留客醉金锺。"]'),
('song-ci-648','朝中措','无名氏','宋','宋词','song-ci','朝中措','[]','红鸾飞下绿云中。',57,'宋词/ci.song.19000.json','["红鸾飞下绿云中。", "天淡日和融。", "回首小园桃杏，怜伊独困霜风。", "妖姿丽质，天然富贵，不假铅红。", "梦作一双蝴蝶，翻翻绕遍芳丛。"]'),
('song-ci-649','朝中措','无名氏','宋','宋词','song-ci','朝中措','[]','洛阳常见画图中。',57,'宋词/ci.song.19000.json','["洛阳常见画图中。", "春去只心融。", "国色辉开寒日，天香熏破霜风。", "平生看了，姚黄魏紫，一捻深红。", "莫是神仙韩令，裁成顷刻花丛。"]'),
('song-ci-650','朝中措','无名氏','宋','宋词','song-ci','朝中措','[]','从来黄菊占秋风。',57,'宋词/ci.song.19000.json','["从来黄菊占秋风。", "红只许芙蓉。", "正是百花浓睡，如何唤起春工。", "小桃破萼，胭脂淡伫，妆粉轻笼。", "为报多情刘阮，武陵消息先通。"]'),
('song-ci-651','朝中措','无名氏','宋','宋词','song-ci','朝中措','[]','宦游只欲赋归休。',57,'宋词/ci.song.19000.json','["宦游只欲赋归休。", "花为解离愁。", "看取星星潘鬓，花应羞上人头。", "武陵流水，桃源路远，空误渔舟。", "把住春光一醉，从教风叶悲秋。"]'),
('song-ci-652','西江月','无名氏','宋','宋词','song-ci','西江月','[]','草市人归日落，荒城风急鸦翻。',58,'宋词/ci.song.19000.json','["草市人归日落，荒城风急鸦翻。", "独携尊酒上高寒。", "缥缈云横楚观。", "柳外半篙绿水，烟中数笔青山。", "天涯流落岁将残。", "望断故园心眼。"]'),
('song-ci-653','西江月','无名氏','宋','宋词','song-ci','西江月','[]','扑扑云垂四野。',58,'宋词/ci.song.19000.json','["扑扑云垂四野。", "冥冥雁下平芜。", "萧萧风叶乱黄芦。", "寒入一滩鸥鹭。", "准拟云窗水榭。", "装成玉树冰壶。", "卷帘独坐拈髭须。", "待看六花飞舞。"]'),
('song-ci-654','西江月','无名氏','宋','宋词','song-ci','西江月','[]','风雨朝来恶甚，池塘春去无多。',58,'宋词/ci.song.19000.json','["风雨朝来恶甚，池塘春去无多。", "绿杨阴里溜莺棱。", "枝上老红犹堕。", "酒满蚁浮金匜，烛残泪滴铜荷。", "更阑孤枕奈情何。", "只恐巫山梦破。"]'),
('song-ci-655','西江月','无名氏','宋','宋词','song-ci','西江月','[]','花下春光正好，柳边春色才多。',58,'宋词/ci.song.19000.json','["花下春光正好，柳边春色才多。", "雨声日夜长沧波。", "暗地芳心滴破。", "拍拍浪飞白雪，冥冥山点青螺。", "汀兰岸芷有情麽。", "还惜江城春过。"]'),
('song-ci-656','西江月','无名氏','宋','宋词','song-ci','西江月','[]','膝下红金不暖，窗前绛蜡犹然。',58,'宋词/ci.song.19000.json','["膝下红金不暖，窗前绛蜡犹然。", "夜深城麓走风烟。", "的砾还飘雪霰。", "海上正迷蝶梦，山阴未棹溪船。", "愿骑白凤玉为鞭。", "西赴瑶池芳宴。"]'),
('song-ci-657','西江月','无名氏','宋','宋词','song-ci','西江月','[]','琼沼融成沆瀣，冰檐滴尽真珠。',58,'宋词/ci.song.19000.json','["琼沼融成沆瀣，冰檐滴尽真珠。", "一园草木气方苏。", "又学杨花飞舞。", "何必乱飘密洒，却疑细糁轻铺。", "谁将粉墨画成图。", "玉做小亭高树。"]'),
('song-ci-658','西江月','无名氏','宋','宋词','song-ci','西江月','[]','翦翦轻寒雨后，瞳瞳晓日晴时。',58,'宋词/ci.song.19000.json','["翦翦轻寒雨后，瞳瞳晓日晴时。", "春风先到绿杨枝。", "金缕野桥山市。", "鶗鴂巧调琴筑，海棠惜吐胭脂。", "玉骢未解锦障泥。", "且挂征鞭一醉。"]'),
('song-ci-659','西江月','无名氏','宋','宋词','song-ci','西江月','[]','翠岭游仙梦破，暖香残酒醒时。',58,'宋词/ci.song.19000.json','["翠岭游仙梦破，暖香残酒醒时。", "子规啼月下花枝。", "日涌山光照市。", "柳拂眉间黛色，桃匀脸上胭脂。", "凄凄芳草路无泥。", "脉脉归心似醉。"]'),
('song-ci-660','西江月','无名氏','宋','宋词','song-ci','西江月','[]','风雨馀寒过了，池塘春水生时。',58,'宋词/ci.song.19000.json','["风雨馀寒过了，池塘春水生时。", "迁莺飞上拂云枝。", "春遍柳村花市。", "酒面清空似水，玉杯温莹如脂。", "莫教花谢涴尘泥。", "把住东君索醉。"]'),
('song-ci-661','点绛唇','无名氏','宋','宋词','song-ci','点绛唇','[]','晓翠初分，挂藤窈窕穿深静。',50,'宋词/ci.song.19000.json','["晓翠初分，挂藤窈窕穿深静。", "乌啼风径。", "竹舞千蛟影。", "又过重阳，感叹伤流景。", "人多病。", "酒杯慵问。", "闲却金卮柄。"]'),
('song-ci-662','好事近','无名氏','宋','宋词','song-ci','好事近','[]','篱落晓来霜，花嫩不禁寒力。',53,'宋词/ci.song.19000.json','["篱落晓来霜，花嫩不禁寒力。", "脉脉自摇疏影，印一奁空碧。", "天生潇洒谢夫人，绝世有谁识。", "何必嫣然一笑，已倾城倾国。"]'),
('song-ci-663','秦楼月・忆秦娥','无名氏','宋','宋词','song-ci','秦楼月・忆秦娥','[]','□□□。',56,'宋词/ci.song.19000.json','["□□□。", "□□□□□□□。", "□□□。", "□□□□，□□□□。", "白鸥飞下屏山曲。", "行人点破秋郊绿。", "秋郊绿。", "细看重咏，怎生得足。"]'),
('song-ci-664','秦楼月・忆秦娥','无名氏','宋','宋词','song-ci','秦楼月・忆秦娥','[]','秋漠漠。',56,'宋词/ci.song.19000.json','["秋漠漠。", "登临常羡东飞鹤。", "东飞鹤。", "一襟乡泪，为君双落。", "明年不负黄花约。", "故人须我归舟泊。", "归舟泊。", "荆溪亭下，晚秋寒薄。"]'),
('song-ci-665','秦楼月・忆秦娥','无名氏','宋','宋词','song-ci','秦楼月・忆秦娥','[]','风淅淅。',56,'宋词/ci.song.19000.json','["风淅淅。", "天容暗淡梅花白。", "梅花白。", "点酥凝粉，比君不得。", "清歌飞下龙沙雪。", "绮疏休印蟾宫月。", "蟾宫月。", "婵娟虽好，有时圆缺。"]'),
('song-ci-666','西地锦','无名氏','宋','宋词','song-ci','西地锦','[]','重过黄梁古驿。',56,'宋词/ci.song.19000.json','["重过黄梁古驿。", "著一鞭春色。", "长亭细柳，青青尚浅，不禁攀折。", "且醉章台风月。", "莫归鞍催发。", "紫泥诏下，朝天去了，如何来得。"]'),
('song-ci-667','如梦令','无名氏','宋','宋词','song-ci','如梦令','[]','试问春归何处。',40,'宋词/ci.song.19000.json','["试问春归何处。", "红入小桃花树。", "同访古章台，把盏重听金缕。", "休去。", "休去。", "应被好山留住。"]'),
('song-ci-668','清平乐','无名氏','宋','宋词','song-ci','清平乐','[]','风不定。',54,'宋词/ci.song.19000.json','["风不定。", "舞碎海棠红影。", "数点雨声池上听。", "湿尽一庭花冷。", "倚阑多少心情。", "轻寒未放春晴。", "谁管天涯憔悴，楚乡又过清明。"]'),
('song-ci-669','浣溪沙','无名氏','宋','宋词','song-ci','浣溪沙','[]','遍地轻阴绿满枝。',48,'宋词/ci.song.19000.json','["遍地轻阴绿满枝。", "乍晴初试袷罗衣。", "东风院落日长时。", "鸂鶒池边飞燕子，海棠花里闹蜂儿。", "一春心事只春知。"]'),
('song-ci-670','望江南・忆江南','无名氏','宋','宋词','song-ci','望江南・忆江南','[]','清夜老，流水淡疏星。',64,'宋词/ci.song.19000.json','["清夜老，流水淡疏星。", "云母窗前生晓色，梧桐叶上得秋声。", "村落一鸡鸣。", "催唤起，带梦著冠缨。", "老去悲秋如宋玉，病来止酒似渊明。", "满院竹风清。"]'),
('song-ci-671','醉蓬莱','无名氏','宋','宋词','song-ci','醉蓬莱','[]','见笋成新竹，燕教雏飞，画堂清昼。',120,'宋词/ci.song.19000.json','["见笋成新竹，燕教雏飞，画堂清昼。", "萱草榴花，遍小庭如绣。", "角簟纱厨，葛巾葵扇，正麦秋时候。", "玉尘生风，け然隐几，香蟠金兽。", "又值生初，故乡何在，三楚云高，谩劳回首。", "睡起情怀，况渊明止酒。", "赖有宾朋，惠来相顾，尽一时英秀。", "旋涤瑶觞，重歌金缕，与公同寿。"]'),
('song-ci-672','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','梅子成阴，海棠初谢，小园才过清明。',118,'宋词/ci.song.19000.json','["梅子成阴，海棠初谢，小园才过清明。", "百花扫地，红紫践为尘。", "别有烟红露绿，嫣然笑、管领东君。", "还知否，天香国色，独步殿馀春。", "轻盈。", "多态度，洛阳图画，韩令经营。", "想谪仙风韵，洒面词成。", "一捻深红尚透，谁信道、花亦通灵。", "君休待、花归阆苑，莫惜醉山倾。"]'),
('song-ci-673','汉宫春','无名氏','宋','宋词','song-ci','汉宫春','[]','争似我，随时临风对月，畅饮更高歌。',17,'宋词/ci.song.19000.json','["争似我，随时临风对月，畅饮更高歌。"]'),
('song-ci-674','瑞鹤仙','无名氏','宋','宋词','song-ci','瑞鹤仙','[]','恨佳人命薄。',17,'宋词/ci.song.19000.json','["恨佳人命薄。", "似春云无定，杨花飘泊。"]'),
('song-ci-675','失调名','无名氏','宋','宋词','song-ci','失调名','[]','须信道、颜色如花，命如秋叶。',14,'宋词/ci.song.19000.json','["须信道、颜色如花，命如秋叶。"]'),
('song-ci-676','失调名','无名氏','宋','宋词','song-ci','失调名','[]','但入新年，愿百事、皆如意。',13,'宋词/ci.song.19000.json','["但入新年，愿百事、皆如意。"]'),
