('song-ci-888','卜算子','无名氏','宋','宋词','song-ci','卜算子','[]','借问陇头梅，春信还知否。',12,'宋词/ci.song.19000.json','["借问陇头梅，春信还知否。"]'),
('song-ci-889','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','光景如梭。',5,'宋词/ci.song.19000.json','["光景如梭。"]'),
('song-ci-890','失调名','无名氏','宋','宋词','song-ci','失调名','[]','酒入柔肠似泪流。',8,'宋词/ci.song.19000.json','["酒入柔肠似泪流。"]'),
('song-ci-891','导引','无名氏','宋','宋词','song-ci','导引','[]','民康俗阜，万国乐升平。',118,'宋词/ci.song.19000.json','["民康俗阜，万国乐升平。", "庆海晏河清。", "唐尧禹舜垂衣化，讵比我皇明。", "九天宝命垂丕贶，云物效祥英。", "星罗羽卫登乔岳，亲告禅云亭。", "我皇垂拱，惠化洽文明。", "盛礼庆重行。", "登封降禅燔柴毕，天仗入神京。", "云雷布泽遍寰瀛。", "遐迩振欢声。", "巍巍圣寿南山固，千载贺承平。"]'),
('song-ci-892','六州','无名氏','宋','宋词','song-ci','六州','[]','良夜永，玉漏正迟迟。',161,'宋词/ci.song.19000.json','["良夜永，玉漏正迟迟。", "丹禁肃，周庐列，羽卫绕皇闱。", "严鼓动，画角声齐。", "金管飘雅韵，远逐轻飔。", "荐嘉玉、躬祀神祗。", "祈福为黔黎。", "升中盛礼，增高益厚，登封检玉，时迈合周诗。", "玄文锡，庆云五色相随。", "甘露降，醴泉涌，三秀发灵芝。", "皇犹播、史册光辉。", "受鸿禧。", "万年永固丕基。", "吾君德、荡荡巍巍。", "迈尧舜文思。", "从今寰宇，休牛归马，耕田凿井，鼓腹乐昌期。"]'),
('song-ci-893','十二时・忆少年','无名氏','宋','宋词','song-ci','十二时・忆少年','[]','圣明代，海县澄清。',155,'宋词/ci.song.19000.json','["圣明代，海县澄清。", "惠化洽寰瀛。", "时康岁足，治定功成。", "遐迩贺升平。", "嘉坛上，昭事神灵。", "荐明诚。", "报本禅云亭。", "俎豆列牺牲。", "宸心蠲洁，明德荐惟馨。", "纪鸿名。", "千载播天声。", "燔柴毕，云罕回仙仗，庆鸾辂还京。", "八神扈跸，四隩来庭。", "嘉气覆重城。", "殊常礼，旷古难行。", "遇文明。", "仁恩苏品汇，沛泽被簪缨。", "祥符锡祚，武库永销兵。", "育群生。", "景运保千龄。"]'),
('song-ci-894','导引','无名氏','宋','宋词','song-ci','导引','[]','明明我后，至德合高穹。',59,'宋词/ci.song.19000.json','["明明我后，至德合高穹。", "祗翼励精衷。", "上真紫殿回飚驭，示圣胄延鸿。", "躬承宝训表钦崇。", "庆泽布寰中。", "告虔备物朝清庙，荷景福来同。"]'),
('song-ci-895','导引','无名氏','宋','宋词','song-ci','导引','[]','穹旻锡祐，盛德日章明。',118,'宋词/ci.song.19000.json','["穹旻锡祐，盛德日章明。", "见地平天成。", "垂衣恭己干戈偃，亿载祐黎甿。", "羽旄饰驾当春候，款谒届殊庭。", "精衷昭感膺多福，夷夏保咸宁。", "圣君御宇，祗翼奉三灵。", "已偃革休兵。", "区中海外鸿禧浃，恭馆励虔诚。", "九斿七萃著声明。", "徯后徇舆情。", "丕图宝绪承繁祉，率土仰隆平。"]'),
('song-ci-896','六州','无名氏','宋','宋词','song-ci','六州','[]','千载运，宝业正遐昌。',161,'宋词/ci.song.19000.json','["千载运，宝业正遐昌。", "钦至道，崇明祀，盛礼迈前王。", "銮辂动，万骑腾骧。", "驰道纷彩仗，瑞日煌煌。", "奉秘检、玉羽群翔。", "非雾满康庄。", "躬朝真馆，齐心绎思，顺风俯拜，奠酒爇萧芗。", "精衷达，飚轮降格昭彰。", "回羽旆，驻雕辇，旧地访睢阳。", "亭清庙、孝德辉光。", "届灵场。", "星罗万国珪璋。", "陈牲币、金石锵洋。", "景福降穰穰。", "垂衣法坐，恩覃群品，庆均海宇，圣寿保无疆。"]'),
('song-ci-897','十二时・忆少年','无名氏','宋','宋词','song-ci','十二时・忆少年','[]','乾坤泰，帝祚遐昌。',155,'宋词/ci.song.19000.json','["乾坤泰，帝祚遐昌。", "宇县乐平康。", "真游降格，宝诲昭彰。", "宸跸造仙乡。", "崇妙道、精意齐庄。", "款灵场。", "洁豆荐芬芳。", "备乐奏铿锵。", "犹龙垂裕，千古播休光。", "极褒阳。", "明号洽徽章。", "朝修展，春豫谐民望。", "睹文物煌煌。", "言旋羽卫，肃设坛场。", "报本达萧芗。", "申严祀、礼备烝尝。", "答穹苍。", "纯禧沾品汇，庆赉浃穷荒。", "封人献寿，德化掩陶唐。", "保绵长。", "锡祐永无疆。"]'),
('song-ci-898','导引','无名氏','宋','宋词','song-ci','导引','[]','秘文镂玉，金阁奉安时。',59,'宋词/ci.song.19000.json','["秘文镂玉，金阁奉安时。", "旌盖俨仙仪。", "珠旒俯拜陈章奏，精意达希夷。", "卿云郁郁曜晨曦。", "玉羽拂华枝。", "灵心报贶垂繁祉，宝祚永隆熙。"]'),
('song-ci-899','导引','无名氏','宋','宋词','song-ci','导引','[]','躬朝太室，列圣大功宣。',59,'宋词/ci.song.19000.json','["躬朝太室，列圣大功宣。", "彩仗耀甘泉。", "秘文升辂空歌发，一路覆祥烟。", "珠旒荐献极精虔。", "列侍俨貂蝉。", "穰穰降福均寰宇，垂拱万斯年。"]'),
('song-ci-900','导引','无名氏','宋','宋词','song-ci','导引','[]','重熙累盛，睿化畅真风。',59,'宋词/ci.song.19000.json','["重熙累盛，睿化畅真风。", "尊祖奉高穹。", "林棼彩仗明初日，瑞气满晴空。", "玉銮徐动出环宫。", "虔巩罄宸衷。", "礼成均庆人神悦，圣寿保无穷。"]'),
('song-ci-901','六州','无名氏','宋','宋词','song-ci','六州','[]','承天统，圣主应昌辰。',160,'宋词/ci.song.19000.json','["承天统，圣主应昌辰。", "宝箓降，飚游至，瑞命庆惟新。", "崇大号，仰奉高真。", "献岁当初吉，天下皆春。", "谒秘宇、藻卫星陈。", "芗霭极纷纶。", "琼编焜耀，仙衣綷□，垂旒俯拜，荐献礼惟寅。", "芬芳备，精衷上达穹旻。", "尊道祖，享清庙，助祭万方臻。", "升泰畤、缛典弥文。", "侍群臣。", "汉庭儒雅彬彬。", "烟飞火举毕严禋。", "天地降氤氲。", "高临华阙，恩覃动植，庆延宗社，圣寿比灵椿。"]'),
('song-ci-902','十二时・忆少年','无名氏','宋','宋词','song-ci','十二时・忆少年','[]','享嘉会，万宇欢康。',155,'宋词/ci.song.19000.json','["享嘉会，万宇欢康。", "圣化迈陶唐。", "元符锡命，天鉴昭彰。", "徽号奉琳房。", "陈缛礼、献岁惟良。", "耀旗章。", "翠辇驻仙乡。", "睿意极齐庄。", "仙衣渥采，玉册共荧煌。", "荐芬芳。", "飚驭降灵场。", "回云罕，尊祖趋仙宇，金石韵锵洋。", "聿朝清庙，躬奠瑶觞。", "报本国之阳。", "执笾豆、列侍貂珰。", "对穹苍。", "洪恩霈夷夏，大庆浃家邦。", "垂衣紫极，圣寿保遐昌。", "集祺祥。", "地久与天长。"]'),
('song-ci-903','导引','无名氏','宋','宋词','song-ci','导引','[]','我皇缵位，覆焘合穹旻。',118,'宋词/ci.song.19000.json','["我皇缵位，覆焘合穹旻。", "秘箓示灵文。", "齐居紫殿膺玄贶，降宝命氤氲。", "奉符让德事严禋。", "检玉陟天孙。", "垂鸿纪号光前古，迈八九为君。", "灵台偃武，书轨庆同文。", "奄六合居尊。", "圆穹锡命垂真箓，清晓降金门。", "升中报本禅云云。", "严祀事惟寅。", "无为致治臻清净，见反朴还淳。"]'),
('song-ci-904','导引','无名氏','宋','宋词','song-ci','导引','[]','宝图熙盛，登格圣功全。',118,'宋词/ci.song.19000.json','["宝图熙盛，登格圣功全。", "瑞命集灵篇。", "钦修祀典成明察，道祖降云軿。", "赖乡真馆宅真仙。", "朝谒帝心虔。", "尊崇教父膺鸿福，绵互万斯年。", "犹龙胜境，真宇俨灵姿。", "肃谒展皇仪。", "宝符先路嘉祥应，云物焕金枝。", "纷纭紫节间黄麾。", "藻卫极葳蕤。", "高穹报贶延休祉，仁寿协昌期。"]'),
('song-ci-905','导引','无名氏','宋','宋词','song-ci','导引','[]','紫霄金阙，重叠降元符。',118,'宋词/ci.song.19000.json','["紫霄金阙，重叠降元符。", "亿兆祚皇图。", "云章焜耀傅温玉，宝阁起清都。", "奉迎彩仗溢天衢。", "观者竟欢呼。", "明君钦翼承鸿阴，亿载御中区。", "宝符锡祚，庆寿命维新。", "俄降格飚轮。", "巍巍帝德增虔奉，懿号蔫穹旻。", "精齐秘馆奉严禋。", "文物耀昌辰。", "升烟太一修郊报，鸿祉介烝民。"]'),
('song-ci-906','导引','无名氏','宋','宋词','song-ci','导引','[]','圣神缵绪，赫奕帝图昌。',59,'宋词/ci.song.19000.json','["圣神缵绪，赫奕帝图昌。", "宝录降穹苍。", "宸心励翼修郊报，彩仗列康庄。", "祥烟瑞霭杂天香。", "管磬发声长。", "升坛礼毕膺繁祉，睿算保无疆。"]'),
('song-ci-907','导引','无名氏','宋','宋词','song-ci','导引','[]','太霄玉帝，总御冠灵真。',59,'宋词/ci.song.19000.json','["太霄玉帝，总御冠灵真。", "威德耸天人。", "宝文瑞命符皇运，绵远庆维新。", "洞开霞馆法虚晨。", "八景降飚轮。", "含生普洽□鸿福，圣寿比仙椿。"]'),
('song-ci-908','导引','无名氏','宋','宋词','song-ci','导引','[]','至真降鉴，飚驭下皇闱。',59,'宋词/ci.song.19000.json','["至真降鉴，飚驭下皇闱。", "清漏正依依。", "范金肖像申严奉，仙馆壮翬飞。", "万灵拱卫瑞烟披。", "岸柳映黄麾。", "九清祚圣鸿基永，尧德更巍巍。"]'),
('song-ci-909','导引','无名氏','宋','宋词','song-ci','导引','[]','元符锡命，祗受庆诚明。',59,'宋词/ci.song.19000.json','["元符锡命，祗受庆诚明。", "恭馆法三清。", "开基盛烈垂无极，金像俨天成。", "奉迎霞布甘泉仗，箫瑟振和声。", "灵辰协吉鸿仪毕，万国保隆平。"]'),
('song-ci-910','导引','无名氏','宋','宋词','song-ci','导引','[]','膺乾抚运，垂庆洽重熙。',59,'宋词/ci.song.19000.json','["膺乾抚运，垂庆洽重熙。", "元圣嗣鸿基。", "发挥宝绪灵仙降，感吉梦先期。", "良金璀璨范真仪。", "精意答蕃厘。", "閟宫神馆崇严配，万祀播葳蕤。"]'),
('song-ci-911','导引','无名氏','宋','宋词','song-ci','导引','[]','先天气祖，魄宝御中宸。',59,'宋词/ci.song.19000.json','["先天气祖，魄宝御中宸。", "列位冠高真。", "绿符锡瑞昭元圣，宝历互千春。", "琳宫壮丽俯严闉。", "璇碧照龙津。", "珍金铸像灵仪睟，集福庇蒸民。"]'),
('song-ci-912','导引','无名氏','宋','宋词','song-ci','导引','[]','仙宗灵祖，仪气降中宸。',59,'宋词/ci.song.19000.json','["仙宗灵祖，仪气降中宸。", "孚宥庆维新。", "国工熔范成金像，仪炳动威神。", "玉虚圣境绝纤尘。", "欢忭洽群伦。", "导迎云驾归琳馆，恭肃奉高真。"]'),
('song-ci-913','导引','无名氏','宋','宋词','song-ci','导引','[]','石文应瑞，真主御寰瀛。',59,'宋词/ci.song.19000.json','["石文应瑞，真主御寰瀛。", "慈俭抚群生。", "巍巍威德超千古，大业保盈成。", "神皋福地开恭馆，灵贶日昭明。", "铸金九牧天仪睟，绀殿矗千楹。"]'),
('song-ci-914','导引','无名氏','宋','宋词','song-ci','导引','[]','乘云英圣，千载仰皇灵。',59,'宋词/ci.song.19000.json','["乘云英圣，千载仰皇灵。", "垂法蔼朝经。", "禹金熔范肖仪刑。", "日角焕珠庭。", "琳宫翠殿凤文屏。", "迎奉庆安宁。", "孝思瞻谒荐惟馨。", "诚悫贯青冥。"]'),
('song-ci-915','导引','无名氏','宋','宋词','song-ci','导引','[]','太霄垂佑，绵宇洽祺祥。',59,'宋词/ci.song.19000.json','["太霄垂佑，绵宇洽祺祥。", "秘检焕云章。", "宸心虔奉崇徽号，茂典迈前王。", "霞明藻卫列通庄。", "宝册奉琳房。", "都人震抃腾谣颂，亿载保欢康。"]'),
('song-ci-916','导引','无名氏','宋','宋词','song-ci','导引','[]','明明道祖，金阙冠仙真。',59,'宋词/ci.song.19000.json','["明明道祖，金阙冠仙真。", "清禁降飙轮。", "遥源始悟垂鸿庆，亿兆耸群伦。", "虔崇徽号盛仪陈。", "宝册奉良辰。", "邦家亿载蒙繁祉，圣寿保无垠。"]'),
('song-ci-917','导引','无名氏','宋','宋词','song-ci','导引','[]','祖宗垂佑，亨会协重熙。',59,'宋词/ci.song.19000.json','["祖宗垂佑，亨会协重熙。", "德泽被烝黎。", "虔崇尊谥陈徽册，藻卫列葳蕤。", "宸心致孝极孜孜。", "展礼诏台司。", "祥烟瑞霭浮清庙，绵宇被纯禧。"]'),
('song-ci-918','导引','无名氏','宋','宋词','song-ci','导引','[]','皇穹锡瑞，帝业愈蕃昌。',118,'宋词/ci.song.19000.json','["皇穹锡瑞，帝业愈蕃昌。", "会万玉来王。", "名山珍馆神游接，实信降云房。", "卜兹显位严坛墠，奕奕睹辉光。", "精衷昭格灵心答，天历保无疆。", "皇家立极，炎德赫中区。", "执契应萝图。", "文章焕烂垂星斗，威略定方隅。", "丹扉翠巘锡灵符。", "瑞物纪神输。", "紫坛大报陈昭配，福庆降清都。"]'),
('song-ci-919','六州','无名氏','宋','宋词','song-ci','六州','[]','齐天宇，四海洽淳风。',152,'宋词/ci.song.19000.json','["齐天宇，四海洽淳风。", "接宝胄，垂真检，景祚无穷。", "成玉牒、日观归功。", "冀野升方鼎，脽上由崇。", "钦桧井、云跸巡东。", "国本震为宫。", "乾文焕炳，真祠曲密，重祥叠瑞，琼蕴降高穹。", "膺丕烈，虔心建垂鸿。", "询吉士，郊兆执玉荐衷。", "锺律应、云物迎空。", "乐和轮囷。", "嘉气葱葱。", "天神来降发冲融。", "玉烛四时通。", "星回金辂雷作解，昆蚑被惠，亿载帝基隆。"]'),
('song-ci-920','十二时・忆少年','无名氏','宋','宋词','song-ci','十二时・忆少年','[]','雕戈偃玉塞清明。',154,'宋词/ci.song.19000.json','["雕戈偃玉塞清明。", "道德洽和平。", "龟畴凤柙，腾实飞英。", "岱畎让功成。", "汾水上、寅辂銮声。", "荐精诚。", "仙宇玉为京。", "圭洁奉高明。", "瑶山银榜，固国本丕闳。", "诏公卿。", "绵蕝殉舆情。", "稽阳位，报本郊坛畤，助祭俨簪缨。", "祖宗配侑，朱燎晶荧。", "百礼备丰盈。", "答天地、用厚怀生。", "泰黎氓。", "千畿先润泽，万宝尽开荣。", "龙沙日窟，文轨永来并。", "保嘉享，史册焕鸿名。"]'),
('song-ci-921','导引','无名氏','宋','宋词','song-ci','导引','[]','真人临御，实瑞集丰融。',118,'宋词/ci.song.19000.json','["真人临御，实瑞集丰融。", "万国仰天聪。", "嘉礼盛礼文章焕，齐洁致清衷。", "笙镛六变三神格，喜备盛仪容。", "乾穹上达昭灵飨，庆绪蔼丕隆。", "阳郊报本，礼意弥勤礼。", "太一下威神。", "天临两观推三赦，庆祉被臣民。", "徽名荐册缛仪陈。", "盛节焕书筠。", "涂歌邑诵扬徽懿，鼎命协惟新。"]'),
('song-ci-922','六州','无名氏','宋','宋词','song-ci','六州','[]','承皇统，天地洽清宁。',140,'宋词/ci.song.19000.json','["承皇统，天地洽清宁。", "熙帝载，建民极，百度推明。", "崇让肄、博考儒经。", "游豫腾谣诵，星跸天行。", "留绀宇、顺拜金庭。", "兆庶动欢声。", "灵心上达，卿云成盖，祥风袭物，瑞日耀园清。", "列圣孝德被寰瀛。", "就阳位协吉，周正俨簪缨。", "交对越群灵。", "皇威赫奕盛仪成。", "徽册受鸿名。", "鸡竿肆赦，鸳行均庆，翾飞浸泽，期万保升平。"]'),
('song-ci-923','十二时・忆少年','无名氏','宋','宋词','song-ci','十二时・忆少年','[]','嘉亨运，璇历均调。',155,'宋词/ci.song.19000.json','["嘉亨运，璇历均调。", "光烈遇唐尧。", "珍图缘错，垂锡乾霄。", "封岱顺车杓。", "修合答、万玉来朝。", "瑞丕昭。", "构宇结瑛瑶。", "虚气下仙飚。", "钦崇道祖，舆驾动临谯。", "整銮镳。", "郊报厚黎苗。", "均纯贶，渗漉咸滋液，能事播欢谣。", "继明缵绪，缓赋轻徭。", "京庾比丰饶。", "勤中昃、采善询荛。", "五风飘。", "授人时吏正，休马橐兵销。", "良肱隆栋，助化率皇僚。", "德声遥。", "懿铄简书标。"]'),
('song-ci-924','导引','无名氏','宋','宋词','song-ci','导引','[]','绵区浃宇，三万里封疆。',118,'宋词/ci.song.19000.json','["绵区浃宇，三万里封疆。", "躬稼穑重光。", "神宗昔举殊尤礼，今复睹吾皇。", "先农祀罢东郊晓，玉趾染游场。", "三推初毕公卿遍，从此万斯箱。", "务农敦本。", "自古属明王。", "文册布彝章。", "吾皇睿圣躬千亩，将欲积神仓。", "去年宿雪田膏极，黛耜应农祥。", "尧郊击壤迎归辂，解雨遍遐荒。"]'),
('song-ci-925','六州','无名氏','宋','宋词','song-ci','六州','[]','寰宇定，四海奉文思。',156,'宋词/ci.song.19000.json','["寰宇定，四海奉文思。", "书轨混，梯航凑，共戴昌期。", "稽古典、方咏京坻。", "耕籍丰民稼，敦本农时。", "陈羽卫、日月旌旗。", "衮冕次坛壝。", "帷宫宿设，梐枑相差。", "穆清端拱，星毕照罘罳。", "良宵永，为民广洽，庞褫奏、行漏昭庭燎，铙吹鼓曾飔。", "百神拥卫斗东移。", "明发俨皇仪。", "手揽洪縻。", "丰年万亿与千斯。", "德泽遍华夷。", "回旋辂、天临双阙，四方在宥，永保鸿基。"]'),
('song-ci-926','十二时・忆少年','无名氏','宋','宋词','song-ci','十二时・忆少年','[]','君天下，万国来王。',154,'宋词/ci.song.19000.json','["君天下，万国来王。", "玉帛凑梯航。", "五风十雨，品物蕃昌。", "栖垅有馀粮。", "躬千亩、天步龙翔。", "化重光。", "举祖彝章。", "验晨正农祥。", "东郊如砥，黛耜御游场。", "荐芬芳。", "稼穑伫丰穰。", "成耨礼，三事并卿尹，执耒有经常。", "此仪旷绝，行自吾皇。", "玉振复金相。", "睹九色、流衍仓箱。", "洽欢康。", "虫鱼皆茂育，戈祋永韬藏。", "两闱至圣，辅以股肱良。", "祚延长。", "寿岳保无疆。"]'),
('song-ci-927','奉礼歌','无名氏','宋','宋词','song-ci','奉礼歌','[]','六龙承驭。',176,'宋词/ci.song.19000.json','["六龙承驭。", "紫坛平、瑞蔼葱笼拥神都。", "肃环卫、严貔虎。", "鸡人行漏传呼。", "灵景霁、星斗临帝居。", "旷天宇。", "微风来、翠幄绕相鸟。", "对越方初。", "笳鼓震，饶箫举。", "阳律才动协气舒。", "氛祲交祛。", "物昭苏。", "抚瑶图。", "柴类精诚，当契唐虞。", "思前古。", "泰平承多祐。", "包戈偃革，柔远咏皇谟。", "称文武。", "四表覆盂。", "端冕出、从路车。", "兵帅谨储胥。", "唯奏凯、乐康臞。", "朝野欢娱。", "歌帝烈，扬盛节，园丘礼大洽，霈泽绵区。"]'),
('song-ci-928','导引','无名氏','宋','宋词','song-ci','导引','[]','母仪天下，圣祚保延长。',118,'宋词/ci.song.19000.json','["母仪天下，圣祚保延长。", "声教被遐方。", "严恭孝飨来清庙，鸾辂历康庄。", "箫韵九奏凤来翔。", "褘翟焕祥光。", "惟馨蕊醴奠瑶觞。", "万寿永无疆。", "亲承先顾，保祐助吾皇。", "亿载正乾纲。", "宗文祖武尊邦社，天下锡蕃昌。", "六宫扈从亲重翟，清庙荐萧芗。", "礼行乐备神祈飨，四海永来王。"]'),
('song-ci-929','六州','无名氏','宋','宋词','song-ci','六州','[]','炎灵永。',157,'宋词/ci.song.19000.json','["炎灵永。", "长乐助文明。", "居靖懿，敷皇化，四海升平。", "慈是宝、万物怀生。", "耀德不观兵。", "大治欢声。", "金辂饬、藻卫天行。", "春色满皇京。", "登歌清庙，神祈顾飨，瑄玉纯精。", "亿万载持盈。", "膺天贶。", "尤祥纷委来呈。", "木连芝三秀，玉烛协和平。", "仲春月、万杏初荣。", "整羽卫葱衡。", "亲款神明。", "九韶叠奏罄箫笙。", "上以继咸英。", "黄流玉瓒，殊庭肸蚃，宸仪回复，景祐遍寰瀛。"]'),
('song-ci-930','十二时・忆少年','无名氏','宋','宋词','song-ci','十二时・忆少年','[]','母仪下，国祚和平。',153,'宋词/ci.song.19000.json','["母仪下，国祚和平。", "玉帛凑寰瀛。", "尤祥极瑞，茂实英声。", "两耀比皇明。", "昭孝飨、躬荐精诚。", "祥并保佑洽由庚。", "和乐遍怀生。", "柔远能迩，海宇永澄清。", "复曾城。", "宝册受鸿名。", "绵龙绪，十治同齐圣。", "至治播欢声。", "止戈为武，顿纲搜英。", "察万物人情。", "损服御、不尚瑛琼。", "俗怀生动，修文考制，颛法上天明。", "地不爱宝，人不爱其诚。", "帝图宏。", "寿岳永嶢峥。"]'),
('song-ci-931','导引','无名氏','宋','宋词','song-ci','导引','[]','受遗仍几，负扆拥文明。',118,'宋词/ci.song.19000.json','["受遗仍几，负扆拥文明。", "勤翼助持盈。", "徽音不独流笙管，青册更峥嵘。", "羽軿上汉玉衣轻。", "隙驷去无程。", "宸心追远严成配，亿世乡粢盛。", "受天明命，作汉发灵长。", "龙日梦休祥。", "真人承体应图箓，庆祚启无疆。", "望舒未满殒清光。", "舜慕极旻苍。", "祢宫崇祔申追养，禘祫复蒸尝。"]'),
('song-ci-932','导引','无名氏','宋','宋词','song-ci','导引','[]','炎精凿乾，正统膺瑶历。',61,'宋词/ci.song.19000.json','["炎精凿乾，正统膺瑶历。", "万宇归神德。", "以圣继圣三后，光声明、扬典则。", "天清日润莹玉泽。", "华殿辉金碧。", "宸心思孝仙驭，三灵休、绥万亿。"]'),
('song-ci-933','导引','无名氏','宋','宋词','song-ci','导引','[]','圣真下武，淳烈缉丕隆。',59,'宋词/ci.song.19000.json','["圣真下武，淳烈缉丕隆。", "绝瑞与天通。", "封山育谷声名举，仙驭邈轩龙。", "腾金篆玉显成功。", "业业承垂鸿。", "惟皇孝述光前志，保祐福来同。"]'),
('song-ci-934','导引','无名氏','宋','宋词','song-ci','导引','[]','膺乾兴运，辰火正心房。',59,'宋词/ci.song.19000.json','["膺乾兴运，辰火正心房。", "宗祀继文王。", "典容希阔成昭备，彬郁づ晖光。", "因心崇孝申郊侑，内外罄斋庄。", "神灵欢嘉昌绵瓞，受福介无疆。"]'),
('song-ci-935','六州','无名氏','宋','宋词','song-ci','六州','[]','崇严配，衢室飨中宸。',159,'宋词/ci.song.19000.json','["崇严配，衢室飨中宸。", "寻汉礼，崇唐典，袭映情文。", "方宝辂、羽卫星陈。", "藻绣填驰路，昭烂如云。", "灵顾諟，德升闻。", "旷瑞集纷纶。", "承平嘉靖，收成和熟，万方歌舞，喜气满青旻。", "成熙事、宣和舆物惟新。", "展宫寝，疑庙室，飨帝极尊亲。", "罄宸虑，四海骈臻。", "肃簪绅。", "斋明际，浃人神。", "乾元盛则属兹辰。", "皇业协华勋。", "房心正位，端居报政，三年美荐，广孝福吾民。"]'),
('song-ci-936','十二时・忆少年','无名氏','宋','宋词','song-ci','十二时・忆少年','[]','恢皇统，宵旰勤考，正朔づ同规。',155,'宋词/ci.song.19000.json','["恢皇统，宵旰勤考，正朔づ同规。", "留谈经幄，来谏书帷。", "稽古极文思。", "尊耀魄、宝秩神祈。", "礼从宜。", "显相协钦祗。", "颢气结华滋。", "西成献瑞，百谷满京坻。", "化无为。", "斯万卜年期。", "隆昌运，大报同姬成，文武绍重熙。", "历朝缺典，自我亲祠，容采炳葳蕤。", "嘉能事、秀错多仪。", "太平时。", "清风涵溥惠，浩露浃深慈。", "群方昭泰，保定宅华夷。", "拥灵禧。", "万叶累鸿基。"]'),
('song-ci-937','导引','无名氏','宋','宋词','song-ci','导引','[]','万灵昭瑞，天地赞昌期。',59,'宋词/ci.song.19000.json','["万灵昭瑞，天地赞昌期。", "宝运协开基。", "巍巍烈圣无疆德，神化洽重熙。", "虔思出驾罄彰施。", "岁暮俨神宜。", "云舆迎奉依珍馆，塞外焕朝仪。"]'),
('song-ci-938','导引','无名氏','宋','宋词','song-ci','导引','[]','穆清冲境，金阙秘寥阳。',59,'宋词/ci.song.19000.json','["穆清冲境，金阙秘寥阳。", "二后侍虚皇。", "真人恭默钦先烈，肖象启琳房。", "岿然神物护灵光。", "玉色粹逾彰。", "虎旌龙节辉前后，馆御镇无疆。"]'),
('song-ci-939','导引','无名氏','宋','宋词','song-ci','导引','[]','剗除霸轨，穆穆照皇明。',59,'宋词/ci.song.19000.json','["剗除霸轨，穆穆照皇明。", "大统一寰瀛。", "穷湖绝塞人安业，武库遂销兵。", "仙游昔日上三清。", "极望紫云平。", "珠宫宝坐严崇奉，圣祚永绥宁。"]'),
('song-ci-940','导引','无名氏','宋','宋词','song-ci','导引','[]','宝图全盛，端拱信巍巍。',59,'宋词/ci.song.19000.json','["宝图全盛，端拱信巍巍。", "声教暨华夷。", "辰髦尽入英雄彀，齐筑太平基。", "仙舆前指玉霄归。", "夹道九鸾飞。", "真宫秘殿严崇奉，圣治永无为。"]'),
('song-ci-941','导引','无名氏','宋','宋词','song-ci','导引','[]','龙驰驾，玉辂俨宸威。',58,'宋词/ci.song.19000.json','["龙驰驾，玉辂俨宸威。", "天仗下端闱。", "华旌翠羽笼黄道，赫奕照晨晖。", "大哉仁孝逾尧舜，圭瓒罄虔祈。", "神灵肸蚃来歆答，万寿保纯禧。"]'),
('song-ci-942','合宫歌','无名氏','宋','宋词','song-ci','合宫歌','[]','泰阶平。',81,'宋词/ci.song.19000.json','["泰阶平。", "勋业属全盛。", "旰昃焦劳，访道缵三朝仁政。", "大庭蒇事款上灵。", "服冕执圭，侑飨尊累圣。", "豆笾奕奕嘉靖。", "神光四照百礼成。", "回御天门。", "讲丕彝，敷大庆。", "蒙被草木，万国仰声明。"]'),
('song-ci-943','六州','无名氏','宋','宋词','song-ci','六州','[]','严太寝，容礼绎前经。',77,'宋词/ci.song.19000.json','["严太寝，容礼绎前经。", "仰苍粹，钦厚顺，式报生成。", "至信洽，上格神灵。", "太和凝气象，霄宇澄清。", "圭币列，鼓钟铿。", "群品荐丰盈。", "熙事既备，大仪交举，百嘉允集，万福来迎。"]'),
('song-ci-944','十二时・忆少年','无名氏','宋','宋词','song-ci','十二时・忆少年','[]','金徒箭、晓漏延长。',76,'宋词/ci.song.19000.json','["金徒箭、晓漏延长。", "霄极烂星芒。", "珠旒绚采，黼衮交章。", "宸表寝永昂。", "上交合奠鬯流香。", "燎扬光。", "神锡以百祥。", "寿延于无疆。", "三时告稔，万亿满仓箱。", "思边防。", "蛮貊尽来王。"]'),
('song-ci-945','导引','无名氏','宋','宋词','song-ci','导引','[]','天仪安豫洽无为。',56,'宋词/ci.song.19000.json','["天仪安豫洽无为。", "九域被雍熙。", "鸾刀亲割升圭瓒，清庙展孝思。", "箫韶九变皇灵格，嘏告显深慈。", "精诚动感归能飨，福祚衍金枝。"]'),
('song-ci-946','奉礼歌','无名氏','宋','宋词','song-ci','奉礼歌','[]','皇泽均普，群生遂。',170,'宋词/ci.song.19000.json','["皇泽均普，群生遂。", "万宇和祔，讲天津、合祭圣宗神祖，八音钧奏谐节。", "堂上荐鸣球，琴瑟击。", "越布濩、霜空静，月华凝、光景蔼蔼。", "纷纷晓霞披。", "和铃作、鸾舆回。", "天人共睹，庆无疆、祚崇明祀。", "五辂驾、腾黄纯驷。", "旗常扈跸严环卫。", "公卿奉引，虚徐弛道，祲容　靡。", "葱葱郁郁，祥风瑞霭。", "发天光旖旎。", "锡羡丰融，漏泉该浃，上恩遐被。", "群心豫，颂声作，皇德至，侔乾贶，浩浩霈。"]'),
('song-ci-947','六州','无名氏','宋','宋词','song-ci','六州','[]','深仁化。',77,'宋词/ci.song.19000.json','["深仁化。", "穹厚格成平。", "徇诚虑，托皇统，万宇光亨。", "申孝致洁飨宗祊。", "金驾徐徐动，容礼辉明。", "躬道祖谒款殊庭。", "列圣固纯诚。", "灵心底豫，休祥充塞，端闱肆眚，爱日灿然明。"]'),
('song-ci-948','十二时・忆少年','无名氏','宋','宋词','song-ci','十二时・忆少年','[]','明昌世、乾统弥文。',77,'宋词/ci.song.19000.json','["明昌世、乾统弥文。", "皇德揆华勋。", "三辰顺晷，庆霭轮囷。", "潜宝耀坤珍。", "躬祫飨、肃荐牺尊。", "孝仪申。", "助祭俨缨绅。", "大乐奏韶钧。", "阳开阴闭，幽显尽欣欣。", "庆霄文。", "思结在黎民。"]'),
('song-ci-949','导引','无名氏','宋','宋词','song-ci','导引','[]','於皇祖烈，大宋启鸿名。',59,'宋词/ci.song.19000.json','["於皇祖烈，大宋启鸿名。", "骏命属炎灵。", "閟宫厚德太阴精。", "重华诞圣明。", "轩台百世护基卮。", "龙驾在清冥。", "汉家原庙崇新饰，鼎业永安宁。"]'),
('song-ci-950','导引','无名氏','宋','宋词','song-ci','导引','[]','母仪天宇，彤史蔼遗芳。',51,'宋词/ci.song.19000.json','["母仪天宇，彤史蔼遗芳。", "纡馀庆气固灵长。", "基祚浸明昌。", "重华大孝奉蒸尝。", "原庙灵光。", "采章翟严新饰，歆愿福穰穰。"]'),
('song-ci-951','导引','无名氏','宋','宋词','song-ci','导引','[]','帝皇盛烈，教孝谨民常。',59,'宋词/ci.song.19000.json','["帝皇盛烈，教孝谨民常。", "严父位明堂。", "管丝金石含天韵，笾豆荐芬芳。", "肃然音响灵来下，容与动祥光。", "四方内外交欣喜，饮福万年觞。"]'),
('song-ci-952','合宫歌','无名氏','宋','宋词','song-ci','合宫歌','[]','太平时。',162,'宋词/ci.song.19000.json','["太平时。", "宝殿垂衣治。", "驭左右贤俊，万国执玉助祭。", "凉秋九月霜华飞。", "感发纯孝，五室配上帝。", "紫汉入夜凝霁。", "房心下，泛华芝。", "大田栖粮，岁功成，农歌沸。", "复道躬拜，肃迎神嬉。", "漏声迟。", "玉磬响，递清吹。", "嘉荐升雕俎，柘桨屡酌几醉。", "云扶灵驾欻若归。", "天意留顾，万福如山委。", "便御丹阙，布为皇泽，与民熙熙。", "远观唐虞，未有如兹盛礼。", "愿常遇鸣銮，三岁亲祠。"]'),
('song-ci-953','六州','无名氏','宋','宋词','song-ci','六州','[]','承景运，天子奉明堂。',157,'宋词/ci.song.19000.json','["承景运，天子奉明堂。", "玉烛应，金飚动，万宝盈箱。", "严法驾、天路龙骧。", "采仗迎祥。", "日色动扶桑。", "款清庙、我诚将。", "回御八鸾锵。", "於皇仁孝，祖宗来顾，熙于四极，令问载无疆。", "躬严配、笙镛奏凤来翔。", "瑞烟起，浮帝衮，玉步间天香。", "升重宇、壁玉华光。", "桂流觞。", "神虞夕照熉黄。", "九霄鸣佩下清厢。", "齐拱太微傍。", "群心同愿，长临路寝，三年讲礼，显祀文王。"]'),
('song-ci-954','十二时・忆少年','无名氏','宋','宋词','song-ci','十二时・忆少年','[]','承平世，嘉祐壬寅。',152,'宋词/ci.song.19000.json','["承平世，嘉祐壬寅。", "九月上旬辛。", "酒醪香旨，谷实丰珍。", "宗祀敞中宸。", "宾延上帝五方神。", "以严亲。", "诚心通杳杳，文物盛彬彬。", "金声玉色，和奏翕铿纯。", "荡无垠。", "天地一洪钧。", "明天子、至化深仁。", "一意奉精禋。", "感时怵惕，即事恭夤。", "用孝教斯民。", "多仪举，大恩沦。", "福来臻。", "清风动阊阖，皓气下天津。", "币诚玉腆，朱燎焜槱薪。", "积欢欣。", "皇历万斯春。"]'),
('song-ci-955','导引','无名氏','宋','宋词','song-ci','导引','[]','九虞初毕，黼座掩瑶觞。',59,'宋词/ci.song.19000.json','["九虞初毕，黼座掩瑶觞。", "羽卫盛煌煌。", "数声清跸来天上，想像赭袍光。", "新成清庙勗云堂。", "孝飨奉蒸尝。", "子孙千载承丕绪，景福介无疆。"]'),
('song-ci-956','导引','无名氏','宋','宋词','song-ci','导引','[]','彤霞缥缈，海上隐三山。',59,'宋词/ci.song.19000.json','["彤霞缥缈，海上隐三山。", "仙去莫能攀。", "珠宫本是神灵宅，飚驭此来还。", "云边天日望威颜。", "不似在人间。", "当时齐鲁鸣鸾处，稽首泪潺湲。"]'),
('song-ci-957','导引','无名氏','宋','宋词','song-ci','导引','[]','治平天子，景至肇严禋。',59,'宋词/ci.song.19000.json','["治平天子，景至肇严禋。", "华玉礼威神。", "六龙齐捧銮舆动，采仗转钩陈。", "归来瑞气满清晨。", "金石舜韶新。", "楼前山鹤衔书下，天地已为春。"]'),
('song-ci-958','六州','无名氏','宋','宋词','song-ci','六州','[]','垂炎运，真主嗣瑶图。',162,'宋词/ci.song.19000.json','["垂炎运，真主嗣瑶图。", "海波晏，卿云烂，日月丽皇都。", "年屡稔、万宝山储。", "广莫风生律，一气潜嘘。", "陈法驾、翠羽装舆。", "清跸下天衢。", "金匏六变，欻然灵顾，来车风马，拜贶紫坛初。", "奉神娱。", "嘉笾荐，美玉奠，照荧□。", "星彩动，霜华薄，禁阁漏声疏。", "回龙驭、宝瑞纷敷。", "众心愉。", "钧天别奏箫竽。", "仙人楼上捧赦书。", "舞鹤更踌蹰。", "丹徼北，穷沙漠，涵皇泽，盛德迈唐虞。"]'),
('song-ci-959','十二时・忆少年','无名氏','宋','宋词','song-ci','十二时・忆少年','[]','千年运，五叶升平。',154,'宋词/ci.song.19000.json','["千年运，五叶升平。", "法扆坐中盈。", "天高日润，雷动风行。", "三万里声明。", "灵台偃伯仆边兵。", "事农耕。", "一气重滋萌。", "万宝迄登成。", "天生嘉谷，博硕又芳馨。", "罄齐精。", "谒款谢嘉生。", "神明地，当阳定，天位来助见人情。", "壁珪葱璨，金石铿鈜。", "仪礼盛西京。", "灵祈喜、福绿来盈。", "咏夷庚。", "幔城班上笏，銮路趣还衡。", "觚棱双阙，赭案切三清。", "动欢声。", "恩泽遍寰瀛。"]'),
('song-ci-960','奉礼歌','无名氏','宋','宋词','song-ci','奉礼歌','[]','皇天眷命集珍符。',169,'宋词/ci.song.19000.json','["皇天眷命集珍符。", "上圣膺期起天衢。", "环紫极鸿枢。", "此时朝野欢娱。", "乐于于。", "似住华胥。", "和气至，嘉生遂，豆实正芬敷。", "礼与诚俱。", "风飘洒，灵来下，喜怡愉。", "斗随车转，月上坛觞。", "奉禋初。", "至诚孚。", "如山岳、福委祥储。", "车旋轨、云间双阙峙，百尺朱绳到地，两行雉扇排虚。", "仙鹤衔书。", "珍袍上笏相趋。", "共欢呼。", "号令崇朝，遍满寰区。", "阳动春嘘。", "躬盛事，受多祉，千万祀，天长久皇图。"]'),
('song-ci-961','导引','无名氏','宋','宋词','song-ci','导引','[]','寿原初掩，归跸九虞终。',59,'宋词/ci.song.19000.json','["寿原初掩，归跸九虞终。", "仙驭更无踪。", "思皇攀慕追来孝，作庙继三宗。", "旌旗居外拥千重。", "延望想威容。", "宝舆迎引归新殿，奏享备钦崇。"]'),
('song-ci-962','导引','无名氏','宋','宋词','song-ci','导引','[]','九清三境，飙驭杳难追。',59,'宋词/ci.song.19000.json','["九清三境，飙驭杳难追。", "功烈并巍巍。", "洛都不及西巡到，犹识睟容归。", "三条驰道隐金槌。", "仙仗共逶迤。", "珠宫绀宇申严奉，亿载固皇基。"]'),
('song-ci-963','导引','无名氏','宋','宋词','song-ci','导引','[]','祥符盛际，二鄙正休兵。',59,'宋词/ci.song.19000.json','["祥符盛际，二鄙正休兵。", "瑞应满寰瀛。", "东封西祀鸣銮辂，从幸见升平。", "仙游一去上三清。", "庙食享隆名。", "寝园松柏秋风起，箫吹想平生。"]'),
('song-ci-964','导引','无名氏','宋','宋词','song-ci','导引','[]','九霄仙驭，四纪乐西清。',59,'宋词/ci.song.19000.json','["九霄仙驭，四纪乐西清。", "游衍遍黄庭。", "云軿万里归真室，上应泰阶平。", "金舆玉像下瑶京。", "彩仗拥霓旌。", "天人感会千年运，福祚永昌明。"]'),
('song-ci-965','导引','无名氏','宋','宋词','song-ci','导引','[]','鼎湖龙去，仙仗隔蓬莱。',59,'宋词/ci.song.19000.json','["鼎湖龙去，仙仗隔蓬莱。", "辇路已苍苔。", "汉家原庙临清渭，远泣玉衣来。", "凤箫鸾扇共徘徊。", "帐殿倚云开。", "春风不向天袍动，空绕翠舆回。"]'),
('song-ci-966','导引','无名氏','宋','宋词','song-ci','导引','[]','清都未晓，万乘并驾，煌煌拥天行。',120,'宋词/ci.song.19000.json','["清都未晓，万乘并驾，煌煌拥天行。", "祥风散瑞霭，华盖耸，旗常建，耀层城。", "四列兵卫，爟火映、金支翠旌。", "众乐警、作充宫庭。", "皦绎成。", "绀幄掀，衮冕明。", "妥帖坛陛霄升。", "振珩璜、神格至诚。", "云车下冥冥。", "储祥降嘏莫可名。", "御端阙、肸号敷荣。", "泽翔施溥，茂祉均被含生。"]'),
('song-ci-967','导引','无名氏','宋','宋词','song-ci','导引','[]','驾斑龙。',59,'宋词/ci.song.19000.json','["驾斑龙。", "忽催金母转仙仗、去瑶宫。", "绛阙深沈杳无踪。", "渐尘空。", "丝网琼林，花似怨东风。", "垂清露啼红。", "犹想旧春中。", "献万寿、宝船空。"]'),
('song-ci-968','六州','无名氏','宋','宋词','song-ci','六州','[]','九龙舆。',170,'宋词/ci.song.19000.json','["九龙舆。", "记春暮、幸蓬壶。", "琼囿敞，绣仗趋。", "年华与逝水俱。", "瑶京远，信息断无。", "宝津池面落花铺。", "愁晚容车来禁涂。", "凤箫鸾翣，西指昭陵去。", "旧赏蟠桃熟，又见涨海枯。", "应共灵真母，曳霞裾。", "宴清都。", "恨满山隅。", "春城翠柏藏乌。", "扃户剑，照灯鱼。", "人间一梦觉馀。", "泉宫窈窕锁夜龙，银江澄澹浴仙凫。", "烟冷金炉玉殿虚。", "绿苔新长，雕辇曾行处。", "夜夜东朝月，似旧照锦疏。", "侍女盈盈泪珠。"]'),
('song-ci-969','十二时・忆少年','无名氏','宋','宋词','song-ci','十二时・忆少年','[]','治平时。',185,'宋词/ci.song.19000.json','["治平时。", "暂垂帘，佑圣子、解危疑。", "坐安天下逾岁。", "厌避万机。", "退处宸闱。", "殿开庆养，志入希夷。", "扶皓日，浴咸池。", "看神孙、抚御千载，重雍累熙。", "四方钦仰洪慈。", "阴德远，仁功积，欢养罄九域，礼无违。", "事难期。", "乘霞去，乍睹升仙，诰下九围。", "泣血涟如，更鸾车、动春晚、雾暗翠旗。", "路指嵩伊。", "薤歌凤吹。", "悠扬逐风悲。", "珠殿悄，网尘垂。", "空坐湿，罔极吾皇孝思。", "镂玉写音徽。", "彤管炜，青编纪，宁更羡周雅，播声诗。"]'),
('song-ci-970','陵歌','无名氏','宋','宋词','song-ci','陵歌','[]','真人地，瑞应待圣时。',159,'宋词/ci.song.19000.json','["真人地，瑞应待圣时。", "巩原西。", "荥河会，润洛与瀍伊。", "众水萦回。", "嵩高映抱，几叠屏帏。", "秀岭参差。", "遥山群凤随。", "共瞻陵寝浮佳气，非烟朝暮飞。", "龟筮告前期。", "奠收玉斝，筵卷时衣。", "銮辂晓驾载龙旗。", "路逶迟。", "铃歌怨、画翣引华芝。", "雾薄风微。", "真游远、闭宝阁金扉。", "侍女悲啼。", "玉阶春草滋。", "露桃结子灵椿翠，青车何日归。", "衔恨望西畿。", "便房一锁，夜台晓无期。"]'),
('song-ci-971','导引','无名氏','宋','宋词','song-ci','导引','[]','龙舆春晚，晓日转三川。',59,'宋词/ci.song.19000.json','["龙舆春晚，晓日转三川。", "鼓吹惨寒烟。", "清明过后落花天。", "望池馆依然。", "东风百宝泛楼船。", "共荐寿当年。", "如今又到苑西边。", "但魂断香軿。"]'),
('song-ci-972','六州','无名氏','宋','宋词','song-ci','六州','[]','庆深恩。',166,'宋词/ci.song.19000.json','["庆深恩。", "宝历正乾坤。", "前帝子，后圣孙。", "援立两仪轩。", "西宫大母朝寝门。", "望椒闼常温。", "芳时媚景，有三千宫女，相将奉、玉辇金根。", "上林红英繁。", "缥缈钧天。", "奏梨园。", "望绝瑶池，影断桃源。", "恨难论。", "开禁阍。", "春风丹旐翩翩。", "飞翠盖、驾雕輼。", "容卫入西原。", "管箫动地清喧。", "陵上柏烟昏。", "残霞弄影，孤蟾浮天外，行人触目是销魂。", "问苍天。", "尘世光阴去如奔。", "河洛潺湲。", "此恨长存。"]'),
('song-ci-973','十二时・忆少年','无名氏','宋','宋词','song-ci','十二时・忆少年','[]','望嵩邙。',185,'宋词/ci.song.19000.json','["望嵩邙。", "永昭陵畔，王气压龙冈。", "巩洛灵光。", "郁郁起嘉祥。", "虚彩帟，转哀仗，閟幽堂。", "叹仙乡路长。", "景霞飞松上。", "珠襦宵掩，细扇晨归，崑阆茫茫。", "满目东郊好，红葩斗芳。", "韶景空骀荡。", "对春色、倍凄凉。", "最情伤。", "从辇嫔嫱。", "指瑶津路，泪雨泣千行。", "翠珥明珰。", "曾忆荐琼觞。", "春又至，人何往。", "事难忘。", "向斜阳断肠。", "听钧天嘹亮。", "清都风细，朱栏花满，谁奏清商。", "紫幄重帘外，时飘宝香。", "环佩珊珊响。", "问何日、反雕房。"]'),
('song-ci-974','虞主歌','无名氏','宋','宋词','song-ci','虞主歌','[]','转紫芝。',171,'宋词/ci.song.19000.json','["转紫芝。", "指东都帝畿。", "愁雾里、箫声宛转，辇路逶迤。", "那堪见、郊原芳菲。", "日迟迟。", "对列凤翣龙旗。", "轻阴黯四垂。", "楼台绿瓦沍琉璃。", "仙仗归。", "寿原清夜，寒月掩褕褘。", "翠幰雕轮，空反灵螭。", "憩长岐。", "嵩峰远，伊川渺弥。", "此时还帝里。", "旌旛上下，葆羽葳蕤。", "天街回、垂杨依依。", "过端闱。", "阊阖正辟金扉。", "觚棱射暖晖。", "虞神宝篆散轻丝。", "空涕涕。", "望陵宫女，嗟物是人非。", "万古千秋，烟惨风悲。"]'),
('song-ci-975','导引','无名氏','宋','宋词','song-ci','导引','[]','轻舆小辇，曾宴玉栏秋。',61,'宋词/ci.song.19000.json','["轻舆小辇，曾宴玉栏秋。", "庆赏殿宸游。", "伤心处，兽香散尽，一夜入丹邱。", "翠帘人静月光浮。", "但半卷银钩。", "谁知道，桂华今夜，却照鹊台幽。"]'),
('song-ci-976','导引','无名氏','宋','宋词','song-ci','导引','[]','新宫翼翼，钜丽冠神京。',59,'宋词/ci.song.19000.json','["新宫翼翼，钜丽冠神京。", "金虬蟠绣楹。", "都人瞻望洪纷处，陆海涌蓬瀛。", "仙舆缥缈下圆清。", "彩仗拥天行。", "熉黄珠幄承灵德，锡羡永升平。"]'),
('song-ci-977','导引','无名氏','宋','宋词','song-ci','导引','[]','九清云杳，飚驭邈难追。',59,'宋词/ci.song.19000.json','["九清云杳，飚驭邈难追。", "功化盛当时。", "保扶仁圣成嘉靖，彤管载音徵。", "天都左界抗华榱。", "仙仗下逶迤。", "宝楹黼帐承神贶，万寿永无期。"]'),
('song-ci-978','导引','无名氏','宋','宋词','song-ci','导引','[]','金殿晚，注目望宫车。',60,'宋词/ci.song.19000.json','["金殿晚，注目望宫车。", "忽听受遗书。", "白云缥缈帝乡去，抱弓空慕龙湖。", "瑶津风物胜蓬壶。", "春色至、望雕舆。", "花飞人寂寂，凄凉一梦清都。"]'),
('song-ci-979','六州','无名氏','宋','宋词','song-ci','六州','[]','炎图盛，六叶正，协重光。',171,'宋词/ci.song.19000.json','["炎图盛，六叶正，协重光。", "膺宝瑞，更法度，智勇超轶成汤。", "昭回云汉烂文章。", "震扬威武慑多方。", "生民帖泰拥殊祥。", "封人祝颂，万寿与天长。", "岂知丹鼎就，龙下五云旁。", "飘然真驭。", "游衍仙乡。", "泣彤裳。", "伊落洋洋。", "嵩峰少室相望。", "藏弓剑，游衣冠，俊功盛德难忘。", "泉台寂、鱼烛荧煌。", "银海深、凫雁翱翔。", "想像平居谩焚香。", "望陵人散，翠柏忽成行。", "犹馀嵩峰月，夜夜照幽堂。", "千秋陈迹凄凉。"]'),
('song-ci-980','十二时・忆少年','无名氏','宋','宋词','song-ci','十二时・忆少年','[]','珍符锡佑启真人。',186,'宋词/ci.song.19000.json','["珍符锡佑启真人。", "储思在斯民。", "勤劳日升万物，皆入陶钧。", "收威柄，更法令，鼎从新。", "东风吹百卉，上苑正青春。", "流虹节近，衣冠玉帛，交奏严宸。", "万寿祝尧仁。", "忽听宫车晚出，但号慕，瞻云路，企龙鳞。", "穷天英。", "冠古精神。", "杳然上傃，人空望、属车巡。", "虚仗星陈。", "画翣环拥龙輴。", "泉宫掩，帝乡远，邈难亲。", "反雕轮。", "飞羽盖、还渡天津。", "雾迷朱服，风摇细扇，触目悲辛。", "列嫔嫱，垂红泪，浥行尘。", "相将问。", "何日下青旻。"]'),
('song-ci-981','永裕陵歌','无名氏','宋','宋词','song-ci','永裕陵歌','[]','升龙德，当位富春秋。',163,'宋词/ci.song.19000.json','["升龙德，当位富春秋。", "受天球。", "膺骏命，玉帛走诸候。", "宝阁珠楼临上苑，百卉弄春柔。", "隐约瀛洲。", "旦旦想宸游。", "那知羽驾忽难留。", "八马入丹邱。", "哀仗出神州。", "笳声凝咽，旌旗去悠悠。", "碧山头。", "真人地，龟洛奥，凤台幽。", "绕伊流。", "嵩峰冈势结蛟虬。", "皇堂一闭威颜杳，寒雾带天愁。", "守陵嫔御，想像奉龙輈。", "牙盘赭案肃神休。", "何日觌云裘。", "红泪滴衣褠。", "那堪风点缀、柏城秋。"]'),
('song-ci-982','导引','无名氏','宋','宋词','song-ci','导引','[]','上林寒早，仙仗转郊圻。',59,'宋词/ci.song.19000.json','["上林寒早，仙仗转郊圻。", "笳鼓入云悲。", "逶迤辇路过西池。", "楼阁锁参差。", "都人瞻望意如疑。", "犹想翠华归。", "玉京传信杳无期。", "空掩赭黄衣。"]'),
('song-ci-983','六州','无名氏','宋','宋词','song-ci','六州','[]','承圣绪，垂意在升平。',170,'宋词/ci.song.19000.json','["承圣绪，垂意在升平。", "驱貔虎，策豪英。", "号令肃天兵。", "四方无复羽书征。", "德泽浸群生。", "睿谋雄俊，绌汉高狭陋，慕三皇二帝，登闳缉乐缀文明。", "将升岱狱告功成。", "玉牒金绳。", "腾宝飞声。", "事难评。", "轩鼎就、清都一梦俄顷。", "飞霞佩，乘龙驭，羽卫入高清。", "祥光浮动五色，迎鸾凤，杂箫笙。", "因山功就，同轨人至，铭旌画翣，行背重城。", "楚笳凝咽，汉仪雄盛，攀慕伤情。", "惟馀内传，知向蓬瀛。"]'),
('song-ci-984','十二时・忆少年','无名氏','宋','宋词','song-ci','十二时・忆少年','[]','太平时。',182,'宋词/ci.song.19000.json','["太平时。", "御华夷。", "躬听断破危疑。", "春秋鼎盛，绌声乐游嬉。", "日升繁机。", "长驾远驭垂。", "意在轩羲。", "恢六典、斥三垂。", "有殊尤绝迹，盛德魄周施。", "方将缀缉声诗。", "扩皇纲，明帝典，绍累圣重熙。", "高拱无为。", "事难知。", "春色盛，逼千秋嘉节，忽闻玉几。", "颁命彤闱。", "厌世御云归。", "翊翠凤，驾文螭。", "缥缈难追。", "侍臣宫女，但攀慕号悲。", "玉轮动，指嵩伊。", "龙镳日益远空游，汉庙冠衣。", "惟盛德巍巍。", "镂玉册，传青史。", "昭示无期。"]'),
('song-ci-985','虞神・虞神歌','无名氏','宋','宋词','song-ci','虞神・虞神歌','[]','复土初。',170,'宋词/ci.song.19000.json','["复土初。", "明旌下储胥。", "回虚仗，箫笳互奏，旌旆随驱。", "岂知飚御在蓬壶。", "道萦纡。", "风日惨、六马踌躇。", "留恨满山隅。", "不堪回首，翠柏已扶疏。", "帝城渐迩，愁雾锁天衢。", "公卿百辟，鳞集云敷。", "迓龙舆。", "端门辟，金碧凌虚。", "此时远帝都。", "严清庙，入空时升，文物灿烂极嘉娱。", "配三宗，号称神，古所无。", "帝德协庙虞。", "九歌毕奏斐然殊。", "会轩朱。", "神具燕喜，锡福集皇居。", "更千万祀，佑启邦图。"]'),
('song-ci-986','导引','无名氏','宋','宋词','song-ci','导引','[]','岁华婉娩，侍宴玉皇宫。',59,'宋词/ci.song.19000.json','["岁华婉娩，侍宴玉皇宫。", "雕辇出房中。", "岂知轩后丹成去，望绝鼎湖龙。", "寿原初掩九虞终。", "归跸五云重。", "惟馀宝册书鸿烈，清庙配三宗。"]'),
('song-ci-987','导引','无名氏','宋','宋词','song-ci','导引','[]','来嫔初载，令德冠层城。',59,'宋词/ci.song.19000.json','["来嫔初载，令德冠层城。", "柔范蔼徽声。", "熊罴梦应芳兰郁，佳气拥雕楹。", "珠宫缥缈泛蓬瀛。", "脱屣世缘轻。", "空馀宝册光琼玖，千古仰鸿名。"]'),
('song-ci-988','导引','无名氏','宋','宋词','song-ci','导引','[]','柔容懿范，蚤岁蔼层闱。',59,'宋词/ci.song.19000.json','["柔容懿范，蚤岁蔼层闱。", "兰梦结芳时。", "秋风一夜惊罗幕，鸾扇影空回。", "荣追褘翟盛威仪。", "遗像掩瑶扉。", "春来只有芭蕉叶，依旧倚晴晖。"]'),
('song-ci-989','导引','无名氏','宋','宋词','song-ci','导引','[]','云軿芝盖，仙路去难攀。',59,'宋词/ci.song.19000.json','["云軿芝盖，仙路去难攀。", "海浪溅三山。", "重迎遗像临驰道，远似在人间。", "西宫瑶殿指坤元。", "璇榜从飞鸾。", "移升宝殿从新诏，盛典永流传。"]'),
('song-ci-990','导引','无名氏','宋','宋词','song-ci','导引','[]','蓬莱邃馆金碧照三山。',58,'宋词/ci.song.19000.json','["蓬莱邃馆金碧照三山。", "真境胜人间。", "秋风又见芭蕉长，遗迹在人寰。", "云轩一去杳难攀。", "斑竹彩舆还。", "深宫旧监闻箫鼓，怅望惨朱颜。"]'),
('song-ci-991','导引','无名氏','宋','宋词','song-ci','导引','[]','圣皇巡狩，清跸驻三吴。',59,'宋词/ci.song.19000.json','["圣皇巡狩，清跸驻三吴。", "十世嗣瑶图。", "边尘不动干戈戢，文德溥天敷。", "灰飞缇室气潜嘘。", "郊见紫坛初。", "归来赦令楼前下，喜气溢寰区。"]'),
('song-ci-992','六州','无名氏','宋','宋词','song-ci','六州','[]','双凤落，佳气蔼龙山。',164,'宋词/ci.song.19000.json','["双凤落，佳气蔼龙山。", "澄江左，清湖右，日夜海潮翻。", "因吉地、卜筑圜坛。", "宏基隆陛级，神位周环。", "边陲静、挂起櫜鞬。", "奠枕海隅安。", "三年亲祀，一阳初动，虔修大报，高处紫烟燔。", "看鸣銮，钩陈肃，天仗转，朔风寒。", "孤竹管，云和瑟，乐奏彻天关。", "嘉笾荐、玉奠璵璠。", "奉神欢。", "九霄瑞气起祥烟。", "来如风马欻然。", "还留福，已滋繁。", "回龙驭，升丹阙，布皇泽，春色满人间。"]'),
('song-ci-993','十二时・忆少年','无名氏','宋','宋词','song-ci','十二时・忆少年','[]','日将旦、阴曀潜消。',154,'宋词/ci.song.19000.json','["日将旦、阴曀潜消。", "天宇扇祥飚。", "边陲静谧，夜熄鸣刁。", "文教普旁昭。", "兴太学、多士舒翘。", "奉宗祧。", "新庙榜宸毫。", "配侑享於郊。", "慈宁万寿，四海仰东朝。", "男女正，中壶至桃夭。", "年屡稔，漕舟衔尾夥，高廪接楹饶。", "庙堂自有、擎天一柱，功比汉庭萧。", "多少群工同德，俊乂旁招。", "吉祥诸福集，燮理四时调。", "三年郊见，六变奏咸韶。", "望云霄。", "降福与唐尧。"]'),
('song-ci-994','奉礼歌','无名氏','宋','宋词','song-ci','奉礼歌','[]','苍苍天色是还非。',174,'宋词/ci.song.19000.json','["苍苍天色是还非。", "视下应疑。", "亦若斯。", "统元气，覆无私。", "四时寒暑推移。", "物蕃滋。", "造化有谁知。", "严大报，反本始，礼重祀神祈。", "律管灰吹。", "黄宫动，阳来复，景长时。", "车陈法驾，仗列黄麾。", "帝心祗。", "紫霄霁，霜华薄，星烂明垂。", "祥烟起，纷敷浮衮冕，六变笙镛迭奏，一诚币玉交持。", "宫漏声迟。", "千官显相多仪。", "百神嬉。", "风马云车，来止来绥。", "诞降纯禧。", "受神策、万年无极，歌颂昊天，成命周诗。"]'),
('song-ci-995','降仙台','无名氏','宋','宋词','song-ci','降仙台','[]','升烟既罢，良夜未晓，天步下神邱。',121,'宋词/ci.song.19000.json','["升烟既罢，良夜未晓，天步下神邱。", "锵锵鸣玉佩，炜炜照金莲，杳蔼云裘。", "彩仗初转，回龙驭、旌旆悠悠。", "星影疏动与天流。", "漏尽五更筹。", "大明升，东海头。", "杲杲灵曜，倒影射旗旒。", "辇路具修。", "葱郁瑞光浮。", "归来双阙看御楼。", "有仙鹤、衔书赦囚。", "万方喜气，均祉福，播歌讴。"]'),
('song-ci-996','导引','无名氏','宋','宋词','song-ci','导引','[]','春融日暖，四野瑞烟浮。',118,'宋词/ci.song.19000.json','["春融日暖，四野瑞烟浮。", "柳菀更桑柔。", "土膏脉起条风扇，宿雪润田畴。", "金根毂转如雷动，羽卫拥貌貅。", "扶携老稚康衢满，延跂望凝旒。", "斗移星转，一气又环周。", "六府要时修。", "务农重谷人胥劝，耕籍礼殊尤。", "坛壝岳峙文明地，黛耜驾青牛。", "雍容南亩三推了，玉趾更迟留。"]'),
('song-ci-997','六州','无名氏','宋','宋词','song-ci','六州','[]','昭圣武，不战屈人兵。',157,'宋词/ci.song.19000.json','["昭圣武，不战屈人兵。", "干戈戢，烽燧息，海宇清宁。", "民丰业，歌咏升平。", "愿咸归畎亩，力穑为甿。", "经界正、东作西成。", "农务轸皇情。", "躬亲耒耜，相劝深耕。", "人心感悦，击壤沸欢声。", "乘鸾辂，羽旗彩仗鲜明。", "传清跸，行黄道，缇骑出重城。", "仰瞻日表，映朱紘。", "环佩更锵鸣。", "百执公卿。", "不辞染履意专精。", "准拟奉粢盛。", "田多稼，风行遐迩，家家给足，胥庆三登。"]'),
('song-ci-998','十二时・忆少年','无名氏','宋','宋词','song-ci','十二时・忆少年','[]','临寰宇，恭已岩廊。',154,'宋词/ci.song.19000.json','["临寰宇，恭已岩廊。", "属意在耕桑。", "爱民利物，德迈陶唐。", "跻俗尽淳庞。", "开千亩、帝籍神仓。", "举彝章。", "祗祓坛场。", "为农事祈祥。", "涓辰行礼，节物值春阳。", "罄齐庄。", "明德荐馨香。", "宫禁邃，嫔妃并御侍，穜稑献君王。", "中闱表率，阴教逾光。", "帐殿霭熉黄。", "梐枑设、翠幕高张。", "庆云翔。", "樽罍陈酒醴，金石奏宫商。", "神灵感格，岁岁富仓箱。", "庆明昌。", "行旅不赍粮。"]'),
('song-ci-999','奉礼歌','无名氏','宋','宋词','song-ci','奉礼歌','[]','吾皇端立太平基。',171,'宋词/ci.song.19000.json','["吾皇端立太平基。", "奉祀肃雍、格神祈。", "抚御耦，降嘉种何辞。", "手览洪縻。", "命太史视日，祗告前期。", "验穹象，天田入望更光辉。", "掌礼陈仪。", "搜钜典，迎春令，颁宣温诏遍九围。", "人尽熙熙。", "仰明时。", "俨垂衣。", "佳气氤氲表庞禧。", "丰年屡，大田生异粟，含滋吐秀，九种传图，尽来丹阙，瑞应昌时。", "享运正当摄提。", "伫见咏京坻。", "躬稼穑，重耘耔。", "盛礼兴行先百姓，崇本业，忧勤如禹稷，播在声诗。"]'),
('song-ci-0','渔家傲','黄裳','宋','宋词','song-ci','渔家傲','[]','汗漫金华寒委地。',72,'宋词/ci.song.2000.json','["汗漫金华寒委地。", "火云散尽奇峰势。", "纨扇团圆休与比。", "犹可喜。", "恩情不怕凉飙至。", "梦冷魂高何处寄。", "琉璃砌上笼人睡。", "逃暑广寒宫似水。", "缘有累。", "乘风却下人间世。"]'),
('song-ci-1','渔家傲','黄裳','宋','宋词','song-ci','渔家傲','[]','人在月中宵汉远。',72,'宋词/ci.song.2000.json','["人在月中宵汉远。", "仙槎乘得秋风便。", "寒信已归砧上练。", "衣未翦。", "疏窗空引相思怨。", "须信婵娟尤有恋。", "轻飞叶上清光转。", "寒菊枝头笼婉娈。", "人初宴。", "新妆更学铅华浅。"]'),
('song-ci-2','渔家傲','黄裳','宋','宋词','song-ci','渔家傲','[]','三月秋光今夜半。',72,'宋词/ci.song.2000.json','["三月秋光今夜半。", "一年人爱今回满。", "莫放笙歌容易散。", "须同玩。", "姮娥解笑人无伴。", "抱尽金精来碧汉。", "醉吟莫作寻常看。", "已过中天欢未断。", "还同叹。", "时情已向明朝换。"]'),
('song-ci-3','蓦山溪','葛胜仲','宋','宋词','song-ci','蓦山溪','[]','出门西笑。',102,'宋词/ci.song.2000.json','["出门西笑。", "千里长安道。", "不用引离声，便登荣、十洲三岛。", "画船珠箔，苹末水风凉，随柳岸，楚台人，景与人俱好。", "应嗟见晚，玉殿生清晓。", "正是妙年时，步承明、谋身须早。", "轺车肤使，新逐凯歌回，恩绋重，彩衣轻，嘉庆知多少。"]'),
('song-ci-4','西江月','葛胜仲','宋','宋词','song-ci','西江月','[]','艳曲醉歌金缕，朱门高耸铜环。',58,'宋词/ci.song.2000.json','["艳曲醉歌金缕，朱门高耸铜环。", "中天楼观共跻攀。", "飞絮落花春晚。", "低映绿阴朱户，斜拖素练沧湾。", "银钩华榜五云间。", "奕奕蛟龙字绾。"]'),
('song-ci-5','西江月','葛胜仲','宋','宋词','song-ci','西江月','[]','靺鞨斜红带柳，琉璃涨绿平桥。',58,'宋词/ci.song.2000.json','["靺鞨斜红带柳，琉璃涨绿平桥。", "人在花月见新妖。", "不数江南苏小。", "恨寄飞花蔌蔌，情随流水迢迢。", "鲤鱼风送木兰桡。", "回棹荒鸡报晓。"]'),
('song-ci-6','西江月','葛胜仲','宋','宋词','song-ci','西江月','[]','清樾已生昼寂，孤花尚表春馀。',58,'宋词/ci.song.2000.json','["清樾已生昼寂，孤花尚表春馀。", "象床筠簟燕堂虚。", "初过晚凉微雨。", "圭璧新来北苑，鲈鱼未减东吴。", "捧觞红袖透香肤。", "不浥翔龙烟缕。"]'),
('song-ci-7','西江月','葛胜仲','宋','宋词','song-ci','西江月','[]','瑞兽香云轻袅，华堂绣幕低垂。',58,'宋词/ci.song.2000.json','["瑞兽香云轻袅，华堂绣幕低垂。", "人生七十尚为稀。", "况是钓璜新岁。", "登俎青梅的皪，明阑红药芳菲。", "天教眉寿过期颐。", "常对风光沈醉。"]'),
('song-ci-8','浣溪沙','葛胜仲','宋','宋词','song-ci','浣溪沙','[]','楼子包金照眼新。',48,'宋词/ci.song.2000.json','["楼子包金照眼新。", "香根犹带广陵尘。", "翻阶不羡掖垣春。", "不分与花为近侍，难甘溱洧赠闲人。", "如羞如怨独含颦。"]'),
('song-ci-9','虞美人','葛胜仲','宋','宋词','song-ci','虞美人','[]','三年曾不窥园树。',66,'宋词/ci.song.2000.json','["三年曾不窥园树。", "辛苦萤窗暮。", "怪来文誉满清时。", "柿叶书残犹自、日临池。", "春秋新学卑繁露。", "黄卷聊堪语。", "家人不用寄龟诗。", "行看升平楼外、化龙归。"]'),
('song-ci-10','虞美人','葛胜仲','宋','宋词','song-ci','虞美人','[]','一轮丹桂窅窊树。',66,'宋词/ci.song.2000.json','["一轮丹桂窅窊树。", "光景疑非暮。", "天公著意在兹时。", "扫尽微云点缀、展清池。", "樽前金奏无晨露。", "只有君房语。", "骊驹客莫赋归诗。", "东道留连应赋、不庸归。"]'),
('song-ci-11','瑞鹧鸪','葛胜仲','宋','宋词','song-ci','瑞鹧鸪','[]','火云欲避金风至。',64,'宋词/ci.song.2000.json','["火云欲避金风至。", "秀气充闾初降瑞。", "去家丁令却归来，还燕悬弧当日地。", "金章紫绶身荣贵。", "寿福天储昌又炽。", "怪来一岁四迁官，还过当生元太岁。"]'),
('song-ci-12','鹊桥仙','葛胜仲','宋','宋词','song-ci','鹊桥仙','[]','鹊桥仙偶，天津轻渡，却笑嫦娥孤皎。',68,'宋词/ci.song.2000.json','["鹊桥仙偶，天津轻渡，却笑嫦娥孤皎。", "平时五夜似经年，问何事、今宵便晓。", "云车将驾，神夫留恋，更吐心期多少。", "支机休浪与闲人，莫倚赖、芳心素巧。"]'),
('song-ci-13','江城子','葛胜仲','宋','宋词','song-ci','江城子','[]','浮家重过水晶宫。',86,'宋词/ci.song.2000.json','["浮家重过水晶宫。", "五年中。", "事何穷。", "无恙山溪，鬟影落青铜。", "欲向旧游寻旧事，云散彩，水流东。", "苔花向我似情锺。", "舞霜风。", "雪濛濛。", "应怪史君，颜鬓便衰翁。", "赖是寻芳无素约，端不恨，绿阴重。"]'),
('song-ci-14','江城子','葛胜仲','宋','宋词','song-ci','江城子','[]','飞身疑到广寒宫。',86,'宋词/ci.song.2000.json','["飞身疑到广寒宫。", "玉花中。", "兴何穷。", "酒贵旗亭，谁是惜青铜。", "飘瞥三无真妙绝，银万里，失西东。", "草堂红蜡暖歌锺。", "卷帘风。", "赏空濛。", "丰颊修眉，鹤氅拥仙翁。", "欲作氍毹花底客，清漏永，禁城重。"]'),
('song-ci-15','蝶恋花','葛胜仲','宋','宋词','song-ci','蝶恋花','[]','安石榴花浓绿映。',70,'宋词/ci.song.2000.json','["安石榴花浓绿映。", "解愠风轻，乍改朱明令。", "衮绣元臣门户盛。", "童孙此日悬弧庆。", "夜宴华堂添酒兴。", "□□除书，远带天香剩。", "欲浥苕波供续命。", "不须龙护江心镜。"]'),
('song-ci-16','南乡子','葛胜仲','宋','宋词','song-ci','南乡子','[]','晴日乱云收。',66,'宋词/ci.song.2000.json','["晴日乱云收。", "人在苹香柳恽洲。", "溪上清风楼上醉，飕飕。", "共折黄花插满头。", "佳客献还酬。", "不负山城九日秋。", "苕碧下青供酩酊，休休。", "楚客当年浪自愁。"]'),
('song-ci-17','南乡子','葛胜仲','宋','宋词','song-ci','南乡子','[]','拂槛晓云鲜。',66,'宋词/ci.song.2000.json','["拂槛晓云鲜。", "销暑楼危竦半天。", "曾是携宾当荐九，开筵。", "度水萦山奏管弦。", "黄菊映华颠。", "千骑重来已六年。", "楼下东流当日水，依然。", "更对周旋旧七贤。"]'),
('song-ci-18','减字木兰花','葛胜仲','宋','宋词','song-ci','减字木兰花','[]','葛山仙隐。',52,'宋词/ci.song.2000.json','["葛山仙隐。", "尚有馀膏留旧鼎。", "十里梅花。", "夹道争看衮绣华。", "人间妙丽。", "并侍黄扉开国贵。", "僻壤孤芳。", "羞涩尊前不敢香。"]'),
('song-ci-19','临江仙','葛胜仲','宋','宋词','song-ci','临江仙','[]','倦客身同舟不系，轻帆来访儒仙。',70,'宋词/ci.song.2000.json','["倦客身同舟不系，轻帆来访儒仙。", "春风元巳艳阳天。", "夭桃芳散锦，高柳欲飞绵。", "千古海昌佳绝地，双凫暂此留连。", "通宵娱客破芳尊。", "兰亭修禊事，梓泽醉名园。"]'),
('song-ci-20','临江仙','葛胜仲','宋','宋词','song-ci','临江仙','[]','宝观岧嶢飞雉堞，登临恍欲升仙。',70,'宋词/ci.song.2000.json','["宝观岧嶢飞雉堞，登临恍欲升仙。", "野桃官柳衬吴天。", "春风寒食夜，遗恨在封绵。", "闻道东溟才二里，银涛直与天连。", "凭谁都卷入芳尊。", "赋归欢靖节，消渴解文园。"]'),
('song-ci-21','减字木兰花','葛胜仲','宋','宋词','song-ci','减字木兰花','[]','辛勤场屋。',52,'宋词/ci.song.2000.json','["辛勤场屋。", "未遇知音甘陆陆。", "诏录遗忠。", "一札天书下九重。", "鹅城初命。", "此去青云应渐近。", "解褐恩新。", "今岁吾家第四人。"]'),
('song-ci-22','减字木兰花','葛胜仲','宋','宋词','song-ci','减字木兰花','[]','杏花零乱。',52,'宋词/ci.song.2000.json','["杏花零乱。", "拟把百觚来判断。", "病卧漳滨。", "不见枝头闹小春。", "吾衰老矣。", "一醉花前犹不遂。", "情绪厌厌。", "虚度韶光又一年。"]'),
('song-ci-23','虞美人','葛胜仲','宋','宋词','song-ci','虞美人','[]','严陵滩畔香醪好。',66,'宋词/ci.song.2000.json','["严陵滩畔香醪好。", "遮莫东方晓。", "春风盎盎如寒肌。", "人道霜浓腊月、我还疑。", "红炉火热香围坐。", "梅蕊迎春破。", "一声清唱解人颐。", "人道牢愁千斛、我谁知。"]'),
('song-ci-24','鹧鸪天','葛胜仲','宋','宋词','song-ci','鹧鸪天','[]','玉琯还飞换岁灰。',64,'宋词/ci.song.2000.json','["玉琯还飞换岁灰。", "定山新棹酒船回。", "年时梁燕双双在，肯为人愁便不来。", "衰意绪，病情怀。", "玉山今夜为谁颓。", "年时梅蕊垂垂破，肯为人愁便不开。"]'),
('song-ci-25','西江月','葛胜仲','宋','宋词','song-ci','西江月','[]','万卷旧推鸿博，一官且慰蹉跎。',58,'宋词/ci.song.2000.json','["万卷旧推鸿博，一官且慰蹉跎。", "升平楼下赐危科。", "曾对顒昂黼坐。", "燕颔从来骨贵，鸾栖尚屈才多。", "今宵且共入无何。", "定远功名幺麽。"]'),
('song-ci-26','浪淘沙','葛胜仲','宋','宋词','song-ci','浪淘沙','[]','我爱菊花枝。',64,'宋词/ci.song.2000.json','["我爱菊花枝。", "浥露偏宜。", "旋移佳种一年期。", "照眼黄金三径烂，可但东篱。", "秋老摘花吹。", "敢恨开迟。", "只愁一夜便香衰。", "待插满头年大也，且泛芳卮。"]'),
('song-ci-27','鹧鸪天','葛胜仲','宋','宋词','song-ci','鹧鸪天','[]','黄菊鲜鲜带露浓。',64,'宋词/ci.song.2000.json','["黄菊鲜鲜带露浓。", "小园开遍度香风。", "自篘玉酝酬秋色，旋洗霜须对晚丛。", "香在手，莫匆匆。", "寻芳今夜有人同。", "黄金委地新收得，莫道山翁到底穷。"]'),
('song-ci-28','鹧鸪天','葛胜仲','宋','宋词','song-ci','鹧鸪天','[]','采采黄花鹄彩浓。',64,'宋词/ci.song.2000.json','["采采黄花鹄彩浓。", "吹开一夜为霜风。", "已邀骚客陶元亮，不用歌妓盛小丛。", "秋易老，莫匆匆。", "齐山高兴古今同。", "欲知此地花多少，一眼金英望不穷。"]'),
('song-ci-29','木兰花・玉楼春','葛胜仲','宋','宋词','song-ci','木兰花・玉楼春','[]','谈围曾蔽青绫帐。',64,'宋词/ci.song.2000.json','["谈围曾蔽青绫帐。", "林下中年敦素尚。", "烟波偶趁一帆风，却锁云扃来就养。", "自从悟得空无相。", "身把虚空来作样。", "大千沙界抹为尘，未比无生真寿量。"]'),
('song-ci-30','醉花阴','葛胜仲','宋','宋词','song-ci','醉花阴','[]','东皇已有来归耗。',62,'宋词/ci.song.2000.json','["东皇已有来归耗。", "十里青山道。", "冻蘖万株梅，一夜妆成，似趁鸣鸡早。", "年时清赏曾同到。", "先仗游蜂报。", "抖擞旧心情，一笑酬春，不羡和羹诏。"]'),
('song-ci-31','浣溪沙','葛胜仲','宋','宋词','song-ci','浣溪沙','["\u897f\u6e56"]','东阁郎官巧写真。',48,'宋词/ci.song.2000.json','["东阁郎官巧写真。", "西湖处士妙传神。", "嫣然一笑腊前春。", "斗好虽无冰骨女，相宜幸是雪髯人。", "且烦疏影入清尊。"]'),
('song-ci-32','浣溪沙','葛胜仲','宋','宋词','song-ci','浣溪沙','[]','盘里明珠芡实香。',48,'宋词/ci.song.2000.json','["盘里明珠芡实香。", "尊前堆雪脍丝长。", "何妨羌管奏伊凉。", "翠葆重生无复日，白波不釂有如江。", "壁间醉墨任淋浪。"]'),
('song-ci-33','临江仙','葛胜仲','宋','宋词','song-ci','临江仙','[]','二月风光浓似酒，小楼新湿青红。',70,'宋词/ci.song.2000.json','["二月风光浓似酒，小楼新湿青红。", "碧琉璃色映群峰。", "更携金凿落，来赏锦薰笼。", "调客旧留□月旦，此花清软纤秾。", "未饶兰蕙转光风。", "赤阑呈雅艳，翠幕护芳丛。"]'),
('song-ci-34','临江仙','葛胜仲','宋','宋词','song-ci','临江仙','[]','雪壁歌词题尚湿，春风又见轻红。',70,'宋词/ci.song.2000.json','["雪壁歌词题尚湿，春风又见轻红。", "一枝斜插映头峰。", "不辞连夜赏，银烛透纱笼。", "白发欺人今老矣，尊前羞见繁秾。", "清香尤嫪虎溪风。", "海棠须避席，佳种谩蚕丛。"]'),
('song-ci-35','浣溪沙','葛胜仲','宋','宋词','song-ci','浣溪沙','[]','一夜狂风尽海棠。',48,'宋词/ci.song.2000.json','["一夜狂风尽海棠。", "此花天遣殿群芳。", "芝兰百濯见真香。", "劝客淋浪灯底韵，恼人魂梦枕边囊。", "一枝插不□□□。"]'),
('song-ci-36','鹊桥仙','葛胜仲','宋','宋词','song-ci','鹊桥仙','[]','凉飙破暑，清歌萦坐，缺月稀星庭户。',68,'宋词/ci.song.2000.json','["凉飙破暑，清歌萦坐，缺月稀星庭户。", "瓜华草草具杯盘，喜共浥、初筵零露。", "天孙东处，牵牛西望，劝汝一杯清醑。", "精灵何必待秋通，为一洗、朦胧今古。"]'),
('song-ci-37','临江仙','葛胜仲','宋','宋词','song-ci','临江仙','[]','槛外奇葩江外种，娇春未减酲红。',70,'宋词/ci.song.2000.json','["槛外奇葩江外种，娇春未减酲红。", "画楼晴日敛云峰。", "佛香来海岸，蜀锦荐灯笼。", "今夜那忧杀风景，酒花来斗妖浓。", "江梅冷淡避春风。", "明朝来纵赏，应醉绮罗丛。"]'),
('song-ci-38','蝶恋花','葛胜仲','宋','宋词','song-ci','蝶恋花','[]','二月春游须烂漫。',70,'宋词/ci.song.2000.json','["二月春游须烂漫。", "秉烛看花，只为晨曦短。", "高举蜡薪通夕看。", "红光万丈腾天半。", "寄语平时游冶伴。", "不负分阴，胜事输今段。", "灯火休催归小院。", "殷勤更照桃花面。"]'),
('song-ci-39','蝶恋花','葛胜仲','宋','宋词','song-ci','蝶恋花','[]','只恐深夜花睡去。',70,'宋词/ci.song.2000.json','["只恐深夜花睡去。", "火照红妆，满意留宾住。", "凤烛千枝花四顾。", "消愁更待寻何处。", "汉苑红光非浪语。", "栖静亭前，都是珊瑚树。", "便请催尊鸣釂鼓。", "明朝风恶飘红雨。"]'),
('song-ci-40','蝶恋花','葛胜仲','宋','宋词','song-ci','蝶恋花','[]','百紫千红今烂熳。',70,'宋词/ci.song.2000.json','["百紫千红今烂熳。", "举烛辉花，莫厌烧令短。", "酒里逢花须细看。", "人生谁似英雄半。", "安得红颜为老伴。", "妙舞花前，杨柳夸身段。", "已倒玉山回竹院。", "清香不断风吹面。"]'),
('song-ci-41','蝶恋花','葛胜仲','宋','宋词','song-ci','蝶恋花','[]','已过春分春欲去。',70,'宋词/ci.song.2000.json','["已过春分春欲去。", "千炬花间，作意留春住。", "一曲清歌无误顾。", "绕梁馀韵归何处。", "尽日劝春春不语。", "红气蒸霞，且看桃千树。", "才子霏谈更五鼓。", "剩看走笔挥风雨。"]'),
('song-ci-42','浪淘沙','葛胜仲','宋','宋词','song-ci','浪淘沙','[]','又见菊花新。',64,'宋词/ci.song.2000.json','["又见菊花新。", "色浅香匀。", "老人衰病卧漳滨。", "虽是无聊仍止酒，幸有嘉宾。", "不用怨萧辰。", "不似芳春。", "请看金蕊照金尊。", "今夜花前须醉倒，直到黎明。"]'),
('song-ci-43','浪淘沙','葛胜仲','宋','宋词','song-ci','浪淘沙','["\u592a\u6e56"]','歌阕斗清新。',64,'宋词/ci.song.2000.json','["歌阕斗清新。", "檀板初匀。", "画堂新筑太湖滨。", "好是黄花开应候，聊宴亲宾。", "上客即逢辰。", "况是青春。", "上林开宴锡尧尊。", "今夜素娥真解事，偏向人明。"]'),
('song-ci-44','浪淘沙','葛胜仲','宋','宋词','song-ci','浪淘沙','[]','娱老小亭新。',64,'宋词/ci.song.2000.json','["娱老小亭新。", "丹垩初匀。", "万枝金菊绕溪滨。", "折向华堂遮醉眼，聊用娱宾。", "红烛夜香辰。", "广坐生春。", "月波新酿入芳尊。", "好向花前拚烂醉，不负承明。"]'),
('song-ci-45','南乡子','葛胜仲','宋','宋词','song-ci','南乡子','[]','秋水莹精神。',66,'宋词/ci.song.2000.json','["秋水莹精神。", "靖节先生太逼真。", "谈麈生风霏玉屑，津津。", "爽气泠然欲侵人。", "一座尽生春。", "满引琼觞已半醺。", "更把黄花寿彭祖，盈盈。", "数阕新声又遏云。"]'),
('song-ci-46','虞美人','葛胜仲','宋','宋词','song-ci','虞美人','[]','灵山法会何曾散。',66,'宋词/ci.song.2000.json','["灵山法会何曾散。", "此地神光满。", "丁公潭下百雷霆。", "疑是银河挽下、一齐倾。", "高桥飞观连云起。", "槛外惊湍水。", "大矶才过小矶来。", "应有天孙灵驭、月中回。"]'),
('song-ci-47','临江仙','米友仁','宋','宋词','song-ci','临江仙','[]','昨夜扁舟沙外舣，淮山微雨初晴。',70,'宋词/ci.song.2000.json','["昨夜扁舟沙外舣，淮山微雨初晴。", "断云飞过月还明。", "一天风露重，人在玉壶清。", "水际不知何许是，遥林□辨微青。", "醉迷归梦强□凌。", "谁言东去雁，解寄此时情。"]'),
('song-ci-48','小重山','米友仁','宋','宋词','song-ci','小重山','[]','醉倚朱阑一解衣。',70,'宋词/ci.song.2000.json','["醉倚朱阑一解衣。", "碧云迷望眼，断虹低。", "近来休说带宽围。", "人千里，还是燕双飞。", "深院日初迟。", "绮窗帘幕静，恨生眉。", "不堪虚度是花时。", "鸿来速，争解寄相思。"]'),
('song-ci-49','减字木兰花','米友仁','宋','宋词','song-ci','减字木兰花','[]','柳塘微雨。',52,'宋词/ci.song.2000.json','["柳塘微雨。", "两两飞鸥来复去。", "倚遍重阑。", "人在碧云山外山。", "一春离怨。", "日照绮窗长几线。", "酒病情魔。", "两事春来无奈何。"]'),
('song-ci-50','点绛唇','米友仁','宋','宋词','song-ci','点绛唇','[]','浩渺湖天，酒浮黄菊携佳侣。',50,'宋词/ci.song.2000.json','["浩渺湖天，酒浮黄菊携佳侣。", "澹烟疏雨。", "去鲁方怀土。", "倾盖相逢，引满哦奇语。", "山围处。", "兕觥频举。", "不醉君无去。"]'),
('song-ci-51','渔家傲','米友仁','宋','宋词','song-ci','渔家傲','[]','从古荆溪名胜地。',72,'宋词/ci.song.2000.json','["从古荆溪名胜地。", "溪光万顷琉璃翠。", "极望荷花三十里。", "香喷鼻。", "我舟日在花间舣。", "向晚馀霞收散绮。", "遥山抹黛天如水。", "满引一尊明月里。", "微风起。", "萧然真在华胥氏。"]'),
('song-ci-52','阮郎归','米友仁','宋','宋词','song-ci','阮郎归','[]','小舟载酒向平湖。',56,'宋词/ci.song.2000.json','["小舟载酒向平湖。", "新凉生晓初。", "乱山烟外有还无。", "王维真画图。", "风遽起，动襟裾。", "雨来荷溅珠。", "一尊相对喜君俱。", "醉归红袖扶。"]'),
('song-ci-53','临江仙','米友仁','宋','宋词','song-ci','临江仙','[]','一曲阳关肠断处，临风惨对离尊。',70,'宋词/ci.song.2000.json','["一曲阳关肠断处，临风惨对离尊。", "红妆揭调十分斟。", "古来多聚散，正似岭头云。", "昨夜晴霄千里月，向人无限多情。", "娟娟今夜满虚庭。", "一帆随浪去，却照画船轻。"]'),
('song-ci-54','宴桃源・如梦令','米友仁','宋','宋词','song-ci','宴桃源・如梦令','[]','蝶梦初回栩栩。',40,'宋词/ci.song.2000.json','["蝶梦初回栩栩。", "柳岸几声莺语。", "苹末起微风，山外一川烟雨。", "凝顾。", "凝顾。", "人在玉壶深处。"]'),
('song-ci-55','南歌子','米友仁','宋','宋词','song-ci','南歌子','[]','遇酒词先举，逢山眼暂明。',62,'宋词/ci.song.2000.json','["遇酒词先举，逢山眼暂明。", "一川风雨纵留人。", "不道此郎归兴、欲兼程。", "客久情深□，寻欢恨不能。", "绳床顿睡梦纵横。", "赖□□□□□、□□□。"]'),
('song-ci-56','渔家傲','米友仁','宋','宋词','song-ci','渔家傲','[]','郊外春和宜散步。',72,'宋词/ci.song.2000.json','["郊外春和宜散步。", "百花枝上初凝露。", "福地神仙多外府。", "藏奇趣。", "幽寻历遍溪边路。", "薄宦浮家无定处。", "萍飘梗泛前人语。", "与子未须乡国去。", "来同住。", "且看群岫烟中雨。"]'),
('song-ci-57','念奴娇','米友仁','宋','宋词','song-ci','念奴娇','[]','九秋气爽，正溪山雨过，茅檐清暇。',121,'宋词/ci.song.2000.json','["九秋气爽，正溪山雨过，茅檐清暇。", "篱菊妍英，知是为，佳节重阳开也。", "色妙香殊，匀浮瓯面，俗状卑金斝。", "歌狂饮俊，满簪还更盈把。", "村外草草杯盘，边尘不动，欲买应无价。", "端使晴霄风露冷，云卷烟收平野。", "向晚婵娟，半轮斜照，想见成清夜。", "玉山颓处，要看猗帽如画。"]'),
('song-ci-58','临江仙','米友仁','宋','宋词','song-ci','临江仙','[]','宝晋轩窗临望处，山围水绕林萦。',70,'宋词/ci.song.2000.json','["宝晋轩窗临望处，山围水绕林萦。", "不堪回首到江城。", "墙趺围瓦砾，鸥鹭见人惊。", "日愿太平归旧里，更无馀事关情。", "小营茅舍倚云汀。", "四时风月里，还我醉腾腾。"]'),
('song-ci-59','阮郎归','米友仁','宋','宋词','song-ci','阮郎归','[]','碧溪风动满文漪。',56,'宋词/ci.song.2000.json','["碧溪风动满文漪。", "雨馀山更奇。", "淡烟横处柳行低。", "鸳鸯来去飞。", "人似玉，醉如泥。", "一枝随鬓猗。", "夷犹双桨月平西。", "幽寻归路迷。"]'),
('song-ci-60','临江仙','米友仁','宋','宋词','song-ci','临江仙','[]','野外不堪无胜侣，笑谈安得君同。',70,'宋词/ci.song.2000.json','["野外不堪无胜侣，笑谈安得君同。", "四时景物一壶中。", "醉馀临望处，远岫数重重。", "溪上新荷初出水，花房半弄微红。", "晓风萧爽韵疏松。", "娟娟明月上，人在广寒宫。"]'),
('song-ci-61','念奴娇','米友仁','宋','宋词','song-ci','念奴娇','[]','阑干倚处。',120,'宋词/ci.song.2000.json','["阑干倚处。", "戏裁成、彭泽当年奇语。", "三径荒凉怀旧里，我欲扁舟归去。", "鸟倦知还，寓形宇内，今已年如许。", "小窗容膝，要寻情话亲侣。", "郭外粗有西畴，故园松菊，日涉方成趣。", "流水涓涓千涧上，云绕奇峰无数。", "窈窕经丘，风清月了，时看烟中雨。", "萧然巾岸，引觞寄傲衡宇。"]'),
('song-ci-62','醉春风','米友仁','宋','宋词','song-ci','醉春风','[]','一阳来复群阴往。',62,'宋词/ci.song.2000.json','["一阳来复群阴往。", "吾道从今长。", "万事莫关情，月夕风前，依旧须豪放。", "卿云舒卷浮青嶂。", "从古书珍赏。", "满引唱新词，春意看看，又到梅梢上。"]'),
('song-ci-63','小重山','米友仁','宋','宋词','song-ci','小重山','[]','雨过风来午暑清。',70,'宋词/ci.song.2000.json','["雨过风来午暑清。", "榴花红照眼，向人明。", "一枝低映宝钗横。", "菖蒲酒，玉碗十分斟。", "引满听新声。", "小轩帘半卷，远山青。", "几人闲处见闲情。", "醒还醉，为趣妙难名。"]'),
('song-ci-64','诉衷情','米友仁','宋','宋词','song-ci','诉衷情','[]','结庐人境羡陶潜。',54,'宋词/ci.song.2000.json','["结庐人境羡陶潜。", "车马不来喧。", "胜处自多真趣，飞鸟日相还。", "心既远，地仍偏。", "见南山。", "手持菊颖，山气常佳，欲辨忘言。"]'),
('song-ci-65','白雪','米友仁','宋','宋词','song-ci','白雪','[]','洞天昼永，正中和时候，凉飙初起。',122,'宋词/ci.song.2000.json','["洞天昼永，正中和时候，凉飙初起。", "羽扇纶巾，云流处，水绕山重云委。", "好雨新晴，绮霞明丽，全是丹青戏。", "豪攘横卷，楚天应解深秘。", "留滞。", "字学书林，折腰缘为米，无机涉世。", "投组归来欣自肆，目仰云霄醒醉。", "论少卑之，家声接武，月旦评吾子。", "凭高临望，桂轮徒共千里。"]'),
('song-ci-66','念奴娇','曾纡','宋','宋词','song-ci','念奴娇','[]','片帆暮落，正前村梅蕊，愁人如雪。',120,'宋词/ci.song.2000.json','["片帆暮落，正前村梅蕊，愁人如雪。", "东陌西溪长记得，疏影横斜时节。", "六出冰姿，玉人微步，笑里轻轻折。", "兰房沈醉，暗香曾共私窃。", "回头万水千山，一枝重见处，离肠千结。", "料想临鸾消瘦损，时把啼红偷浥。", "怎得伊来，许多幽恨，共拈青梢说。", "如今千里，断魂空对明月。"]'),
('song-ci-67','上林春・一落萦','曾纡','宋','宋词','song-ci','上林春・一落萦','[]','东苑梅繁，豪健放乐，醉倒花前狂客。',127,'宋词/ci.song.2000.json','["东苑梅繁，豪健放乐，醉倒花前狂客。", "靓妆微步，攀条弄粉，凌波遍寻青陌。", "暗香堕靥。", "更飘近、雾鬟蝉额。", "倒金荷、念流光易失，幽姿堪惜。", "惜花心、未甘鬓白。", "南枝上、又见寻芳消息。", "旧游回首，前欢如梦，谁知等闲抛掷。", "稠红乱蕊，漫开遍、楚江南北。", "独销魂，念谁寄、故园春色。"]'),
('song-ci-68','秋霁','曾纡','宋','宋词','song-ci','秋霁','[]','木落山明，暮江碧，楼倚太虚寥廓。',125,'宋词/ci.song.2000.json','["木落山明，暮江碧，楼倚太虚寥廓。", "素手飞觞，钗头笑取，金英满浮桑落。", "鬓云慢约。", "酒红拂破香腮薄。", "细细酌。", "帘外任教、月转画阑角。", "当年快意登临，异乡节物，难禁离索。", "故人远、凌波何在，惟有残英共寂寞。", "愁到断肠无处著。", "寄寒香与，凭渠问讯佳时，弄粉吹花，为谁梳掠。"]'),
('song-ci-69','念奴娇','曾纡','宋','宋词','song-ci','念奴娇','[]','江城春晚，正海棠临水，嫣然幽独。',121,'宋词/ci.song.2000.json','["江城春晚，正海棠临水，嫣然幽独。", "秀色天姿真富贵，何必金盘华屋。", "月下无人，雨中有泪，绝艳仍清淑。", "丰肌得酒，嫩红微透轻縠。", "晓日雾霭林深，佳人春睡思，朦胧初足。", "笑出疏篱，端可厌，桃李漫山粗俗。", "衔子飞来，鸿鹄何在，千里移西蜀。", "明朝酒醒，乱红那忍轻触。"]'),
('song-ci-70','洞仙歌','曾纡','宋','宋词','song-ci','洞仙歌','[]','相如当日，曾奏凌云赋。',101,'宋词/ci.song.2000.json','["相如当日，曾奏凌云赋。", "落笔纵横妙风雨。", "记扬鞭辇路，同醉金明，穷胜赏，不管重城已暮。", "旧游如梦觉，零落朋侪，遗墨淋漓尚如故。", "况神洲北望，今已丘墟，伤白璧、久埋黄土。", "但空似、灵光岿然存，怅朗月清风，更无玄度。"]'),
('song-ci-71','临江仙','曾纡','宋','宋词','song-ci','临江仙','[]','后院短墙临绿水，春风急管繁弦。',70,'宋词/ci.song.2000.json','["后院短墙临绿水，春风急管繁弦。", "问谁亲按小婵娟。", "玉堂真学士，琳馆地行仙。", "安得此身来此处，依稀一梦梨园。", "江南刺使谩垂涎。", "据鞍肠已断，何况到尊前。"]'),
('song-ci-72','菩萨蛮','曾纡','宋','宋词','song-ci','菩萨蛮','[]','山光冷浸清溪底。',52,'宋词/ci.song.2000.json','["山光冷浸清溪底。", "溪光直到柴门里。", "卧对白苹洲。", "猗眠数钓舟。", "溪山无限好。", "恨不相逢早。", "老病独醒多。", "如此良夜何。"]'),
('song-ci-73','谒金门','曾纡','宋','宋词','song-ci','谒金门','[]','风淅沥。',53,'宋词/ci.song.2000.json','["风淅沥。", "窗外雪花初积。", "梦破小窗人寂寂。", "寒威无处敌。", "强起饮君涓滴。", "清泪醉来沾臆。", "歧路即今多拥隔。", "弟兄无信息。"]'),
('song-ci-74','品令','曾纡','宋','宋词','song-ci','品令','[]','纹漪涨绿。',77,'宋词/ci.song.2000.json','["纹漪涨绿。", "疏霭连孤鹜。", "一年春事，柳飞轻絮，笋添新竹。", "寂寞幽花，独殿小园嫩绿。", "登临未足。", "怅游子、归期促。", "他年清梦千里，犹到城阴溪曲。", "应有凌波，时为故人凝目。"]'),
('song-ci-75','失调名','秦湛','宋','宋词','song-ci','失调名','[]','藕叶清香胜花气。',8,'宋词/ci.song.2000.json','["藕叶清香胜花气。"]'),
('song-ci-76','卜算子','秦湛','宋','宋词','song-ci','卜算子','[]','春透水波明，寒峭花枝瘦。',52,'宋词/ci.song.2000.json','["春透水波明，寒峭花枝瘦。", "极目烟中百尺楼，人在楼中否。", "四和袅金凫，双陆思纤手。", "拟倩东风浣此情，情更浓於酒。"]'),
('song-ci-77','木兰花慢','范周','宋','宋词','song-ci','木兰花慢','[]','美兰堂昼永，晏清暑、晚迎凉。',126,'宋词/ci.song.2000.json','["美兰堂昼永，晏清暑、晚迎凉。", "控水槛风帘，千花竞拥，一朵偏双。", "银塘。", "尽倾醉眼，讶湘娥、倦倚两霓裳。", "依约凝情鉴里，并头宫面高妆。", "莲房。", "露脸盈盈，无语处、恨何长。", "有翡翠怜红，鸳鸯妒影，俱断柔肠。", "凄凉。", "芰荷暮雨，褪娇红、换紫结秋房。", "堪把丹青对写，凤池归去携将。"]'),
('song-ci-78','宝鼎现','范周','宋','宋词','song-ci','宝鼎现','[]','夕阳西下，暮霭红隘，香风罗绮。',191,'宋词/ci.song.2000.json','["夕阳西下，暮霭红隘，香风罗绮。", "乘丽景、华灯争放，浓焰烧空连锦砌。", "睹皓月、浸严城如画，花影寒笼绛蕊。", "渐掩映、芙蓉万顷，迤逦齐开秋水。", "太守无限行歌意。", "拥麾幢、光动珠翠。", "倾万井、歌台舞榭，瞻望朱轮骈鼓吹。", "控宝马、耀貔貅千骑。", "银烛交光数里。", "似乱簇、寒星万点，拥入蓬壶影里。", "宴阁多才，环艳粉、瑶簪珠履。", "恐看看、丹诏催奉，宸游燕侍。", "便趁早、占通宵醉。", "缓引笙歌妓。", "任画角、吹老寒梅，月落西楼十二。"]'),
('song-ci-79','秦楼月・忆秦娥','吴则礼','宋','宋词','song-ci','秦楼月・忆秦娥','[]','怅离阕。',56,'宋词/ci.song.2000.json','["怅离阕。", "淮南三度梅花发。", "梅花发。", "片帆西去，落英如雪。", "新秦古塞人华发。", "一樽别酒君听说。", "君听说。", "胡笳征雁，陇云沙月。"]'),
('song-ci-80','江楼令','吴则礼','宋','宋词','song-ci','江楼令','[]','凭栏试觅红楼句，听考考、城头暮鼓。',62,'宋词/ci.song.2000.json','["凭栏试觅红楼句，听考考、城头暮鼓。", "数骑翩翩度孤戍。", "尽雕弓白羽。", "平生正被儒冠误。", "待闲看、将军射虎。", "朱槛潇潇过微雨。", "送斜阳西去。"]'),
('song-ci-81','虞美人','吴则礼','宋','宋词','song-ci','虞美人','[]','真香秀色盈盈女。',66,'宋词/ci.song.2000.json','["真香秀色盈盈女。", "一笑重阳雨。", "不应解怯晚丛寒。", "眼底轻罗小扇、且团团。", "吴云楚燕浑依旧。", "更把金英嗅。", "鲜鲜未恨出闺迟。", "自许平生孤韵、与秋期。"]'),
('song-ci-82','虞美人','吴则礼','宋','宋词','song-ci','虞美人','[]','夜寒闲倚西楼月。',66,'宋词/ci.song.2000.json','["夜寒闲倚西楼月。", "消尽江南雪。", "东风明日木兰船。", "想见阳关声彻、雁连天。", "斜斜洲渚溶溶水。", "端负青春醉。", "平安小字几时回。", "空有暗香疏影、陇头梅。"]'),
('song-ci-83','虞美人','吴则礼','宋','宋词','song-ci','虞美人','[]','从来强作游秦计。',66,'宋词/ci.song.2000.json','["从来强作游秦计。", "只有貂裘敝。", "休论范叔十年寒。", "看取星星种种、坐儒冠。", "江湖旧日渔竿手。", "初把黄花酒。", "且凭洛水送归船。", "想见淮南秋尽、水如天。"]'),
('song-ci-84','虞美人','吴则礼','宋','宋词','song-ci','虞美人','[]','乌皮白氎西窗暖。',66,'宋词/ci.song.2000.json','["乌皮白氎西窗暖。", "种种霜毛短。", "小春何处有梅花。", "想见水边篱落、数枝斜。", "殊方他日登楼句。", "好在孤吟处。", "五年拚落醉魂中。", "试觅酒垆陈迹、问黄公。"]'),
('song-ci-85','减字木兰花','吴则礼','宋','宋词','song-ci','减字木兰花','[]','星星素发。',52,'宋词/ci.song.2000.json','["星星素发。", "只有鸣笳楼上发。", "看舞胡姬。", "带得平安探骑归。", "故人渐老。", "只与虎头论墨妙。", "怀抱难开。", "快遣披云一笑来。"]'),
('song-ci-86','减字木兰花','吴则礼','宋','宋词','song-ci','减字木兰花','[]','梅花未彻。',52,'宋词/ci.song.2000.json','["梅花未彻。", "付与团团沙塞月。", "端欲捐书。", "去乞君王丈二殳。", "貂裘锦帽。", "盘马不甘青鬓老。", "底事偏奇。", "细草平沙看打围。"]'),
('song-ci-87','减字木兰花','吴则礼','宋','宋词','song-ci','减字木兰花','[]','河西春晚。',52,'宋词/ci.song.2000.json','["河西春晚。", "独有柳条来入眼。", "塞外斜斜。", "不道欺寒红杏花。", "边笳初发。", "与唤团团沙塞月。", "雁响连天。", "谁倚城头百尺栏。"]'),
('song-ci-88','八声甘州','向子諲','宋','宋词','song-ci','八声甘州','[]','扫长空、万里静无云，飞镜上天东。',119,'宋词/ci.song.2000.json','["扫长空、万里静无云，飞镜上天东。", "欲骑鲸与问，一株丹桂，几度秋风。", "取水珠宫贝阙，聊为洗尘容。", "莫放素娥去，清影方中。", "玄魄犹馀半壁，便笙篁万籁，尊俎千峰。", "况十分端正，更鼓舞衰翁。", "恨人生、时乎不再，未转头、欢事已沈空。", "多酌我，岁华好处，浩意无穷。"]'),
('song-ci-89','水调歌头','向子諲','宋','宋词','song-ci','水调歌头','[]','闰馀有何好，一年两中秋。',114,'宋词/ci.song.2000.json','["闰馀有何好，一年两中秋。", "补天修月人去，千古想风流。", "少日南昌幕下，更得洪徐苏李，快意作清游。", "送日眺西岭，得月上东楼。", "四十载，两人在，总白头。", "谁知沧海成陆，萍迹落南州。", "忍问神京何在，幸有芗林秋露，芳气袭衣裘。", "断送馀生事，惟酒可忘忧。"]'),
('song-ci-90','水调歌头','向子諲','宋','宋词','song-ci','水调歌头','[]','我生六十四，四度闰中秋。',114,'宋词/ci.song.2000.json','["我生六十四，四度闰中秋。", "碧天千里如水，明月更如流。", "照我洛滨诗伯，携手仙卿廛隐，阆苑与同游。", "人醉玉相倚，不肯下琼楼。", "芗林老，章江上，几回头。", "剩欲控鹤瀛海，聊下越王州。", "直入白云深处，细酌仙人九酝，香雾尽侵裘。", "共看一笑粲，以写我心忧。"]'),
('song-ci-91','水调歌头','向子諲','宋','宋词','song-ci','水调歌头','[]','飘飘任公子，爽气欲横秋。',114,'宋词/ci.song.2000.json','["飘飘任公子，爽气欲横秋。", "向日携诗过我，知不是凡流。", "筑室清江西畔，巧占一川佳处，胜士日追游。", "邀我出门去，柱月上新楼。", "烂银盘，从树杪，出云头。", "好是风流从事，同醉入青州。", "须信人生如幻，七十古来稀有，销得几狐裘。", "谁似芗林老，无喜亦无忧。"]'),
('song-ci-92','洞仙歌','向子諲','宋','宋词','song-ci','洞仙歌','[]','碧天如水，一洗秋容净。',103,'宋词/ci.song.2000.json','["碧天如水，一洗秋容净。", "何处飞来大明镜。", "谁道斫却桂，应更光辉，无遗照，泻出山河倒影。", "人犹苦馀热，肺腑生尘，移我超然到三境。", "问姮娥、缘底事，乃有盈亏，烦玉斧、运风重整。", "教夜夜、人世十分圆，待拚却长年，醉了还醒。"]'),
('song-ci-93','满江红','向子諲','宋','宋词','song-ci','满江红','[]','雁阵横空，江枫战、几番风雨。',116,'宋词/ci.song.2000.json','["雁阵横空，江枫战、几番风雨。", "天有意、作新秋令，欲鏖残暑。", "篱菊岩花俱秀发，清氛不断来窗户。", "共欢然、一醉得黄香，仍叔度。", "尊前事，尘中去。", "拈花问，无人语。", "芗林顾灵照，笑抚庭树。", "试举似虎头城太守，想应会得玄玄处。", "老我来、懒更作渊明，闲情赋。"]'),
('song-ci-94','虞美人','向子諲','宋','宋词','song-ci','虞美人','[]','淮阳堂上曾相对。',66,'宋词/ci.song.2000.json','["淮阳堂上曾相对。", "笑把姚黄醉。", "十年离乱有深忧。", "白发萧萧同见、渚江秋。", "履声细听知何处。", "欲上星辰去。", "清寒初溢暮云收。", "更看碧天如水、月如流。"]'),
('song-ci-95','虞美人','向子諲','宋','宋词','song-ci','虞美人','["\u5e90\u5c71"]','银山堆里庐山对。',66,'宋词/ci.song.2000.json','["银山堆里庐山对。", "舟子愁如醉。", "笑看五老了无忧。", "大觉胸中云梦、气横秋。", "若人到得归元处。", "空一齐销去。", "直须闻见泯然收。", "始知大江东注、不曾流。"]'),
('song-ci-96','虞美人','向子諲','宋','宋词','song-ci','虞美人','[]','澄江霁月清无对。',66,'宋词/ci.song.2000.json','["澄江霁月清无对。", "鲁酒何须醉。", "人怜贫病不堪忧。", "谁识此心如月、正含秋。", "再三涝漉方知处。", "试向波心去。", "迢迢空劫勿能收。", "谩道从来天地、与同流。"]'),
('song-ci-97','虞美人','向子諲','宋','宋词','song-ci','虞美人','[]','江头苦被梅花恼。',66,'宋词/ci.song.2000.json','["江头苦被梅花恼。", "一夜霜须老。", "谁将冰玉比精神。", "除是凌风却月、见天真。", "情高意远仍多思。", "只有人相似。", "满城桃李不能春。", "独向雪花深处、露花身。"]'),
('song-ci-98','蝶恋花','向子諲','宋','宋词','song-ci','蝶恋花','[]','推上百花如锦绣。',70,'宋词/ci.song.2000.json','["推上百花如锦绣。", "水满池塘，更作溅溅溜。", "断送风光惟有酒。", "苦吟不怕因诗瘦。", "寻壑经丘长是久。", "晚晚归来，稚子柴门候。", "万事付之醒梦后。", "眉头不为闲愁皱。"]'),
('song-ci-99','蝶恋花','向子諲','宋','宋词','song-ci','蝶恋花','[]','岩桂秋风南埭路。',70,'宋词/ci.song.2000.json','["岩桂秋风南埭路。", "墙外行人，十里香随步。", "此是芗林游戏处。", "谁知不向根尘住。", "今日对花非浪语。", "忆昨明光，早辱君王顾。", "生怕青蝇轻点污。", "思鲈何似思花去。"]'),
('song-ci-100','鹧鸪天','向子諲','宋','宋词','song-ci','鹧鸪天','[]','戏彩堂深翠幕张。',64,'宋词/ci.song.2000.json','["戏彩堂深翠幕张。", "南飔特地作微凉。", "葵花向日枝枝似，萱草忘忧日日长。", "门有庆，福无疆。", "老人星与酒生光。", "殷勤更假天吴手，倾泻西江入寿觞。"]'),
('song-ci-101','鹧鸪天','向子諲','宋','宋词','song-ci','鹧鸪天','[]','召埭初逢两妙年。',64,'宋词/ci.song.2000.json','["召埭初逢两妙年。", "遥林玉树倚风前。", "疏梅影里春同醉，红芰香中月一船。", "长怅恨，短因缘。", "空馀蝴蝶梦相连。", "谁知瘴雨蛮烟地，重上襄王玳瑁筵。"]'),
('song-ci-102','鹧鸪天','向子諲','宋','宋词','song-ci','鹧鸪天','[]','两个鸳鸯波上来。',64,'宋词/ci.song.2000.json','["两个鸳鸯波上来。", "一ь杨柳掌中回。", "已愁共雪因风去，更着繁弦急管催。", "含浅笑，劝深杯。", "桃花气暖眼边开。", "司空常见风流惯，输与山翁醉玉摧。"]'),
('song-ci-103','鹧鸪天','向子諲','宋','宋词','song-ci','鹧鸪天','[]','露下风前处处幽。',64,'宋词/ci.song.2000.json','["露下风前处处幽。", "官黄如染翠如流。", "谁将天上蟾宫树，散作人间水国秋。", "香郁郁，思悠悠。", "几年梦魂绕江头。", "今朝得到芗林醉，白发相看万事休。"]'),
('song-ci-104','鹧鸪天','向子諲','宋','宋词','song-ci','鹧鸪天','[]','莫问清江与洛阳。',64,'宋词/ci.song.2000.json','["莫问清江与洛阳。", "山林总是一般香。", "两家地占西南胜，可是前人例姓杨。", "石作枕，醉为乡。", "藕花菱角满池塘。", "虽无中岛霓裳奏，独鹤随人意自长。"]'),
('song-ci-105','鹧鸪天','向子諲','宋','宋词','song-ci','鹧鸪天','[]','紫禁烟花一万重。',64,'宋词/ci.song.2000.json','["紫禁烟花一万重。", "鳌山宫阙倚晴空。", "玉皇端拱彤云上，人物嬉游陆海中。", "星转斗，驾回龙。", "五侯池馆醉春风。", "而今白发三千丈，愁对寒灯数点红。"]'),
('song-ci-106','鹧鸪天','向子諲','宋','宋词','song-ci','鹧鸪天','[]','只有梅花似玉容。',64,'宋词/ci.song.2000.json','["只有梅花似玉容。", "云窗月户几尊同。", "见来怨眼明秋水，欲去愁眉淡远峰。", "山万叠，水千重。", "一双蝴蝶梦能通。", "都将泪作黄梅雨，尽把情为柳絮风。"]'),
('song-ci-107','鹧鸪天','向子諲','宋','宋词','song-ci','鹧鸪天','[]','玉篆题名在九天。',64,'宋词/ci.song.2000.json','["玉篆题名在九天。", "而今且作地行仙。", "挂冠神武归休后，同醉芗林是几年。", "龟游泳，鹤蹁迁。", "疏梅修竹两清妍。", "欲知福寿都多少，阁皂清江可比肩。"]'),
('song-ci-108','鹧鸪天','向子諲','宋','宋词','song-ci','鹧鸪天','[]','江北江南雪未消。',64,'宋词/ci.song.2000.json','["江北江南雪未消。", "此花独步百花饶。", "青枝可爱难为杏，绿叶初无不是桃。", "多态度，足风标。", "蕊珠仙子醉红潮。", "绝怜竹外横斜处，似与芗林慰寂寥。"]'),
('song-ci-109','鹧鸪天','向子諲','宋','宋词','song-ci','鹧鸪天','[]','驾月新成碧玉梁。',64,'宋词/ci.song.2000.json','["驾月新成碧玉梁。", "青天万里泻银潢。", "广寒宫里无双树，无热池边不尽香。", "承露液，酿秋光。", "直须一举累千觞。", "不知世路风波恶，何似芗林气味长。"]'),
('song-ci-110','鹧鸪天','向子諲','宋','宋词','song-ci','鹧鸪天','[]','明月光中与客期。',64,'宋词/ci.song.2000.json','["明月光中与客期。", "一年秋半两圆时。", "姮娥得意为长计，织女欢盟可恨迟。", "瞻玉兔，倒琼彝。", "追怀往事记新词。", "浩歌直入沧浪去，醉里归来凝不知。"]'),
('song-ci-111','鹧鸪天','向子諲','宋','宋词','song-ci','鹧鸪天','[]','赣上人人说故侯。',64,'宋词/ci.song.2000.json','["赣上人人说故侯。", "从来文采更风流。", "题诗谩道三千首，别酒须拚一百筹。", "乘画鹢，衣轻裘。", "又将春色过荆州。", "合江绕岸垂杨柳，总学歌眉叶叶愁。"]'),
('song-ci-112','减字木兰花','向子諲','宋','宋词','song-ci','减字木兰花','[]','青松翠篠。',52,'宋词/ci.song.2000.json','["青松翠篠。", "一夜猗倾如醉倒。", "残腊能佳。", "落尽梅花见雪花。", "诗崖酒岛。", "何日登临同笑傲。", "未老还家。", "饱历年华有鬓华。"]'),
('song-ci-113','减字木兰花','向子諲','宋','宋词','song-ci','减字木兰花','[]','斜红翠叠。',52,'宋词/ci.song.2000.json','["斜红翠叠。", "何许花神来献瑞。", "粲粲裳衣。", "割得天孙锦一机。", "真香妙质。", "不耐世间风与日。", "着意遮围。", "莫放春光造次归。"]'),
('song-ci-114','阮郎归','向子諲','宋','宋词','song-ci','阮郎归','[]','江南江北雪漫漫。',56,'宋词/ci.song.2000.json','["江南江北雪漫漫。", "遥知易水寒。", "同云深处望三关。", "断肠山又山。", "天可老，海能翻。", "消除此恨难。", "频闻遣使问平安。", "几时鸾辂还。"]'),
('song-ci-115','秦楼月・忆秦娥','向子諲','宋','宋词','song-ci','秦楼月・忆秦娥','[]','芳菲歇。',56,'宋词/ci.song.2000.json','["芳菲歇。", "故园目断伤心切。", "伤心切。", "无边烟水，无穷山色。", "可堪更近乾龙节。", "眼中泪尽空啼血。", "空啼血。", "子规声外，晓风残月。"]'),
('song-ci-116','少年游','向子諲','宋','宋词','song-ci','少年游','[]','去年同醉，酴醿花下，健笔赋新词。',62,'宋词/ci.song.2000.json','["去年同醉，酴醿花下，健笔赋新词。", "今年君去，酴醿欲破，谁与醉为期。", "旧曲重歌倾别酒，风露泣花枝。", "章水能长湘水远，流不尽、两相思。"]'),
('song-ci-117','西江月','向子諲','宋','宋词','song-ci','西江月','[]','风响蕉林似雨，烛生粉艳如花。',58,'宋词/ci.song.2000.json','["风响蕉林似雨，烛生粉艳如花。", "客星乘兴泛仙槎。", "误到支机石下。", "欢喜地中取醉，温柔乡里为家。", "暖红香雾闹春华。", "不道风波可怕。"]'),
('song-ci-118','西江月','向子諲','宋','宋词','song-ci','西江月','[]','见处莫教认著，无心慎勿沈空。',58,'宋词/ci.song.2000.json','["见处莫教认著，无心慎勿沈空。", "本无背面与初终。", "说了还同说梦。", "欲识芗林居士，真成渔父家风。", "收丝垂钓月明中。", "总是神通妙用。"]'),
('song-ci-119','西江月','向子諲','宋','宋词','song-ci','西江月','[]','得意穿云度水，及时斫玉分金。',58,'宋词/ci.song.2000.json','["得意穿云度水，及时斫玉分金。", "兹游了却未来心。", "怪我归迟一任。", "居士何如学士，翰林休笑芗林。", "个中真味少知音。", "不是清狂太甚。"]'),
('song-ci-120','西江月','向子諲','宋','宋词','song-ci','西江月','[]','五柳坊中烟绿，百花洲上云红。',58,'宋词/ci.song.2000.json','["五柳坊中烟绿，百花洲上云红。", "萧萧白发两衰翁。", "不与时人同梦。", "抛掷麟符虎节，徜徉江月林风。", "世间万事转头空。", "个里如如不动。"]'),
('song-ci-121','西江月','向子諲','宋','宋词','song-ci','西江月','[]','红退小园桃杏，绿生芳草池塘。',58,'宋词/ci.song.2000.json','["红退小园桃杏，绿生芳草池塘。", "谁教芍药殿春光。", "不似酴醿官样。", "翠盖更蒙珠幰，薰炉剩熨沈香。", "娟娟风露满衣赏。", "独步瑶台月上。"]'),
('song-ci-122','西江月','向子諲','宋','宋词','song-ci','西江月','[]','几见芙蓉并蒂，忽生三秀灵芝。',58,'宋词/ci.song.2000.json','["几见芙蓉并蒂，忽生三秀灵芝。", "千年老树出孙枝。", "岩桂秋来满地。", "白鹤云间翔舞，绿龟叶上游戏。", "齐眉偕老更何疑。", "个里自非尘世。"]'),
('song-ci-123','南乡子','向子諲','宋','宋词','song-ci','南乡子','[]','梅与雪争姝。',66,'宋词/ci.song.2000.json','["梅与雪争姝。", "试问春风管得无。", "除却个人多样态，谁如。", "细把冰姿比玉肤。", "一曲倒金壶。", "既醉仍烦翠袖扶。", "同向凌风台上看，何如。", "且与芗林作画图。"]'),
('song-ci-124','浣溪沙','向子諲','宋','宋词','song-ci','浣溪沙','[]','绿玉丛中紫玉条。',48,'宋词/ci.song.2000.json','["绿玉丛中紫玉条。", "幽花疏淡更香饶。", "不将朱粉污高标。", "空谷佳人宜结伴，贵游公子不能招。", "小窗相对诵离骚。"]'),
('song-ci-125','浣溪沙','向子諲','宋','宋词','song-ci','浣溪沙','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','乐在烟波钓是闲。',48,'宋词/ci.song.2000.json','["乐在烟波钓是闲。", "草堂松桂已胜攀。", "梢梢新月几回弯。", "一碧太湖三万顷，屹然相对洞庭山。", "况风浪起且须还。"]'),
('song-ci-126','浣溪沙','向子諲','宋','宋词','song-ci','浣溪沙','[]','进步须於百尺竿。',48,'宋词/ci.song.2000.json','["进步须於百尺竿。", "二边休立莫中安。", "要知玄露没多般。", "花影镜中拈不起，蟾光空里撮应难。", "道人无事更参看。"]'),
('song-ci-127','浣溪沙','向子諲','宋','宋词','song-ci','浣溪沙','[]','爆竹声中一岁除。',48,'宋词/ci.song.2000.json','["爆竹声中一岁除。", "东风送暖入屠苏。", "瞳瞳晓色上林庐。", "老去怕看新历日，退归拟学旧桃符。", "青春不染白髭须。"]'),
('song-ci-128','浣溪沙','向子諲','宋','宋词','song-ci','浣溪沙','[]','醉里惊从月窟来。',48,'宋词/ci.song.2000.json','["醉里惊从月窟来。", "睡馀如梦蕊宫回。", "碧云时度小崔嵬。", "疑是海山怜我老，不论时节遣花开。", "从今休数返魂梅。"]'),
('song-ci-129','浣溪沙','向子諲','宋','宋词','song-ci','浣溪沙','[]','星斗昭回自一天。',48,'宋词/ci.song.2000.json','["星斗昭回自一天。", "疏梅池畔斗清妍。", "蟠桃正熟藕如船。", "叶上灵龟来瑞世，林间白鹤舞胎仙。", "春秋不记几千年。"]'),
('song-ci-130','浣溪沙','向子諲','宋','宋词','song-ci','浣溪沙','[]','瑞气氤氲拂水来。',48,'宋词/ci.song.2000.json','["瑞气氤氲拂水来。", "金幢玉节下瑶台。", "江梅岩桂一时开。", "不尽秋香凝燕寝，无边春色入尊罍。", "临风嗅蕊共裴回。"]'),
('song-ci-131','浣溪沙','向子諲','宋','宋词','song-ci','浣溪沙','[]','绿绕红围宋玉墙。',48,'宋词/ci.song.2000.json','["绿绕红围宋玉墙。", "幽兰林下正芬芳。", "桃花气暖玉生香。", "谁道广平心似铁，艳妆高韵两难忘。", "苏州老矣不能狂。"]'),
('song-ci-132','浣溪沙','向子諲','宋','宋词','song-ci','浣溪沙','[]','霭霭停云覆短墙。',48,'宋词/ci.song.2000.json','["霭霭停云覆短墙。", "夭夭临水自然芳。", "猗猗无处着清香。", "珍重蓦山溪句好，尊前频举不相忘。", "濠梁梦蝶尽春狂。"]'),
('song-ci-133','浣溪沙','向子諲','宋','宋词','song-ci','浣溪沙','[]','南国风烟深更深。',48,'宋词/ci.song.2000.json','["南国风烟深更深。", "清江相结是庐陵。", "甘棠两地绿成阴。", "九日黄花兄弟会，中秋明月故人心。", "悲欢离合古犹今。"]'),
('song-ci-134','浣溪沙','向子諲','宋','宋词','song-ci','浣溪沙','[]','樽俎风流意气倾。',48,'宋词/ci.song.2000.json','["樽俎风流意气倾。", "一杯相属忍催行。", "离歌更作断肠声。", "衮衮大江前后浪，娟娟明月短长亭。", "水程山驿总关情。"]'),
('song-ci-135','生查子','向子諲','宋','宋词','song-ci','生查子','[]','我爱木中犀，不是凡花数。',48,'宋词/ci.song.2000.json','["我爱木中犀，不是凡花数。", "清似水沈香，色染蔷薇露。", "芗林月冷时，玉笋云深处。", "归梦托秋风，夜夜江头路。"]'),
('song-ci-136','生查子','向子諲','宋','宋词','song-ci','生查子','[]','月姊倚秋风，香度青林杪。',48,'宋词/ci.song.2000.json','["月姊倚秋风，香度青林杪。", "吹堕酒杯中，笑靥撩人小。", "芗林万事休，独此情未了。", "醉里又题诗，不觉花前老。"]'),
('song-ci-137','临江仙','向子諲','宋','宋词','song-ci','临江仙','[]','新月低垂帘额，小梅半出檐牙。',66,'宋词/ci.song.2000.json','["新月低垂帘额，小梅半出檐牙。", "高堂开燕静无哗。", "麟孙凤女，学语正咿呀。", "宝鼎剩熏沈水，琼彝烂醉流霞。", "芗林同老此生涯。", "一川风露，总道是仙家。"]'),
('song-ci-138','七娘子','向子諲','宋','宋词','song-ci','七娘子','["\u957f\u6c5f"]','山围水绕高唐路。',72,'宋词/ci.song.2000.json','["山围水绕高唐路。", "恨密云、不下阳台雨。", "雾阁云窗，风亭月户。", "分明携手同行处。", "而今不见生尘步。", "但长江、无语东流去。", "满地落花，漫天飞絮。", "谁知总是离愁做。"]'),
('song-ci-139','减字木兰花','向子諲','宋','宋词','song-ci','减字木兰花','[]','维摩住处。',52,'宋词/ci.song.2000.json','["维摩住处。", "竟日缤纷花似雨。", "更有难忘。", "十里清芬扑鼻香。", "当年疏傅。", "借问赐金那用许。", "何似归艎。", "宝墨光芒万丈长。"]'),
('song-ci-140','减字木兰花','向子諲','宋','宋词','song-ci','减字木兰花','[]','年年岩桂。',52,'宋词/ci.song.2000.json','["年年岩桂。", "恰恰中秋供我醉。", "今日重阳。", "百树犹无一树香。", "且倾白酒。", "赖有茱萸枝在手。", "可是清甘。", "绕遍东篱摘未堪。"]'),
('song-ci-141','清平乐','向子諲','宋','宋词','song-ci','清平乐','[]','幽花无外。',54,'宋词/ci.song.2000.json','["幽花无外。", "心与芗林会。", "绿发相看今老矣。", "不作浅俗气味。", "露叶薿薿生光。", "风梢泛泛飘香。", "称意中秋开了，馀情犹及重阳。"]'),
('song-ci-142','清平乐','向子諲','宋','宋词','song-ci','清平乐','[]','吴头楚尾。',54,'宋词/ci.song.2000.json','["吴头楚尾。", "踏破芒鞋底。", "万壑千岩秋色里。", "不耐恼人风味。", "而今我老芗林。", "世间百不关心。", "独喜爱香韩寿，能来同醉花阴。"]'),
('song-ci-143','清平乐','向子諲','宋','宋词','song-ci','清平乐','[]','薄情风雨。',54,'宋词/ci.song.2000.json','["薄情风雨。", "断送花何许。", "一夜清香无觅处。", "却返云窗月户。", "醉乡曲米为春。", "荆州富贵中人。", "肯入芗林净社，玉山屡倒芳茵。"]'),
('song-ci-144','清平乐','向子諲','宋','宋词','song-ci','清平乐','[]','银钩虿尾。',54,'宋词/ci.song.2000.json','["银钩虿尾。", "一似锺繇字。", "吏部文章麟角起。", "自是惊人瑞世。", "西垣准拟挥毫。", "不须苦续离骚。", "政看翻阶红药，无忘丛桂香醪。"]'),
('song-ci-145','清平乐','向子諲','宋','宋词','song-ci','清平乐','[]','人间尘外。',54,'宋词/ci.song.2000.json','["人间尘外。", "一种寒香蕊。", "疑是月娥天上醉。", "戏把黄云挼碎。", "使君坐啸清江。", "腾芳飞誉无双。", "兴寄小山丛桂，诗成棐几明窗。"]'),
('song-ci-146','清平乐','向子諲','宋','宋词','song-ci','清平乐','[]','芗林春色。',54,'宋词/ci.song.2000.json','["芗林春色。", "杯面云腴白。", "醉里不知天地窄。", "真是人间欢伯。", "风流玉友争妍。", "酪奴可与忘年。", "空诵少陵佳句，饮中谁与俱仙。"]'),
('song-ci-147','更漏子','向子諲','宋','宋词','song-ci','更漏子','[]','小窗前，疏影下。',58,'宋词/ci.song.2000.json','["小窗前，疏影下。", "鸾镜弄妆初罢。", "梅似雪，雪如人。", "都无一点尘。", "暮江寒，人响绝。", "更着朦胧微月。", "山似玉，玉如君。", "相看一笑温。"]'),
('song-ci-148','点绛唇','向子諲','宋','宋词','song-ci','点绛唇','[]','绿水青山，一轮明月林梢过。',50,'宋词/ci.song.2000.json','["绿水青山，一轮明月林梢过。", "有谁同坐。", "妙德毗卢我。", "石女高歌，古调无人和。", "还知麽。", "更没别个。", "且莫分疏破。"]'),
('song-ci-149','点绛唇','向子諲','宋','宋词','song-ci','点绛唇','[]','此夜中秋，不向光影门前过。',50,'宋词/ci.song.2000.json','["此夜中秋，不向光影门前过。", "披衣得坐。", "无佛众生我。", "没鼓打皮，借问今几和。", "还知麽。", "就中两个。", "鼻孔谁穿破。"]'),
('song-ci-150','点绛唇','向子諲','宋','宋词','song-ci','点绛唇','[]','不昧本来，太虚明月流辉过。',50,'宋词/ci.song.2000.json','["不昧本来，太虚明月流辉过。", "令行独坐。", "高下都由我。", "玉轸无弦，谁对秋风和。", "还知麽。", "老庞一个。", "识得机关破。"]'),
('song-ci-151','点绛唇','向子諲','宋','宋词','song-ci','点绛唇','[]','折脚铛中，二时粥饭随缘过。',50,'宋词/ci.song.2000.json','["折脚铛中，二时粥饭随缘过。", "东行西坐。", "不识而今我。", "坏尽田园，终日且婆和。", "还知麽。", "锥也无个。", "肘露衣衫破。"]'),
('song-ci-152','点绛唇','向子諲','宋','宋词','song-ci','点绛唇','[]','不挂一裘，世间万事如风过。',50,'宋词/ci.song.2000.json','["不挂一裘，世间万事如风过。", "忘缘兀坐。", "皮袋非真我。", "随色摩尼，朱碧如何和。", "还知麽。", "从来只个。", "千古扑不破。"]'),
('song-ci-153','点绛唇','向子諲','宋','宋词','song-ci','点绛唇','[]','荆棘林中，浪夸好手曾穿过。',50,'宋词/ci.song.2000.json','["荆棘林中，浪夸好手曾穿过。", "不起於坐。", "畐塞虚空我。", "问路台山，婆子随声和。", "还知麽。", "石桥老个。", "些子平窥破。"]'),
('song-ci-154','点绛唇','向子諲','宋','宋词','song-ci','点绛唇','[]','春浪桃花，禹门三尺平跳过。',50,'宋词/ci.song.2000.json','["春浪桃花，禹门三尺平跳过。", "死生不坐。", "变化须归我。", "山起南云，白雨声相和。", "还知麽。", "点点真个。", "块土何曾破。"]'),
('song-ci-155','点绛唇','向子諲','宋','宋词','song-ci','点绛唇','["\u8861\u5c71"]','脱落皮肤，故人南岳峰前过。',50,'宋词/ci.song.2000.json','["脱落皮肤，故人南岳峰前过。", "只知闲坐。", "千圣难窥我。", "明月澄潭，谁唱复谁和。", "还知麽。", "锦鳞没个。", "莫触清光破。"]'),
('song-ci-156','点绛唇','向子諲','宋','宋词','song-ci','点绛唇','[]','绿水池塘，笑看野鸭双飞过。',50,'宋词/ci.song.2000.json','["绿水池塘，笑看野鸭双飞过。", "正当呆坐。", "纫鼻须还我。", "尽日张弓，许久无人和。", "还知麽。", "难得全个。", "不免须明破。"]'),
('song-ci-157','点绛唇','向子諲','宋','宋词','song-ci','点绛唇','[]','冰雪肌肤，靓妆喜作梅花面。',50,'宋词/ci.song.2000.json','["冰雪肌肤，靓妆喜作梅花面。", "寄情高远。", "不与凡尘染。", "玉立峰前，闲把经珠转。", "秋风便。", "雾收云卷。", "水月光中见。"]'),
('song-ci-158','点绛唇','向子諲','宋','宋词','song-ci','点绛唇','[]','无热池南，岁寒亭上开新宴。',50,'宋词/ci.song.2000.json','["无热池南，岁寒亭上开新宴。", "青山芳甸。", "尽入真如观。", "举酒高歌，人在秋天半。", "晴空远。", "巷江影乱。", "何处飞来雁。"]'),
('song-ci-159','点绛唇','向子諲','宋','宋词','song-ci','点绛唇','[]','病卧秋风，懒寻杯酒追欢宴。',50,'宋词/ci.song.2000.json','["病卧秋风，懒寻杯酒追欢宴。", "梦游都甸。", "不改当年观。", "故旧雕零，天下今无半。", "烟尘远。", "泪珠零乱。", "怕问随阳雁。"]'),
('song-ci-160','点绛唇','向子諲','宋','宋词','song-ci','点绛唇','[]','今日重阳，强挼青蕊聊开宴。',50,'宋词/ci.song.2000.json','["今日重阳，强挼青蕊聊开宴。", "我家几甸。", "试上连辉观。", "忆着酺池，古塔烟霄半。", "愁心远。", "情随云乱。", "肠断江城雁。"]'),
('song-ci-161','点绛唇','向子諲','宋','宋词','song-ci','点绛唇','[]','莫问重阳，黄花满地须游宴。',50,'宋词/ci.song.2000.json','["莫问重阳，黄花满地须游宴。", "休论夷甸。", "且作江山观。", "百岁光阴，屈指今过半。", "霜天晚。", "眼昏花乱。", "不见书空雁。"]'),
('song-ci-162','点绛唇','向子諲','宋','宋词','song-ci','点绛唇','[]','春蕙秋兰，断崖空谷终难近。',50,'宋词/ci.song.2000.json','["春蕙秋兰，断崖空谷终难近。", "何如逸韵。", "十里香成阵。", "倾盖论交，白首情无尽。", "因君问。", "新声玉振。", "更觉花清润。"]'),
('song-ci-163','点绛唇','向子諲','宋','宋词','song-ci','点绛唇','[]','璧月光辉，万山不隔蟾宫树。',50,'宋词/ci.song.2000.json','["璧月光辉，万山不隔蟾宫树。", "金风玉露。", "水国秋无数。", "老子情锺，欲向香中住。", "君王许。", "龙鸾飞舞。", "送到归休处。"]'),
('song-ci-164','点绛唇','向子諲','宋','宋词','song-ci','点绛唇','[]','明月山头，古香吹堕青林底。',50,'宋词/ci.song.2000.json','["明月山头，古香吹堕青林底。", "世情无味。", "伴我千岩里。", "诗老风流，也向花留意。", "歌新拟。", "调高难比。", "半坐分君醉。"]'),
('song-ci-165','采桑子','向子諲','宋','宋词','song-ci','采桑子','[]','霜须七十期同老，云水之乡。',52,'宋词/ci.song.2000.json','["霜须七十期同老，云水之乡。", "总挂冠裳。", "闲里光阴一倍长。", "况逢菊靥篱边笑，风露中香。", "报答秋光。", "自有仙人九酝觞。"]'),
('song-ci-166','一落索','向子諲','宋','宋词','song-ci','一落索','[]','春风吹断前山雨。',56,'宋词/ci.song.2000.json','["春风吹断前山雨。", "行云归去。", "暂来须信本无心，回首了无寻处。", "欲问个中玄路。", "阿谁能语。", "澄江霁月却深知，把此意、都分付。"]'),
('song-ci-167','如梦令','向子諲','宋','宋词','song-ci','如梦令','[]','欲问芗林秋露。',40,'宋词/ci.song.2000.json','["欲问芗林秋露。", "来自广寒深处。", "海上说蔷薇，何似桂华风度。", "高古。", "高古。", "不著世间尘污。"]'),
('song-ci-168','如梦令','向子諲','宋','宋词','song-ci','如梦令','[]','谁识芗林秋露。',40,'宋词/ci.song.2000.json','["谁识芗林秋露。", "胜却诸天花雨。", "休更觅曹溪，自有个中玄路。", "参取。", "参取。", "滴滴要知落处。"]'),
('song-ci-169','卜算子','向子諲','宋','宋词','song-ci','卜算子','["\u897f\u6e56"]','临镜笑春风，生怕梅花妒。',52,'宋词/ci.song.2000.json','["临镜笑春风，生怕梅花妒。", "疑是西湖处士家，疏影横斜处。", "江静竹娟娟，绿绕青无数。", "独许幽人子细看，全胜墙东路。"]'),
('song-ci-170','卜算子','向子諲','宋','宋词','song-ci','卜算子','[]','雨意挟风回，月色兼天静。',52,'宋词/ci.song.2000.json','["雨意挟风回，月色兼天静。", "心与秋空一样清，万象森如影。", "何处一声钟，令我发深省。", "独立沧浪忘却归，不觉霜华冷。"]'),
('song-ci-171','卜算子','向子諲','宋','宋词','song-ci','卜算子','[]','时菊碎榛丛，地僻柴门静。',52,'宋词/ci.song.2000.json','["时菊碎榛丛，地僻柴门静。", "谁道村中好客稀，明月和清影。", "天地一蘧庐，梦事慵思省。", "若个知余懒是真，心已如灰冷。"]');
